def render_closeout_summary_for_pr(plan: dict[str, Any], pr: dict[str, Any]) -> dict[str, Any]:
    number = pr.get("number")
    if (
        not isinstance(number, int)
        or isinstance(number, bool)
        or number < 1
        or number > CLOSEOUT_PR_PLACEHOLDER_NUMBER
    ):
        raise WorkflowError("Final projection PR number is invalid.", exit_code=2)
    expected_url = canonical_pull_request_url(plan["git"]["repo"], number, pr.get("url"))
    summary = copy.deepcopy(plan["projection"]["summary_template"])
    summary["github"]["pr_url"] = expected_url
    summary["index"]["search_terms"]["pr_refs"] = [f"PR #{number}"]
    summary["index"]["retrieval_text"] = finish_summary_retrieval_text(
        str(summary["task"]["title"]), summary["index"]
    )
    return summary


def closeout_summary_for_pr(plan: dict[str, Any], pr: dict[str, Any]) -> dict[str, Any]:
    summary = render_closeout_summary_for_pr(plan, pr)
    validate_finish_summary(summary)
    return summary


def closeout_json_artifact_bytes(payload: dict[str, Any]) -> bytes:
    return (json.dumps(payload, ensure_ascii=False, indent=2) + "\n").encode("utf-8")


def closeout_summary_runtime_pr_facts_from_bytes(
    plan: dict[str, Any], content: bytes, *, expected_pr: dict[str, Any] | None = None
) -> dict[str, Any]:
    """Bind runtime PR facts without invoking the general local summary validator."""
    try:
        summary = json.loads(content.decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise WorkflowError("Committed final summary is not deterministic UTF-8 JSON.", exit_code=2) from exc
    if not isinstance(summary, dict):
        raise WorkflowError("Committed final summary JSON root must be an object.", exit_code=2)
    github = summary.get("github")
    index = summary.get("index")
    search_terms = index.get("search_terms") if isinstance(index, dict) else None
    pr_url = github.get("pr_url") if isinstance(github, dict) else None
    try:
        pr_url, number = parse_canonical_pull_request_url(plan["git"]["repo"], pr_url)
    except WorkflowError as exc:
        raise WorkflowError(
            "Committed final summary PR URL is not canonical for the immutable repo.", exit_code=2
        ) from exc
    if not isinstance(search_terms, dict) or search_terms.get("pr_refs") != [f"PR #{number}"]:
        raise WorkflowError("Committed final summary PR ref does not match its canonical URL.", exit_code=2)
    runtime_pr = {"number": number, "url": pr_url}
    if expected_pr is not None:
        expected_number = expected_pr.get("number")
        if not isinstance(expected_number, int) or isinstance(expected_number, bool):
            raise WorkflowError("Expected final summary PR number is invalid.", exit_code=2)
        expected_url = canonical_pull_request_url(
            plan["git"]["repo"], expected_number, expected_pr.get("url")
        )
        if number != expected_number or pr_url != expected_url:
            raise WorkflowError(
                "Final summary runtime PR facts differ from the bound pull request.",
                exit_code=2,
            )
        runtime_pr = {"number": expected_number, "url": expected_url}
    expected_summary = render_closeout_summary_for_pr(plan, runtime_pr)
    expected_bytes = closeout_json_artifact_bytes(expected_summary)
    actual_digest = hashlib.sha256(content).hexdigest()
    expected_digest = hashlib.sha256(expected_bytes).hexdigest()
    if content != expected_bytes:
        raise WorkflowError(
            "Final summary bytes do not match the deterministic runtime PR projection.",
            exit_code=2,
            payload={
                "expected_summary_sha256": expected_digest,
                "actual_summary_sha256": actual_digest,
            },
        )
    return {
        "number": number,
        "url": str(pr_url),
        "summary_sha256": actual_digest,
    }


def closeout_summary_template_digest(plan: dict[str, Any], summary: dict[str, Any]) -> str:
    normalized = copy.deepcopy(summary)
    placeholder = plan["projection"]["summary_placeholder"]
    normalized["github"]["pr_url"] = placeholder["url"]
    normalized["index"]["search_terms"]["pr_refs"] = [placeholder["ref"]]
    normalized["index"]["retrieval_text"] = finish_summary_retrieval_text(
        str(normalized["task"]["title"]), normalized["index"]
    )
    return closeout_json_artifact_sha256(normalized)


def validate_closeout_final_summary(plan: dict[str, Any], summary: dict[str, Any]) -> None:
    validate_finish_summary(summary)
    pr_url = summary.get("github", {}).get("pr_url")
    try:
        _canonical_url, number = parse_canonical_pull_request_url(plan["git"]["repo"], pr_url)
    except WorkflowError as exc:
        raise WorkflowError(
            "Final summary PR URL does not match closeout repo identity.", exit_code=2
        ) from exc
    expected_ref = [f"PR #{number}"]
    if summary.get("index", {}).get("search_terms", {}).get("pr_refs") != expected_ref:
        raise WorkflowError("Final summary PR ref does not match canonical PR identity.", exit_code=2)
    actual = closeout_summary_template_digest(plan, summary)
    expected = plan["projection"]["summary_template_sha256"]
    if actual != expected:
        raise WorkflowError(
            "Final summary differs from the prevalidated closeout template.",
            exit_code=2,
            payload={"expected_template_sha256": expected, "actual_template_sha256": actual},
        )


def read_and_validate_closeout_final_summary(path: Path, plan: dict[str, Any]) -> dict[str, Any]:
    summary = read_json(path)
    expected_file_sha = closeout_json_artifact_sha256(summary)
    actual_file_sha = hashlib.sha256(path.read_bytes()).hexdigest()
    if actual_file_sha != expected_file_sha:
        raise WorkflowError(
            "Final summary bytes are not the exact deterministic JSON artifact encoding.",
            exit_code=2,
            payload={"expected_file_sha256": expected_file_sha, "actual_file_sha256": actual_file_sha},
        )
    validate_closeout_final_summary(plan, summary)
    return summary


def closeout_plan_digest(plan: dict[str, Any]) -> str:
    payload = copy.deepcopy(plan)
    payload.pop("plan_digest", None)
    return canonical_json_sha256(payload)


def closeout_json_artifact_sha256(payload: dict[str, Any]) -> str:
    return hashlib.sha256(closeout_json_artifact_bytes(payload)).hexdigest()


def closeout_plan_errors(plan: Any) -> list[str]:
    if not isinstance(plan, dict):
        return ["closeout plan must be an object."]
    expected = {
        "schema_version", "task", "git", "inputs", "review", "publish",
        "marketplace", "projection", "transitions", "plan_digest",
    }
    errors: list[str] = []
    if set(plan) != expected:
        errors.append("closeout plan top-level keys do not match schema 1.0.")
    if plan.get("schema_version") != CLOSEOUT_PLAN_SCHEMA_VERSION:
        errors.append("closeout plan schema_version must be 1.0.")
    digest = str(plan.get("plan_digest") or "")
    if not re.fullmatch(r"[0-9a-f]{64}", digest) or digest != closeout_plan_digest(plan):
        errors.append("closeout plan digest does not match canonical content.")
    if plan.get("transitions") != CLOSEOUT_TRANSITIONS:
        errors.append("closeout plan transitions are invalid.")
    task = plan.get("task") if isinstance(plan.get("task"), dict) else {}
    git = plan.get("git") if isinstance(plan.get("git"), dict) else {}
    review = plan.get("review") if isinstance(plan.get("review"), dict) else {}
    publish = plan.get("publish") if isinstance(plan.get("publish"), dict) else {}
    marketplace = plan.get("marketplace") if isinstance(plan.get("marketplace"), dict) else {}
    projection = plan.get("projection") if isinstance(plan.get("projection"), dict) else {}
    nested_keys = {
        "task": (task, {"id", "title", "source_issue", "active_locator", "archive_locator"}),
        "review": (review, {"gate_locator", "reviewed_head", "changed_paths", "close_issues_reviewed"}),
        "publish": (publish, {"title", "body_sha256", "draft", "draft_to_ready", "match"}),
        "marketplace": (marketplace, {"required", "pending_machine", "verifier_artifact_locator"}),
        "projection": (
            projection,
            {
                "active_locator", "archive_locator", "finish_summary_locator",
                "metadata_allowlist", "move_paths", "tracked_move_paths",
                "untracked_archive_outputs", "evidence_paths",
                "summary_placeholder", "summary_template_sha256",
                "summary_template", "runtime_fact_fields",
            },
        ),
    }
    for label, (value, keys) in nested_keys.items():
        if set(value) != keys:
            errors.append(f"closeout plan {label} keys are invalid.")
    git_keys = {"repo", "remote", "base_branch", "head_branch", "reviewed_work_head"}
    if frozenset(git) not in {frozenset(git_keys), frozenset(git_keys | {"evidence_parent_head"})}:
        errors.append("closeout plan git keys are invalid.")
    for label, value in [
        ("task.active_locator", task.get("active_locator")),
        ("task.archive_locator", task.get("archive_locator")),
        ("projection.finish_summary_locator", projection.get("finish_summary_locator")),
    ]:
        errors.extend(finish_summary_path_errors(value, label))
    if not str(task.get("active_locator") or "").startswith(".trellis/tasks/"):
        errors.append("closeout task active locator is invalid.")
    if not str(task.get("archive_locator") or "").startswith(".trellis/tasks/archive/"):
        errors.append("closeout task archive locator is invalid.")
    if not isinstance(task.get("source_issue"), int) or isinstance(task.get("source_issue"), bool) or int(task.get("source_issue") or 0) < 1:
        errors.append("closeout task source_issue is invalid.")
    for key in ["repo", "remote", "base_branch", "head_branch"]:
        if not isinstance(git.get(key), str) or not str(git[key]).strip():
            errors.append(f"closeout git.{key} is invalid.")
    if normalize_github_repository(git.get("repo")) != git.get("repo"):
        errors.append("closeout git.repo must be a normalized GitHub owner/repository identity.")
    if not re.fullmatch(r"[0-9a-f]{40}", str(git.get("reviewed_work_head") or "")):
        errors.append("closeout reviewed_work_head is invalid.")
    if not re.fullmatch(r"[0-9a-f]{40}", closeout_evidence_parent_head(plan)):
        errors.append("closeout evidence_parent_head is invalid.")
    if review.get("reviewed_head") != git.get("reviewed_work_head"):
        errors.append("closeout review HEAD does not match git identity.")
    changed = review.get("changed_paths")
    if not isinstance(changed, list) or any(not isinstance(path, str) for path in changed) or changed != sorted(set(changed)):
        errors.append("closeout review changed paths must be sorted and unique.")
    reviewed_issues = review.get("close_issues_reviewed")
    if not isinstance(reviewed_issues, list) or any(not isinstance(number, int) or isinstance(number, bool) for number in reviewed_issues) or reviewed_issues != sorted(set(reviewed_issues)):
        errors.append("closeout reviewed close issues must be sorted and unique.")
    if publish.get("draft") is not True or publish.get("draft_to_ready") is not True:
        errors.append("closeout publish must use draft then ready.")
    if not re.fullmatch(r"[0-9a-f]{64}", str(publish.get("body_sha256") or "")):
        errors.append("closeout publish body digest is invalid.")
    expected_match = {"repo": git.get("repo"), "head": git.get("head_branch"), "base": git.get("base_branch")}
    if publish.get("match") != expected_match:
        errors.append("closeout publish match identity does not match git identity.")
    pending = marketplace.get("pending_machine") if isinstance(marketplace.get("pending_machine"), dict) else {}
    pending_keys = {
        "type", "status", "required", "artifact_path", "artifact_sha256",
        "verified_content_head", "remote_head", "publish_head", "commands_passed",
    }
    if (
        set(pending) != pending_keys
        or pending.get("type") != REMOTE_MARKETPLACE_EVIDENCE_TYPE
        or pending.get("status") != "pending"
        or pending.get("required") is not True
        or pending.get("artifact_sha256") != ""
        or pending.get("verified_content_head") != git.get("reviewed_work_head")
        or pending.get("remote_head") != ""
        or pending.get("publish_head") != git.get("reviewed_work_head")
        or pending.get("commands_passed") is not False
    ):
        errors.append("closeout pending marketplace machine identity is invalid.")
    if not isinstance(marketplace.get("required"), bool):
        errors.append("closeout marketplace required must be boolean.")
    if pending.get("artifact_path") != MARKETPLACE_VERIFICATION_ARTIFACT:
        errors.append("closeout marketplace artifact locator must be task-relative.")
    if marketplace.get("verifier_artifact_locator") != pending.get("artifact_path"):
        errors.append("closeout verifier locator does not match pending machine identity.")
    if projection.get("active_locator") != task.get("active_locator") or projection.get("archive_locator") != task.get("archive_locator"):
        errors.append("closeout projection task locators do not match task identity.")
    if projection.get("finish_summary_locator") != f"{task.get('archive_locator')}/{FINISH_SUMMARY_ARTIFACT}":
        errors.append("closeout projection finish-summary locator is invalid.")
    allowlist = projection.get("metadata_allowlist")
    if not isinstance(allowlist, list) or not allowlist or any(not isinstance(path, str) for path in allowlist) or allowlist != sorted(set(allowlist)):
        errors.append("closeout metadata allowlist must be sorted and unique.")
    elif any(finish_summary_path_errors(path, "projection.metadata_allowlist[]") for path in allowlist):
        errors.append("closeout metadata allowlist contains an unsafe path.")
    move_paths = projection.get("move_paths")
    if (
        not isinstance(move_paths, list)
        or not move_paths
        or any(
            not isinstance(path, str)
            or bool(finish_summary_path_errors(path, "projection.move_paths[]"))
            for path in move_paths
        )
        or move_paths != sorted(set(move_paths))
    ):
        errors.append("closeout move paths must be a sorted unique task-relative file set.")
        move_paths = []
    tracked_move_paths = projection.get("tracked_move_paths")
    if (
        not isinstance(tracked_move_paths, list)
        or not tracked_move_paths
        or tracked_move_paths != sorted(set(tracked_move_paths))
        or any(path not in move_paths for path in tracked_move_paths)
    ):
        errors.append("closeout tracked move paths must be a sorted non-empty subset of move paths.")
        tracked_move_paths = []
    untracked_archive_outputs = projection.get("untracked_archive_outputs")
    if (
        not isinstance(untracked_archive_outputs, list)
        or not untracked_archive_outputs
        or untracked_archive_outputs != sorted(set(untracked_archive_outputs))
        or any(path not in move_paths for path in untracked_archive_outputs)
    ):
        errors.append("closeout untracked archive outputs must be a sorted non-empty subset of move paths.")
        untracked_archive_outputs = []
    if (
        set(tracked_move_paths) & set(untracked_archive_outputs)
        or sorted(set(tracked_move_paths) | set(untracked_archive_outputs)) != move_paths
    ):
        errors.append("closeout tracked/untracked move classes must be disjoint and cover every move path.")
    if FINISH_SUMMARY_ARTIFACT not in untracked_archive_outputs:
        errors.append("closeout final summary must be classified as an untracked archive output.")
    expected_allowlist = sorted(
        [f"{task.get('active_locator')}/{path}" for path in tracked_move_paths]
        + [f"{task.get('archive_locator')}/{path}" for path in move_paths]
    )
    if allowlist != expected_allowlist:
        errors.append("closeout metadata allowlist must equal tracked active deletions plus all archive outputs.")
    evidence_paths = projection.get("evidence_paths")
    if (
        not isinstance(evidence_paths, list)
        or not evidence_paths
        or evidence_paths != sorted(set(evidence_paths))
        or any(
            path not in expected_allowlist
            or not path.startswith(f"{task.get('active_locator')}/")
            for path in evidence_paths
        )
    ):
        errors.append("closeout evidence paths must be the exact active-task pre-draft set.")
    placeholder = projection.get("summary_placeholder")
    expected_placeholder = closeout_pr_placeholder(str(git.get("repo") or "invalid/invalid"))
    if placeholder != expected_placeholder:
        errors.append("closeout summary PR placeholder is invalid.")
    if projection.get("runtime_fact_fields") != CLOSEOUT_SUMMARY_RUNTIME_FACT_FIELDS:
        errors.append("closeout summary runtime fact fields are invalid.")
    template = projection.get("summary_template")
    template_digest = str(projection.get("summary_template_sha256") or "")
    if not isinstance(template, dict):
        errors.append("closeout summary template must be an object.")
    else:
        template_errors = finish_summary_errors(template)
        if template_errors:
            errors.extend(f"closeout summary template: {error}" for error in template_errors)
        if template.get("github", {}).get("pr_url") != expected_placeholder["url"]:
            errors.append("closeout summary template PR URL must equal the deterministic placeholder.")
        if template.get("index", {}).get("search_terms", {}).get("pr_refs") != [expected_placeholder["ref"]]:
            errors.append("closeout summary template PR ref must equal the deterministic placeholder.")
        if template.get("task", {}).get("archive_dir") != task.get("archive_locator"):
            errors.append("closeout summary template archive locator is invalid.")
        template_artifacts = set(template.get("artifacts", {}).values()) if isinstance(template.get("artifacts"), dict) else set()
        if not template_artifacts.issubset(set(move_paths)):
            errors.append("closeout summary template artifacts are outside the planned move set.")
        if not re.fullmatch(r"[0-9a-f]{64}", template_digest) or template_digest != closeout_json_artifact_sha256(template):
            errors.append("closeout summary template digest does not match canonical content.")
    inputs = plan.get("inputs")
    if not isinstance(inputs, dict) or not inputs:
        errors.append("closeout inputs must be a non-empty object.")
    else:
        for key, item in inputs.items():
            if not isinstance(item, dict) or set(item) != {"path", "sha256"}:
                errors.append(f"closeout input {key} is invalid.")
            elif not re.fullmatch(r"[0-9a-f]{64}", str(item.get("sha256") or "")):
                errors.append(f"closeout input {key} digest is invalid.")
            else:
                errors.extend(finish_summary_path_errors(item.get("path"), f"inputs.{key}.path"))
    return errors


def validate_closeout_plan(plan: Any) -> dict[str, Any]:
    errors = closeout_plan_errors(plan)
    if errors:
        raise WorkflowError("closeout-plan validation failed.", exit_code=2, payload={"errors": errors})
    return plan


def build_closeout_plan(
    root: Path,
    task_dir: Path,
    task_context: dict[str, Any],
    task: dict[str, Any],
    gate_path: Path,
    gate: dict[str, Any],
    ledger: dict[str, Any],
    finish_summary_index_path: Path,
    *,
    repo: str,
    remote: str,
    base_branch: str,
    head_branch: str,
    reviewed_head: str,
    title: str,
) -> dict[str, Any]:
    active_locator = repo_relative(root, task_dir)
    existing_plan_path = closeout_plan_path(task_dir)
    existing_plan = read_json(existing_plan_path) if existing_plan_path.is_file() else {}
    if existing_plan:
        validate_closeout_plan(existing_plan)
    existing_task = existing_plan.get("task") if isinstance(existing_plan.get("task"), dict) else {}
    existing_projection = (
        existing_plan.get("projection")
        if isinstance(existing_plan.get("projection"), dict)
        else {}
    )
    reviewed_head_now = current_head(root)
    archive_month_now = current_archive_month()
    superseding_committed_month = False
    archive_locator = str(existing_task.get("archive_locator") or "")
    evidence_parent_head = reviewed_head
    if archive_locator and closeout_archive_month(existing_plan) != archive_month_now:
        if reviewed_head_now != reviewed_head:
            validate_closeout_evidence_commit(root, existing_plan, reviewed_head_now)
            superseding_committed_month = True
            evidence_parent_head = reviewed_head_now
        archive_locator = f".trellis/tasks/archive/{archive_month_now}/{task_dir.name}"
    if not archive_locator:
        archive_locator = f".trellis/tasks/archive/{archive_month_now}/{task_dir.name}"
    assert_closeout_archive_path_preflight(root, archive_locator)
    observed_task_files = {
        path.relative_to(task_dir).as_posix()
        for path in task_dir.rglob("*")
        if path.is_file()
    }
    active_prefix = f"{active_locator}/"
    observed_task_files.update(
        path.removeprefix(active_prefix)
        for path in git_status_paths(root)
        if path.startswith(active_prefix)
    )
    if existing_projection:
        task_files = set(existing_projection.get("move_paths", []))
        unexpected_task_files = sorted(observed_task_files - task_files)
        if unexpected_task_files:
            raise WorkflowError(
                "Persisted closeout plan does not own newly added task artifacts.",
                exit_code=2,
                payload={"unexpected_task_files": unexpected_task_files},
            )
    else:
        if (task_dir / FINISH_SUMMARY_ARTIFACT).exists():
            raise WorkflowError(
                "Initial closeout prepare found a stale final summary before the immutable plan existed.",
                exit_code=2,
            )
        task_files = set(observed_task_files)
        task_files.update({CLOSEOUT_PLAN_ARTIFACT, PR_READINESS_ARTIFACT, FINISH_SUMMARY_ARTIFACT})
        if marketplace_verification_required(gate):
            task_files.add(MARKETPLACE_VERIFICATION_ARTIFACT)
    move_paths = sorted(task_files)
    if existing_projection:
        tracked_move_paths = list(existing_projection.get("tracked_move_paths", []))
        untracked_archive_outputs = list(existing_projection.get("untracked_archive_outputs", []))
    else:
        untracked_archive_outputs = [FINISH_SUMMARY_ARTIFACT]
        tracked_move_paths = sorted(set(move_paths) - set(untracked_archive_outputs))
    metadata_allowlist = sorted(
        {f"{active_locator}/{name}" for name in tracked_move_paths}
        | {f"{archive_locator}/{name}" for name in move_paths}
    )
    if existing_projection and superseding_committed_month:
        evidence_paths = sorted(
            f"{active_locator}/{name}"
            for name in (CLOSEOUT_PLAN_ARTIFACT, PR_READINESS_ARTIFACT)
        )
    elif existing_projection:
        evidence_paths = list(existing_projection.get("evidence_paths", []))
    else:
        current_dirty = set(git_status_paths(root))
        evidence_names = {
            path.removeprefix(active_prefix)
            for path in current_dirty
            if path.startswith(active_prefix)
        }
        evidence_names.update({CLOSEOUT_PLAN_ARTIFACT, PR_READINESS_ARTIFACT})
        if marketplace_verification_required(gate):
            evidence_names.update({MARKETPLACE_VERIFICATION_ARTIFACT, "issue-scope-ledger.json"})
        evidence_paths = sorted(f"{active_locator}/{name}" for name in evidence_names)
    context_path = task_dir / str(DEFAULTS["task_start_context_artifact"])
    body_path = task_dir / PR_BODY_ARTIFACT
    ledger_path = issue_scope_ledger_path(task_dir)
    inputs = {
        "task_context": closeout_input_record(root, context_path, payload=task_context),
        "task": closeout_input_record(root, task_dir / "task.json"),
        "review_gate": closeout_input_record(root, gate_path, payload=gate),
        "issue_scope_ledger": closeout_input_record(
            root, ledger_path, payload=closeout_semantic_ledger(ledger)
        ),
        "pr_body": closeout_input_record(root, body_path),
        "finish_summary_index": closeout_input_record(root, finish_summary_index_path),
        "official_after_archive_hooks": closeout_input_record(
            root,
            root / ".trellis/config.yaml",
            payload=official_after_archive_hook_state(root),
        ),
    }
    config_path = root / ".trellis/guru-team/config.yml"
    if config_path.is_file():
        inputs["guru_team_config"] = closeout_input_record(root, config_path)
    source_issue = primary_issue_number_from_ledger(ledger)
    pending = closeout_pending_marketplace_evidence(root, task_dir, reviewed_head)
    placeholder = closeout_pr_placeholder(repo)
    generated_at = str(gate.get("generated_at") or "")
    if not re.fullmatch(r"[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}Z", generated_at):
        raise WorkflowError(
            "Branch Review Gate generated_at is required for the deterministic final-summary projection.",
            exit_code=2,
        )
    projected_ledger = (
        record_marketplace_machine_evidence(ledger, pending)
        if marketplace_verification_required(gate)
        else ledger
    )
    projected_artifacts = {
        key: filename
        for key, filename in FINISH_SUMMARY_ARTIFACT_FILES.items()
        if filename in task_files
    }
    summary_template = build_finish_summary(
        root,
        task_dir,
        task_context,
        projected_ledger,
        read_json(finish_summary_index_path),
        reviewed_head,
        pr_url=placeholder["url"],
        changed_paths=sorted(set(gate.get("changed_files", [])) | set(metadata_allowlist)),
        archive_dir_override=archive_locator,
        generated_at_override=generated_at,
        artifacts_override=projected_artifacts,
    )
    plan: dict[str, Any] = {
        "schema_version": CLOSEOUT_PLAN_SCHEMA_VERSION,
        "task": {
            "id": str(task.get("id") or task.get("name") or task_dir.name),
            "title": str(task.get("title") or task.get("name") or task_dir.name),
            "source_issue": source_issue,
            "active_locator": active_locator,
            "archive_locator": archive_locator,
        },
        "git": {
            "repo": repo,
            "remote": remote,
            "base_branch": normalize_ref(base_branch).removeprefix("origin/"),
            "head_branch": head_branch,
            "reviewed_work_head": reviewed_head,
            "evidence_parent_head": evidence_parent_head,
        },
        "inputs": inputs,
        "review": {
            "gate_locator": repo_relative(root, gate_path),
            "reviewed_head": str(gate.get("head") or ""),
            "changed_paths": sorted(set(str(path) for path in gate.get("changed_files", []) if str(path))),
            "close_issues_reviewed": sorted(set(issue_numbers(gate.get("issue_scope", {}).get("close_issues_reviewed")))),
        },
        "publish": {
            "title": title,
            "body_sha256": hashlib.sha256(body_path.read_bytes()).hexdigest(),
            "draft": True,
            "draft_to_ready": True,
            "match": {"repo": repo, "head": head_branch, "base": normalize_ref(base_branch).removeprefix("origin/")},
        },
        "marketplace": {
            "required": marketplace_verification_required(gate),
            "pending_machine": pending,
            "verifier_artifact_locator": MARKETPLACE_VERIFICATION_ARTIFACT,
        },
        "projection": {
            "active_locator": active_locator,
            "archive_locator": archive_locator,
            "finish_summary_locator": f"{archive_locator}/{FINISH_SUMMARY_ARTIFACT}",
            "metadata_allowlist": metadata_allowlist,
            "move_paths": move_paths,
            "tracked_move_paths": tracked_move_paths,
            "untracked_archive_outputs": untracked_archive_outputs,
            "evidence_paths": evidence_paths,
            "summary_placeholder": placeholder,
            "summary_template_sha256": closeout_json_artifact_sha256(summary_template),
            "summary_template": summary_template,
            "runtime_fact_fields": list(CLOSEOUT_SUMMARY_RUNTIME_FACT_FIELDS),
        },
        "transitions": list(CLOSEOUT_TRANSITIONS),
        "plan_digest": "",
    }
    plan["plan_digest"] = closeout_plan_digest(plan)
    return validate_closeout_plan(plan)


def prepare_closeout(
    root: Path,
    args: argparse.Namespace,
    config: dict[str, Any],
    task_dir: Path,
    task_context: dict[str, Any],
) -> dict[str, Any]:
    official_after_archive_hook_state(root)
    gate_path, gate, gate_errors = validate_review_gate(root, task_dir, config, True)
    if gate_errors:
        raise WorkflowError(
            "finish-work blocked because Branch Review Gate is not valid for the reviewed HEAD.",
            exit_code=2,
            payload={"artifact_path": str(gate_path), "errors": gate_errors},
        )
    dirty, dirty_paths = has_non_metadata_dirty_paths(root)
    if dirty:
        raise WorkflowError(
            "Working tree has uncommitted non-metadata changes. Commit task work before finish-work.",
            exit_code=2,
            payload={"dirty_paths": dirty_paths},
        )
    reviewed_head = str(gate.get("head") or "")
    if not re.fullmatch(r"[0-9a-f]{40}", reviewed_head):
        raise WorkflowError("Branch Review Gate reviewed HEAD is invalid.", exit_code=2)
    index_path, index = load_finish_summary_index(task_dir, args.finish_summary_index_file)
    ledger = load_issue_scope_ledger(task_dir, task_context)
    requires_marketplace = marketplace_verification_required(gate)
    if requires_marketplace:
        existing_targets: list[dict[str, Any]] = []
        if isinstance(ledger.get("primary_issue"), dict):
            existing_targets.append(ledger["primary_issue"])
        existing_targets.extend(item for item in ledger.get("close_issues", []) if isinstance(item, dict))
        tampered_errors: list[str] = []
        for issue in existing_targets:
            if remote_marketplace_evidence(issue) is None:
                continue
            pending_errors = remote_marketplace_evidence_errors(issue, allow_pending=True)
            passed_errors = remote_marketplace_evidence_errors(issue, allow_pending=False)
            if pending_errors and passed_errors:
                tampered_errors.extend(pending_errors)
        if tampered_errors:
            raise WorkflowError(
                "Existing marketplace machine evidence is malformed or tampered.",
                exit_code=2,
                payload={"errors": tampered_errors},
            )
        validation_ledger = record_marketplace_machine_evidence(
            ledger, closeout_pending_marketplace_evidence(root, task_dir, reviewed_head)
        )
    else:
        validation_ledger = ledger
    ledger_errors = validate_ledger_for_publish(
        validation_ledger, gate, allow_pending_remote_marketplace=requires_marketplace
    )
    if ledger_errors:
        raise WorkflowError("Issue Scope Ledger is incomplete for closeout.", exit_code=2, payload={"errors": ledger_errors})
    body, body_source = resolve_closeout_reviewed_body(root, task_dir, args)
    body_errors = validate_pr_body_quality(body, ledger, False)
    source_errors = validate_reviewed_body_source_for_publish(body_source, False)
    if body_errors or source_errors:
        raise WorkflowError(
            "finish-work blocked because PR readiness evidence is incomplete.",
            exit_code=2,
            payload={"errors": body_errors + source_errors, "body_source": body_source, "reviewed_source_ok": not source_errors},
        )
    task = task_json(task_dir)
    validate_closeout_task_children(task_dir, task)
    repo = normalize_github_repository(
        str(args.repo or config.get("github_repo") or "").strip() or infer_github_repo(root)
    )
    if not repo:
        raise WorkflowError("Could not resolve GitHub repo for closeout plan.", exit_code=2)
    base = base_branch_from_sources(args, task, task_context)
    branch = current_branch(root)
    remote = str(args.remote or publish_config(config).get("remote") or "origin")
    validate_github_remote_repository(root, remote, repo)
    title = pr_title_from_task(task, args)
    plan = build_closeout_plan(
        root, task_dir, task_context, task, gate_path, gate, ledger, index_path,
        repo=repo, remote=remote, base_branch=base, head_branch=branch,
        reviewed_head=reviewed_head, title=title,
    )
    month_supersession: dict[str, Any] | None = None
    existing = closeout_plan_path(task_dir)
    if existing.is_file():
        persisted = validate_closeout_plan(read_json(existing))
        if persisted != plan:
            previous_month = closeout_archive_month(persisted)
            next_month = closeout_archive_month(plan)
            committed = current_head(root) != reviewed_head
            supersession_errors = closeout_month_supersession_errors(
                persisted,
                plan,
                previous_evidence_head=current_head(root),
                committed=committed,
            )
            if (
                previous_month == next_month
                or task.get("status") != "in_progress"
                or (root / persisted["task"]["archive_locator"]).exists()
                or supersession_errors
            ):
                raise WorkflowError(
                    "Persisted closeout plan no longer matches protected inputs.",
                    exit_code=2,
                    payload={
                        "persisted_digest": persisted.get("plan_digest"),
                        "rebuilt_digest": plan.get("plan_digest"),
                        "month_supersession_errors": supersession_errors,
                    },
                )
            if committed:
                if not closeout_evidence_is_committed(root, task_dir, persisted, ledger, gate):
                    raise WorkflowError(
                        "Committed stale-month plan is not an exact evidence commit and cannot be superseded.",
                        exit_code=2,
                    )
                prior_state = "evidence_pushed"
            else:
                prior_state = resolve_closeout_pre_draft_state(
                    root, task_dir, persisted, ledger, gate
                )
                if prior_state not in {"content_pushed", "evidence_ready"}:
                    raise WorkflowError(
                        "Uncommitted stale-month plan has no unique reprepare state.",
                        exit_code=2,
                        payload={"state": prior_state},
                    )
            month_supersession = {
                "previous_plan": persisted,
                "previous_month": previous_month,
                "current_month": next_month,
                "committed": committed,
                "prior_state": prior_state,
            }
        else:
            plan = persisted
    return {
        "plan": plan,
        "plan_digest": plan["plan_digest"],
        "task": task,
        "task_context": task_context,
        "gate": gate,
        "gate_path": gate_path,
        "ledger": ledger,
        "finish_summary_index": index,
        "finish_summary_index_path": index_path,
        "body": body,
        "body_source": body_source,
        "month_supersession": month_supersession,
    }


def record_marketplace_machine_evidence(
    ledger: dict[str, Any], evidence: dict[str, Any]
) -> dict[str, Any]:
    updated = copy.deepcopy(ledger)
    targets: list[dict[str, Any]] = []
    primary = updated.get("primary_issue")
    if isinstance(primary, dict):
        targets.append(primary)
    close_issues = updated.get("close_issues")
    if isinstance(close_issues, list):
        targets.extend(item for item in close_issues if isinstance(item, dict))
    for issue in targets:
        values = issue.get("acceptance_evidence")
        if not isinstance(values, list):
            raise WorkflowError("Issue Scope Ledger acceptance_evidence must be an array.", exit_code=2)
        values[:] = [
            item for item in values
            if not (isinstance(item, dict) and item.get("type") == REMOTE_MARKETPLACE_EVIDENCE_TYPE)
        ]
        values.append(copy.deepcopy(evidence))
    return updated


def closeout_passed_marketplace_evidence(
    root: Path, verification_path: Path, verification: dict[str, Any]
) -> dict[str, Any]:
    if verification.get("status") != "passed" or marketplace_verification_contract_errors(verification):
        raise WorkflowError("Cannot record invalid marketplace verification.", exit_code=2)
    return {
        "type": REMOTE_MARKETPLACE_EVIDENCE_TYPE,
        "status": "passed",
        "required": True,
        "artifact_path": MARKETPLACE_VERIFICATION_ARTIFACT,
        "artifact_sha256": hashlib.sha256(verification_path.read_bytes()).hexdigest(),
        "verified_content_head": verification["verified_head"],
        "remote_head": verification["remote_head"],
        "publish_head": verification["verified_head"],
        "commands_passed": all(step.get("passed") is True for step in verification.get("steps", [])),
    }


def commit_closeout_evidence_metadata(root: Path, task_dir: Path, plan: dict[str, Any]) -> dict[str, Any]:
    names = [CLOSEOUT_PLAN_ARTIFACT, PR_READINESS_ARTIFACT]
    if plan["marketplace"]["required"]:
        names.extend([MARKETPLACE_VERIFICATION_ARTIFACT, "issue-scope-ledger.json"])
    required = {repo_relative(root, task_dir / name) for name in names}
    expected = set(plan["projection"]["evidence_paths"])
    dirty = set(git_status_paths(root))
    if dirty != expected:
        raise WorkflowError(
            "Closeout evidence metadata does not match the prevalidated exact path set.",
            exit_code=2,
            payload={
                "expected_paths": sorted(expected),
                "dirty_paths": sorted(dirty),
                "unexpected_dirty_paths": sorted(dirty - expected),
                "missing_dirty_paths": sorted(expected - dirty),
            },
        )
    missing = sorted(path for path in required if not (root / path).is_file())
    if missing:
        raise WorkflowError("Closeout evidence metadata is incomplete.", exit_code=2, payload={"missing_paths": missing})
    if not expected:
        raise WorkflowError("Closeout evidence metadata has no exact task-local changes to commit.", exit_code=2)
    run_stdout(["git", "add", "-A", "--", plan["task"]["active_locator"]], cwd=root)
    staged = set(run_stdout(["git", "diff", "--cached", "--name-only", "--no-renames"], cwd=root).splitlines())
    if staged != expected:
        raise WorkflowError("Closeout evidence staged paths do not match the exact allowlist.", exit_code=2, payload={"staged_paths": sorted(staged), "expected_paths": sorted(expected)})
    parent = current_head(root)
    expected_parent = closeout_evidence_parent_head(plan)
    if parent != expected_parent:
        raise WorkflowError(
            "Closeout evidence commit parent drifted from the immutable evidence parent.",
            exit_code=2,
            payload={"expected_parent": expected_parent, "actual_parent": parent},
        )
    run_stdout(["git", "commit", "-m", format_metadata_commit_subject(int(plan["task"]["source_issue"]))], cwd=root)
    commit = current_head(root)
    validate_closeout_evidence_commit(root, plan, commit)
    return {"commit": commit, "parent": parent, "paths": sorted(expected)}


def closeout_evidence_is_committed(
    root: Path,
    task_dir: Path,
    plan: dict[str, Any],
    ledger: dict[str, Any],
    gate: dict[str, Any],
) -> bool:
    required = [closeout_plan_path(task_dir), task_dir / PR_READINESS_ARTIFACT]
    if plan["marketplace"]["required"]:
        required.append(marketplace_verification_path(task_dir))
    if any(not path.is_file() for path in required):
        return False
    dirty = set(git_status_paths(root))
    if any(repo_relative(root, path) in dirty for path in required + [issue_scope_ledger_path(task_dir)]):
        return False
    targets = []
    if isinstance(ledger.get("primary_issue"), dict):
        targets.append(ledger["primary_issue"])
    targets.extend(item for item in ledger.get("close_issues", []) if isinstance(item, dict))
    if plan["marketplace"]["required"] and any(remote_marketplace_evidence_errors(issue, allow_pending=False) for issue in targets):
        return False
    _path, inputs, _body = read_pr_readiness_publish_inputs(
        root,
        task_dir,
        str(task_dir / PR_READINESS_ARTIFACT),
        gate,
        require_committed=True,
    )
    expected = {
        "repo": plan["git"]["repo"],
        "base_branch": plan["git"]["base_branch"],
        "head_branch": plan["git"]["head_branch"],
        "reviewed_head_sha": plan["git"]["reviewed_work_head"],
        "title": plan["publish"]["title"],
        "body_sha256": plan["publish"]["body_sha256"],
        "draft": True,
        "closeout_plan_digest": plan["plan_digest"],
    }
    if any(inputs.get(key) != value for key, value in expected.items()):
        raise WorkflowError("Committed closeout readiness does not match immutable plan.", exit_code=2)
    validate_closeout_evidence_commit(root, plan, current_head(root))
    return True


def resolve_closeout_pre_draft_state(
    root: Path,
    task_dir: Path,
    plan: dict[str, Any],
    ledger: dict[str, Any],
    gate: dict[str, Any],
) -> str:
    if closeout_evidence_is_committed(root, task_dir, plan, ledger, gate):
        return "evidence_pushed"

    plan_path = closeout_plan_path(task_dir)
    readiness_path = task_dir / PR_READINESS_ARTIFACT
    if not plan_path.exists() and not readiness_path.exists():
        return "prepared"
    if not plan_path.is_file() or not readiness_path.is_file():
        raise WorkflowError("Interrupted closeout has an incomplete plan/readiness pair.", exit_code=2)
    if validate_closeout_plan(read_json(plan_path)) != plan:
        raise WorkflowError("Interrupted closeout plan differs from the rebuilt immutable plan.", exit_code=2)
    _path, inputs, _body = read_pr_readiness_publish_inputs(
        root,
        task_dir,
        str(readiness_path),
        gate,
        require_committed=False,
    )
    expected_inputs = {
        "repo": plan["git"]["repo"],
        "base_branch": plan["git"]["base_branch"],
        "head_branch": plan["git"]["head_branch"],
        "reviewed_head_sha": plan["git"]["reviewed_work_head"],
        "title": plan["publish"]["title"],
        "body_sha256": plan["publish"]["body_sha256"],
        "draft": True,
        "closeout_plan_digest": plan["plan_digest"],
    }
    if any(inputs.get(key) != value for key, value in expected_inputs.items()):
        raise WorkflowError("Interrupted closeout readiness differs from the immutable plan.", exit_code=2)
    if current_head(root) != plan["git"]["reviewed_work_head"]:
        raise WorkflowError("Uncommitted closeout evidence is not based on the reviewed work HEAD.", exit_code=2)

    if not plan["marketplace"]["required"]:
        return "evidence_ready"
    targets: list[dict[str, Any]] = []
    if isinstance(ledger.get("primary_issue"), dict):
        targets.append(ledger["primary_issue"])
    targets.extend(item for item in ledger.get("close_issues", []) if isinstance(item, dict))
    evidence = [remote_marketplace_evidence(issue) for issue in targets]
    if evidence and all(item == plan["marketplace"]["pending_machine"] for item in evidence):
        return "content_pushed"

    verification_path = marketplace_verification_path(task_dir)
    if verification_path.is_file():
        verification = read_json(verification_path)
        if verification.get("status") == "passed" and not marketplace_verification_contract_errors(verification):
            passed = closeout_passed_marketplace_evidence(root, verification_path, verification)
            if evidence and all(item == passed for item in evidence):
                return "evidence_ready"
    raise WorkflowError("Interrupted closeout marketplace evidence has no unique resumable state.", exit_code=2)


def closeout_remote_branch_head(root: Path, plan: dict[str, Any]) -> str:
    proc = run(
        ["git", "ls-remote", "--heads", plan["git"]["remote"], plan["git"]["head_branch"]],
        cwd=root,
        check=False,
    )
    rows = [line.split() for line in proc.stdout.splitlines() if line.strip()]
    if proc.returncode != 0 or len(rows) > 1:
        raise WorkflowError("Could not resolve the unique closeout remote branch HEAD.", exit_code=2)
    return rows[0][0] if rows else ""


def push_closeout_branch_if_needed(root: Path, plan: dict[str, Any]) -> bool:
    local_head = current_head(root)
    if closeout_remote_branch_head(root, plan) == local_head:
        return False
    command = ["git", "push", plan["git"]["remote"], plan["git"]["head_branch"]]
    run_stdout(command, cwd=root)
    return True


def closeout_pull_request_head_repository(
    item: dict[str, Any], expected_repo: str
) -> tuple[str, bool]:
    expected = normalize_github_repository(expected_repo)
    repository = item.get("headRepository")
    owner = item.get("headRepositoryOwner")
    cross_repository = item.get("isCrossRepository")
    if (
        not expected
        or not isinstance(repository, dict)
        or not isinstance(owner, dict)
        or not isinstance(cross_repository, bool)
    ):
        raise WorkflowError("Closeout pull request head repository identity is missing or invalid.", exit_code=2)
    actual = normalize_github_repository(repository.get("nameWithOwner"))
    owner_login = str(owner.get("login") or "").strip().casefold()
    if not actual or owner_login != actual.split("/", 1)[0]:
        raise WorkflowError("Closeout pull request head repository fields are inconsistent.", exit_code=2)
    is_target = actual == expected
    if cross_repository != (not is_target):
        raise WorkflowError("Closeout pull request cross-repository identity is inconsistent.", exit_code=2)
    return actual, is_target


def resolve_closeout_pull_request(
    root: Path, repo: str, branch: str, base_branch: str, remote: str = "origin"
) -> dict[str, Any] | None:
    expected_repo = validate_github_remote_repository(root, remote, repo)
    proc = run(
        [
            "gh", "pr", "list", "--repo", repo, "--head", branch,
            "--base", base_branch, "--state", "open", "--limit", "100",
            "--json", (
                "number,url,title,body,headRefName,baseRefName,headRefOid,isDraft,"
                "headRepository,headRepositoryOwner,isCrossRepository"
            ),
        ],
        cwd=root,
        check=False,
    )
    if proc.returncode != 0:
        raise WorkflowError("Could not query closeout pull request identity.", exit_code=2, payload={"stderr": proc.stderr.strip()})
    try:
        values = json.loads(proc.stdout or "[]")
    except json.JSONDecodeError as exc:
        raise WorkflowError("Closeout pull request query returned invalid JSON.", exit_code=2) from exc
    if not isinstance(values, list):
        raise WorkflowError("Closeout pull request query must return an array.", exit_code=2)
    exact: list[dict[str, Any]] = []
    cross_repository: list[dict[str, Any]] = []
    for item in values:
        if not isinstance(item, dict):
            raise WorkflowError("Closeout pull request identity is invalid.", exit_code=2)
        number = item.get("number")
        if (
            not isinstance(number, int)
            or item.get("headRefName") != branch
            or item.get("baseRefName") != base_branch
        ):
            raise WorkflowError("Closeout pull request repo/head/base identity is invalid.", exit_code=2)
        actual_repo, is_target = closeout_pull_request_head_repository(item, expected_repo)
        if not is_target:
            cross_repository.append({"number": number, "head_repository": actual_repo})
            continue
        item["url"] = canonical_pull_request_url(expected_repo, number, item.get("url"))
        if not re.fullmatch(r"[0-9a-f]{40}", str(item.get("headRefOid") or "")):
            raise WorkflowError("Closeout pull request headRefOid is invalid.", exit_code=2)
        if not isinstance(item.get("isDraft"), bool):
            raise WorkflowError("Closeout pull request draft state is invalid.", exit_code=2)
        if not isinstance(item.get("title"), str) or not isinstance(item.get("body"), str):
            raise WorkflowError("Closeout pull request title/body identity is invalid.", exit_code=2)
        exact.append(item)
    if cross_repository:
        raise WorkflowError(
            "Closeout found cross-repository pull request candidates for the immutable head branch.",
            exit_code=2,
            payload={"candidates": cross_repository},
        )
    if len(exact) > 1:
        raise WorkflowError(
            "Closeout requires zero or one exact open pull request.",
            exit_code=2,
            payload={"open_pr_count": len(exact)},
        )
    return exact[0] if exact else None


def closeout_task_dir_from_plan(root: Path, plan: dict[str, Any]) -> Path:
    active = root / plan["task"]["active_locator"]
    archived = root / plan["task"]["archive_locator"]
    if active.is_dir() and not archived.exists():
        return active
    if archived.is_dir() and not active.exists():
        return archived
    raise WorkflowError(
        "Closeout PR identity requires exactly one active or archived task locator.",
        exit_code=2,
    )


def validate_closeout_remote_pull_request_identity(
    plan: dict[str, Any],
    pr: dict[str, Any],
    *,
    expected_draft: bool,
    expected_head: str | None = None,
    bound_pr: dict[str, Any] | None = None,
) -> None:
    expected_repo = normalize_github_repository(plan["git"]["repo"])
    actual_repo, is_target = closeout_pull_request_head_repository(pr, expected_repo)
    if not is_target or actual_repo != expected_repo:
        raise WorkflowError("Closeout pull request head repository differs from immutable readiness.", exit_code=2)
    number = pr.get("number")
    if not isinstance(number, int):
        raise WorkflowError("Closeout pull request number is invalid.", exit_code=2)
    canonical_url = canonical_pull_request_url(plan["git"]["repo"], number, pr.get("url"))
    if pr.get("url") != canonical_url:
        raise WorkflowError("Closeout pull request URL is not canonical.", exit_code=2)
    if (
        pr.get("headRefName") != plan["git"]["head_branch"]
        or pr.get("baseRefName") != plan["git"]["base_branch"]
    ):
        raise WorkflowError("Closeout pull request head/base differs from the immutable plan.", exit_code=2)
    if pr.get("title") != plan["publish"]["title"]:
        raise WorkflowError("Closeout pull request title differs from immutable readiness.", exit_code=2)
    body = pr.get("body")
    if not isinstance(body, str):
        raise WorkflowError("Closeout pull request body identity is invalid.", exit_code=2)
    try:
        body_digest = hashlib.sha256(body.encode("utf-8")).hexdigest()
    except UnicodeEncodeError as exc:
        raise WorkflowError("Closeout pull request body is not valid UTF-8.", exit_code=2) from exc
    if body_digest != plan["publish"]["body_sha256"]:
        raise WorkflowError("Closeout pull request body differs from immutable readiness.", exit_code=2)
    if pr.get("isDraft") is not expected_draft:
        state = "draft" if expected_draft else "ready"
        raise WorkflowError(f"Closeout pull request is not in expected {state} state.", exit_code=2)
    if expected_head is not None and pr.get("headRefOid") != expected_head:
        raise WorkflowError("Closeout pull request HEAD differs from the expected immutable stage HEAD.", exit_code=2)
    if bound_pr is not None:
        bound_number = bound_pr.get("number")
        if not isinstance(bound_number, int):
            raise WorkflowError("Bound closeout pull request number is invalid.", exit_code=2)
        bound_url = canonical_pull_request_url(plan["git"]["repo"], bound_number, bound_pr.get("url"))
        if number != bound_number or canonical_url != bound_url:
            raise WorkflowError("Closeout pull request number/URL differs from the bound remote identity.", exit_code=2)


def validate_closeout_pull_request_identity(
    root: Path,
    task_dir: Path,
    plan: dict[str, Any],
    pr: dict[str, Any],
    *,
    expected_draft: bool,
    require_summary: bool,
    expected_head: str | None = None,
) -> None:
    validate_closeout_remote_pull_request_identity(
        plan,
        pr,
        expected_draft=expected_draft,
        expected_head=expected_head,
    )
    number = pr["number"]
    canonical_url = canonical_pull_request_url(plan["git"]["repo"], number, pr.get("url"))

    body_path = task_dir / PR_BODY_ARTIFACT
    if not body_path.is_file():
        raise WorkflowError("Closeout immutable PR body artifact is missing.", exit_code=2)
    body_bytes = body_path.read_bytes()
    if hashlib.sha256(body_bytes).hexdigest() != plan["publish"]["body_sha256"]:
        raise WorkflowError("Closeout immutable PR body digest does not match the plan.", exit_code=2)
    try:
        expected_body = body_bytes.decode("utf-8")
    except UnicodeDecodeError as exc:
        raise WorkflowError("Closeout immutable PR body is not valid UTF-8.", exit_code=2) from exc
    if pr.get("body") != expected_body:
        raise WorkflowError("Closeout pull request body differs from immutable readiness.", exit_code=2)

    summary_path = task_dir / FINISH_SUMMARY_ARTIFACT
    if require_summary and not summary_path.is_file():
        raise WorkflowError("Closeout final summary is missing for PR identity validation.", exit_code=2)
    if summary_path.is_file():
        summary = read_and_validate_closeout_final_summary(summary_path, plan)
        expected_ref = f"PR #{number}"
        if (
            summary.get("github", {}).get("pr_url") != canonical_url
            or summary.get("index", {}).get("search_terms", {}).get("pr_refs") != [expected_ref]
        ):
            raise WorkflowError(
                "Closeout final summary does not reference the same immutable pull request.",
                exit_code=2,
            )


def ensure_closeout_draft_pr(root: Path, plan: dict[str, Any], body: str) -> dict[str, Any]:
    git = plan["git"]
    task_dir = closeout_task_dir_from_plan(root, plan)
    existing = resolve_closeout_pull_request(
        root, git["repo"], git["head_branch"], git["base_branch"], git["remote"]
    )
    if existing is not None:
        validate_closeout_pull_request_identity(
            root,
            task_dir,
            plan,
            existing,
            expected_draft=True,
            require_summary=False,
            expected_head=current_head(root),
        )
        return existing
    pr_url = create_pull_request(
        root, git["repo"], git["base_branch"], git["head_branch"],
        plan["publish"]["title"], body, True,
    )
    number = parse_pull_request_number(pr_url)
    if number is None:
        raise WorkflowError("Could not parse draft PR identity.", exit_code=2)
    created = resolve_closeout_pull_request(
        root, git["repo"], git["head_branch"], git["base_branch"], git["remote"]
    )
    if created is None or created.get("number") != number:
        raise WorkflowError("Created draft PR could not be rebound to one immutable identity.", exit_code=2)
    validate_closeout_pull_request_identity(
        root,
        task_dir,
        plan,
        created,
        expected_draft=True,
        require_summary=False,
        expected_head=current_head(root),
    )
    return created


def validate_closeout_marketplace_artifact(
    root: Path, task_dir: Path, plan: dict[str, Any], ledger: dict[str, Any]
) -> None:
    if not plan["marketplace"]["required"]:
        return
    locator = plan["marketplace"]["verifier_artifact_locator"]
    if locator != MARKETPLACE_VERIFICATION_ARTIFACT:
        raise WorkflowError("Marketplace verifier locator is not task-relative.", exit_code=2)
    artifact = task_dir / locator
    if not artifact.is_file():
        raise WorkflowError("Marketplace verifier artifact is missing from the task.", exit_code=2)
    verification = read_json(artifact)
    if verification.get("status") != "passed" or marketplace_verification_contract_errors(verification):
        raise WorkflowError("Marketplace verifier artifact is not a passed canonical artifact.", exit_code=2)
    expected = closeout_passed_marketplace_evidence(root, artifact, verification)
    targets: list[dict[str, Any]] = []
    if isinstance(ledger.get("primary_issue"), dict):
        targets.append(ledger["primary_issue"])
    targets.extend(item for item in ledger.get("close_issues", []) if isinstance(item, dict))
    mismatches = [
        int(issue.get("number") or 0)
        for issue in targets
        if remote_marketplace_evidence(issue) != expected
    ]
    if mismatches:
        raise WorkflowError(
            "Marketplace ledger evidence does not match the task-relative artifact digest.",
            exit_code=2,
            payload={"issue_numbers": mismatches, "artifact_path": locator},
        )


def build_final_archive_projection(
    root: Path,
    task_dir: Path,
    prepared: dict[str, Any],
    pr: dict[str, Any],
) -> tuple[Path, dict[str, Any]]:
    plan = prepared["plan"]
    ledger = load_issue_scope_ledger(task_dir, prepared["task_context"])
    ledger_errors = validate_ledger_for_publish(ledger, prepared["gate"])
    if ledger_errors:
        raise WorkflowError("Final projection ledger validation failed.", exit_code=2, payload={"errors": ledger_errors})
    readiness = read_json(task_dir / PR_READINESS_ARTIFACT)
    inputs = readiness.get("publish_inputs") if isinstance(readiness.get("publish_inputs"), dict) else {}
    if inputs.get("closeout_plan_digest") != plan["plan_digest"]:
        raise WorkflowError("Final projection readiness digest does not match closeout plan.", exit_code=2)
    validate_closeout_pull_request_identity(
        root,
        task_dir,
        plan,
        pr,
        expected_draft=True,
        require_summary=False,
        expected_head=current_head(root),
    )
    validate_closeout_marketplace_artifact(root, task_dir, plan, ledger)
    summary = closeout_summary_for_pr(plan, pr)
    if summary["index"]["search_terms"]["pr_refs"] != [f"PR #{pr['number']}"]:
        raise WorkflowError("Final projection must contain one canonical PR ref.", exit_code=2)
    required_artifacts = set(summary["artifacts"].values()) | {
        CLOSEOUT_PLAN_ARTIFACT, PR_READINESS_ARTIFACT, FINISH_SUMMARY_INDEX_ARTIFACT,
        "issue-scope-ledger.json", "review-gate.json", PR_BODY_ARTIFACT,
    }
    missing = sorted(name for name in required_artifacts if not (task_dir / name).is_file())
    if missing:
        raise WorkflowError("Final archive projection is missing task artifacts.", exit_code=2, payload={"missing": missing})
    validate_closeout_final_summary(plan, summary)
    path = task_dir / FINISH_SUMMARY_ARTIFACT
    write_json(path, summary)
    read_and_validate_closeout_final_summary(path, plan)
    return path, summary


def closeout_commit_paths(root: Path, commit: str) -> set[str]:
    return set(
        run_stdout(
            ["git", "diff-tree", "--no-commit-id", "--name-only", "--no-renames", "-r", commit],
            cwd=root,
        ).splitlines()
    )


def closeout_archive_transaction_paths(plan: dict[str, Any]) -> set[str]:
    projection = plan["projection"]
    active = plan["task"]["active_locator"]
    archived = plan["task"]["archive_locator"]
    return {
        *(f"{active}/{path}" for path in projection["tracked_move_paths"]),
        *(f"{archived}/{path}" for path in projection["move_paths"]),
    }


def validate_closeout_archive_git_paths(
    paths: set[str], plan: dict[str, Any], *, stage: str
) -> None:
    expected = closeout_archive_transaction_paths(plan)
    if paths != expected:
        raise WorkflowError(
            f"Closeout {stage} paths do not equal the immutable tracked/untracked archive transaction.",
            exit_code=2,
            payload={
                "stage": stage,
                "expected_paths": sorted(expected),
                "actual_paths": sorted(paths),
                "missing_paths": sorted(expected - paths),
                "extra_paths": sorted(paths - expected),
            },
        )


def closeout_commit_parent(root: Path, commit: str) -> str:
    return run_stdout(["git", "rev-parse", f"{commit}^"], cwd=root)


def closeout_commit_tracked_task_paths(
    root: Path, commit: str, active_locator: str
) -> set[str]:
    return set(
        run_stdout(
            ["git", "ls-tree", "-r", "--name-only", commit, "--", active_locator],
            cwd=root,
        ).splitlines()
    )


def validate_closeout_evidence_commit(
    root: Path,
    plan: dict[str, Any],
    commit: str,
    *,
    _seen: set[str] | None = None,
) -> None:
    seen = set(_seen or set())
    if commit in seen or len(seen) >= 24:
        raise WorkflowError("Closeout evidence supersession chain is cyclic or too deep.", exit_code=2)
    seen.add(commit)
    parent = closeout_commit_parent(root, commit)
    expected_parent = closeout_evidence_parent_head(plan)
    paths = closeout_commit_paths(root, commit)
    expected_paths = set(plan["projection"]["evidence_paths"])
    active = plan["task"]["active_locator"]
    tracked_paths = closeout_commit_tracked_task_paths(root, commit, active)
    expected_tracked_paths = {
        f"{active}/{path}" for path in plan["projection"]["tracked_move_paths"]
    }
    if (
        parent != expected_parent
        or paths != expected_paths
        or tracked_paths != expected_tracked_paths
    ):
        raise WorkflowError(
            "Closeout evidence commit does not match the prevalidated parent/path/tracking snapshot.",
            exit_code=2,
            payload={
                "commit": commit,
                "expected_parent": expected_parent,
                "actual_parent": parent,
                "expected_paths": sorted(expected_paths),
                "actual_paths": sorted(paths),
                "expected_tracked_paths": sorted(expected_tracked_paths),
                "actual_tracked_paths": sorted(tracked_paths),
            },
        )
    if expected_parent != plan["git"]["reviewed_work_head"]:
        previous_path = f"{plan['task']['active_locator']}/{CLOSEOUT_PLAN_ARTIFACT}"
        previous_bytes = closeout_optional_commit_blob_bytes(root, expected_parent, previous_path)
        if previous_bytes is None:
            raise WorkflowError(
                "Closeout evidence supersession parent is missing its committed active plan.",
                exit_code=2,
            )
        try:
            previous = validate_closeout_plan(json.loads(previous_bytes.decode("utf-8")))
        except (UnicodeDecodeError, json.JSONDecodeError) as exc:
            raise WorkflowError(
                "Closeout evidence supersession parent plan is invalid.", exit_code=2
            ) from exc
        supersession_errors = closeout_month_supersession_errors(
            previous,
            plan,
            previous_evidence_head=expected_parent,
            committed=True,
        )
        if supersession_errors:
            raise WorkflowError(
                "Closeout evidence supersession lineage is invalid.",
                exit_code=2,
                payload={"errors": supersession_errors},
            )
        validate_closeout_evidence_commit(root, previous, expected_parent, _seen=seen)


def validate_closeout_active_projection(root: Path, task_dir: Path, plan: dict[str, Any]) -> None:
    if repo_relative(root, task_dir) != plan["task"]["active_locator"] or not task_dir.is_dir():
        raise WorkflowError("Closeout active projection locator is invalid.", exit_code=2)
    actual_files = sorted(path.relative_to(task_dir).as_posix() for path in task_dir.rglob("*") if path.is_file())
    expected_files = plan["projection"]["move_paths"]
    if actual_files != expected_files:
        raise WorkflowError(
            "Closeout active projection does not match the complete planned move set.",
            exit_code=2,
            payload={"expected_files": expected_files, "actual_files": actual_files},
        )
    read_and_validate_closeout_final_summary(task_dir / FINISH_SUMMARY_ARTIFACT, plan)
    ledger = read_json(task_dir / "issue-scope-ledger.json")
    validate_closeout_marketplace_artifact(root, task_dir, plan, ledger)


def closeout_commit_tree_entry(root: Path, commit: str, path: str) -> tuple[str, str, str]:
    proc = run(["git", "ls-tree", commit, "--", path], cwd=root, check=False)
    rows = [line for line in proc.stdout.splitlines() if line]
    if proc.returncode != 0 or len(rows) != 1:
        raise WorkflowError(
            "Closeout evidence commit is missing one exact tracked move path.",
            exit_code=2,
            payload={"commit": commit, "path": path, "stage": "pre-archive-continuity"},
        )
    metadata, separator, actual_path = rows[0].partition("\t")
    fields = metadata.split()
    if separator != "\t" or actual_path != path or len(fields) != 3:
        raise WorkflowError(
            "Closeout evidence tree entry is ambiguous.",
            exit_code=2,
            payload={"commit": commit, "path": path, "stage": "pre-archive-continuity"},
        )
    return fields[0], fields[1], fields[2]


def closeout_untracked_paths(root: Path) -> set[str]:
    proc = run(
        ["git", "ls-files", "--others", "--exclude-standard", "-z"],
        cwd=root,
        check=False,
    )
    if proc.returncode != 0:
        raise WorkflowError("Could not enumerate pre-archive untracked paths.", exit_code=2)
    return {path for path in proc.stdout.split("\0") if path}


def validate_closeout_pre_move_continuity(
    root: Path,
    task_dir: Path,
    plan: dict[str, Any],
    evidence_commit: str,
    *,
    expected_summary_pr: dict[str, Any] | None = None,
) -> None:
    """Validate every local archive input before official task.py can mutate it."""
    assert_closeout_archive_month_current(plan)
    hook_state = official_after_archive_hook_state(root)
    hook_input = plan.get("inputs", {}).get("official_after_archive_hooks")
    if (
        not isinstance(hook_input, dict)
        or hook_input.get("path") != ".trellis/config.yaml"
        or hook_input.get("sha256") != canonical_json_sha256(hook_state)
    ):
        raise WorkflowError(
            "Official after_archive hook state drifted from the immutable closeout plan.",
            exit_code=2,
            payload={"stage": "after-archive-hook-preflight", "hook_executed": False},
        )

    active_locator = plan["task"]["active_locator"]
    for relative in plan["projection"]["move_paths"]:
        target = task_dir / relative
        try:
            working_mode = os.lstat(target).st_mode
        except OSError as exc:
            raise WorkflowError(
                "Closeout pre-archive move path is missing or unreadable.",
                exit_code=2,
                payload={"path": relative, "stage": "pre-archive-continuity"},
            ) from exc
        if not stat.S_ISREG(working_mode):
            raise WorkflowError(
                "Closeout pre-archive move paths must be regular files; symlinks and special modes are rejected.",
                exit_code=2,
                payload={"path": relative, "stage": "pre-archive-continuity"},
            )

    closeout_summary_runtime_pr_facts_from_bytes(
        plan,
        (task_dir / FINISH_SUMMARY_ARTIFACT).read_bytes(),
        expected_pr=expected_summary_pr,
    )

    for relative in plan["projection"]["tracked_move_paths"]:
        repo_path = f"{active_locator}/{relative}"
        git_mode, object_type, _object_id = closeout_commit_tree_entry(
            root, evidence_commit, repo_path
        )
        if object_type != "blob" or git_mode not in {"100644", "100755"}:
            raise WorkflowError(
                "Closeout tracked move paths must be regular Git blobs, not symlinks, submodules, or special modes.",
                exit_code=2,
                payload={
                    "path": relative,
                    "git_mode": git_mode,
                    "object_type": object_type,
                    "stage": "pre-archive-continuity",
                },
            )
        target = task_dir / relative
        working_mode = os.lstat(target).st_mode
        expected_working_mode = "100755" if working_mode & 0o111 else "100644"
        if expected_working_mode != git_mode:
            raise WorkflowError(
                "Closeout tracked file mode differs from the immutable evidence commit.",
                exit_code=2,
                payload={
                    "path": relative,
                    "expected_mode": git_mode,
                    "actual_mode": expected_working_mode,
                    "stage": "pre-archive-continuity",
                },
            )
        before = closeout_commit_blob_bytes(root, evidence_commit, repo_path)
        if target.read_bytes() != before:
            raise WorkflowError(
                "Closeout tracked output differs from the immutable evidence blob before archive.",
                exit_code=2,
                payload={"path": relative, "stage": "pre-archive-continuity"},
            )

    expected_outputs = {
        f"{active_locator}/{relative}"
        for relative in plan["projection"]["untracked_archive_outputs"]
    }
    dirty = set(git_status_paths(root))
    staged = set(
        run_stdout(
            ["git", "diff", "--cached", "--name-only", "--no-renames"], cwd=root
        ).splitlines()
    )
    untracked = closeout_untracked_paths(root)
    if dirty != expected_outputs or staged or untracked != expected_outputs:
        raise WorkflowError(
            "Closeout pre-archive dirty/staged/untracked paths do not match the immutable final outputs.",
            exit_code=2,
            payload={
                "stage": "pre-archive-continuity",
                "next_transition": "archive-move",
                "expected_paths": sorted(expected_outputs),
                "dirty_paths": sorted(dirty),
                "staged_paths": sorted(staged),
                "untracked_paths": sorted(untracked),
            },
        )


def validate_closeout_archive_move_layout(root: Path, archived: Path, plan: dict[str, Any]) -> None:
    active = root / plan["task"]["active_locator"]
    expected_archived = root / plan["task"]["archive_locator"]
    if (
        active.exists()
        or closeout_lexical_path(archived) != closeout_lexical_path(expected_archived)
        or archived.is_symlink()
        or not archived.is_dir()
    ):
        raise WorkflowError(
            "Archived closeout must have no active locator and one complete planned archive locator.",
            exit_code=2,
        )
    actual_files = sorted(path.relative_to(archived).as_posix() for path in archived.rglob("*") if path.is_file())
    expected_files = plan["projection"]["move_paths"]
    if actual_files != expected_files:
        raise WorkflowError(
            "Archived closeout files do not match the complete prevalidated move set.",
            exit_code=2,
            payload={"expected_files": expected_files, "actual_files": actual_files},
        )


def closeout_commit_blob_bytes(root: Path, commit: str, path: str) -> bytes:
    proc = subprocess.run(
        ["git", "show", f"{commit}:{path}"],
        cwd=root,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        check=False,
    )
    if proc.returncode != 0:
        raise WorkflowError(
            "Closeout could not read an immutable Git blob.",
            exit_code=2,
            payload={"commit": commit, "path": path},
        )
    return proc.stdout


def closeout_optional_commit_blob_bytes(root: Path, commit: str, path: str) -> bytes | None:
    proc = subprocess.run(
        ["git", "show", f"{commit}:{path}"],
        cwd=root,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        check=False,
    )
    return proc.stdout if proc.returncode == 0 else None


def validate_closeout_task_json_archive_change(before: bytes, after: bytes) -> None:
    try:
        before_payload = json.loads(before.decode("utf-8"))
        after_payload = json.loads(after.decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise WorkflowError("Closeout task.json archive blobs are invalid JSON.", exit_code=2) from exc
    if not isinstance(before_payload, dict) or not isinstance(after_payload, dict):
        raise WorkflowError("Closeout task.json archive blobs must be objects.", exit_code=2)
    expected = copy.deepcopy(before_payload)
    expected["status"] = "completed"
    completed_at = after_payload.get("completedAt")
    if not isinstance(completed_at, str) or not re.fullmatch(r"\d{4}-\d{2}-\d{2}", completed_at):
        raise WorkflowError("Archived task.json completedAt is not an official date value.", exit_code=2)
    expected["completedAt"] = completed_at
    if after_payload != expected:
        raise WorkflowError(
            "Archived task.json contains changes beyond the official status/completedAt transition.",
            exit_code=2,
        )


def validate_closeout_archive_blob_continuity(
    root: Path,
    archived: Path,
    plan: dict[str, Any],
    evidence_commit: str,
    *,
    archive_commit: str | None = None,
    expected_summary_pr: dict[str, Any] | None = None,
) -> dict[str, Any]:
    active_locator = plan["task"]["active_locator"]
    archive_locator = plan["task"]["archive_locator"]
    for relative in plan["projection"]["tracked_move_paths"]:
        before = closeout_commit_blob_bytes(root, evidence_commit, f"{active_locator}/{relative}")
        if archive_commit is None:
            target = archived / relative
            if not target.is_file():
                raise WorkflowError(
                    "Archived tracked output is missing during content validation.",
                    exit_code=2,
                    payload={"path": relative},
                )
            after = target.read_bytes()
        else:
            after = closeout_commit_blob_bytes(root, archive_commit, f"{archive_locator}/{relative}")
        if relative == "task.json":
            validate_closeout_task_json_archive_change(before, after)
        elif before != after:
            raise WorkflowError(
                "Archived tracked output differs from the immutable evidence blob.",
                exit_code=2,
                payload={"path": relative},
            )
    if archive_commit is None:
        summary_path = archived / FINISH_SUMMARY_ARTIFACT
        try:
            summary_bytes = summary_path.read_bytes()
        except OSError as exc:
            raise WorkflowError("Archived final summary is missing during continuity validation.", exit_code=2) from exc
    else:
        summary_bytes = closeout_commit_blob_bytes(
            root,
            archive_commit,
            f"{archive_locator}/{FINISH_SUMMARY_ARTIFACT}",
        )
    return closeout_summary_runtime_pr_facts_from_bytes(
        plan,
        summary_bytes,
        expected_pr=expected_summary_pr,
    )


def validate_closeout_archive_commit_tree(
    root: Path, plan: dict[str, Any], archive_commit: str
) -> None:
    active_locator = plan["task"]["active_locator"]
    archive_locator = plan["task"]["archive_locator"]
    active_paths = closeout_commit_tracked_task_paths(root, archive_commit, active_locator)
    archived_paths = closeout_commit_tracked_task_paths(root, archive_commit, archive_locator)
    expected_archived_paths = {
        f"{archive_locator}/{relative}" for relative in plan["projection"]["move_paths"]
    }
    if active_paths or archived_paths != expected_archived_paths:
        raise WorkflowError(
            "Closeout archive commit tree does not contain the exact completed task move.",
            exit_code=2,
            payload={
                "commit": archive_commit,
                "unexpected_active_paths": sorted(active_paths),
                "expected_archive_paths": sorted(expected_archived_paths),
                "actual_archive_paths": sorted(archived_paths),
            },
        )


def resolve_committed_closeout_archive_transaction(
    root: Path, plan: dict[str, Any]
) -> dict[str, Any] | None:
    archive_commit = current_head(root)
    committed_paths = closeout_commit_paths(root, archive_commit)
    if committed_paths != closeout_archive_transaction_paths(plan):
        return None
    validate_closeout_archive_git_paths(committed_paths, plan, stage="archive-committed-head")
    evidence_commit = closeout_commit_parent(root, archive_commit)
    validate_closeout_evidence_commit(root, plan, evidence_commit)
    validate_closeout_archive_commit_tree(root, plan, archive_commit)
    summary_pr = validate_closeout_archive_blob_continuity(
        root,
        root / plan["task"]["archive_locator"],
        plan,
        evidence_commit,
        archive_commit=archive_commit,
    )
    return {
        "commit": archive_commit,
        "parent": evidence_commit,
        "paths": sorted(committed_paths),
        "summary_pr": summary_pr,
    }


def assert_archived_committed_workspace_boundary(
    root: Path,
    config: dict[str, Any],
    task_dir: Path,
    expected_plan_digest: str,
) -> dict[str, Any]:
    root = closeout_lexical_path(root)
    task_dir = closeout_lexical_path(task_dir)
    try:
        task_locator = task_dir.relative_to(root).as_posix()
    except ValueError as exc:
        raise WorkflowError(
            "Archived closeout workspace boundary task locator is outside the repository.",
            exit_code=2,
            payload={"repo_root": str(root), "task_dir": str(task_dir)},
        ) from exc

    git_root = Path(run_stdout(["git", "rev-parse", "--show-toplevel"], cwd=root)).resolve()
    if git_root != root:
        raise WorkflowError(
            "Archived closeout workspace boundary repository root mismatch.",
            exit_code=2,
            payload={"expected_root": str(root), "actual_git_root": str(git_root)},
        )
    if (
        not task_dir_is_archived(root, task_dir)
        or not path_within(tasks_root(root) / "archive", task_dir)
    ):
        raise WorkflowError(
            "Archived closeout workspace boundary task locator is invalid.",
            exit_code=2,
            payload={"repo_root": str(root), "task_dir": str(task_dir)},
        )

    archive_commit = current_head(root)
    archive_plan_path = f"{task_locator}/{CLOSEOUT_PLAN_ARTIFACT}"
    plan_blob = closeout_optional_commit_blob_bytes(root, archive_commit, archive_plan_path)
    plan_source = "archive"
    if plan_blob is None:
        active_plan_path = f".trellis/tasks/{task_dir.name}/{CLOSEOUT_PLAN_ARTIFACT}"
        plan_blob = closeout_optional_commit_blob_bytes(root, archive_commit, active_plan_path)
        plan_source = "active"
    if plan_blob is None:
        raise WorkflowError(
            "Archived closeout current commit contains neither the exact archive plan nor the evidence-commit active plan.",
            exit_code=2,
            payload={"head": archive_commit, "task_dir": task_locator},
        )
    try:
        raw_plan = json.loads(plan_blob.decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise WorkflowError(
            "Archived closeout committed plan is invalid JSON.",
            exit_code=2,
        ) from exc
    plan = validate_closeout_plan(raw_plan)
    if expected_plan_digest != plan["plan_digest"]:
        raise WorkflowError(
            "Archived closeout workspace boundary expected digest mismatch.",
            exit_code=2,
            payload={
                "expected": expected_plan_digest,
                "actual": plan["plan_digest"],
            },
        )

    task = plan["task"]
    git = plan["git"]
    projection = plan["projection"]
    summary = projection["summary_template"]
    summary_task = summary.get("task") if isinstance(summary.get("task"), dict) else {}
    summary_git = summary.get("git") if isinstance(summary.get("git"), dict) else {}
    summary_github = summary.get("github") if isinstance(summary.get("github"), dict) else {}
    active_locator = str(task["active_locator"])
    archive_locator = str(task["archive_locator"])
    expected_task_dir = closeout_lexical_path(root / archive_locator)
    try:
        resolved_task_dir = task_dir.resolve(strict=True)
        resolved_expected_task_dir = expected_task_dir.resolve(strict=True)
    except (FileNotFoundError, OSError) as exc:
        raise WorkflowError(
            "Archived closeout workspace boundary could not resolve the validated task locator.",
            exit_code=2,
            payload={"task_dir": str(task_dir), "archive_locator": archive_locator},
        ) from exc
    active_parts = Path(active_locator).parts
    archive_parts = Path(archive_locator).parts
    source_issues = summary_github.get("source_issues")
    locator_identity_valid = (
        task_locator == archive_locator
        and resolved_task_dir == resolved_expected_task_dir
        and active_parts[:2] == (".trellis", "tasks")
        and len(active_parts) == 3
        and archive_parts[:3] == (".trellis", "tasks", "archive")
        and len(archive_parts) == 5
        and active_parts[-1] == archive_parts[-1] == task_dir.name
        and not (root / active_locator).exists()
        and CLOSEOUT_PLAN_ARTIFACT in projection["tracked_move_paths"]
        and summary_task.get("slug") == task_dir.name
        and summary_task.get("title") == task["title"]
        and summary_task.get("artifact_dir") == active_locator
        and summary_task.get("archive_dir") == archive_locator
        and summary_git.get("branch") == git["head_branch"]
        and summary_git.get("base_branch") == git["base_branch"]
        and isinstance(source_issues, list)
        and task["source_issue"] in source_issues
    )
    if not locator_identity_valid:
        raise WorkflowError(
            "Archived closeout workspace boundary task identity or locator mismatch.",
            exit_code=2,
            payload={
                "task_dir": task_locator,
                "active_locator": active_locator,
                "archive_locator": archive_locator,
            },
        )

    configured_repo_value = str(config.get("github_repo") or "").strip()
    configured_repo = normalize_github_repository(configured_repo_value)
    if configured_repo_value and configured_repo != git["repo"]:
        raise WorkflowError(
            "Archived closeout workspace boundary configured repository mismatch.",
            exit_code=2,
            payload={"expected_repo": git["repo"], "configured_repo": configured_repo},
        )
    validate_github_remote_repository(root, git["remote"], git["repo"])
    actual_branch = current_branch(root)
    if actual_branch != git["head_branch"]:
        raise WorkflowError(
            "Archived closeout workspace boundary branch mismatch.",
            exit_code=2,
            payload={"expected_branch": git["head_branch"], "actual_branch": actual_branch},
        )
    base_refs = [git["base_branch"], f"{git['remote']}/{git['base_branch']}"]
    if not any(git_branch_exists(root, ref) for ref in base_refs):
        raise WorkflowError(
            "Archived closeout workspace boundary base branch is unavailable.",
            exit_code=2,
            payload={"base_branch": git["base_branch"], "checked_refs": base_refs},
        )

    transaction = resolve_committed_closeout_archive_transaction(root, plan)
    if plan_source == "archive" and transaction is None:
        raise WorkflowError(
            "Archived closeout workspace boundary requires the exact committed archive transaction.",
            exit_code=2,
            payload={"head": archive_commit, "task_dir": task_locator},
        )
    if plan_source == "active":
        if transaction is not None:
            raise WorkflowError(
                "Archived closeout evidence-plan fallback cannot replace an exact archive plan.",
                exit_code=2,
            )
        validate_closeout_evidence_commit(root, plan, archive_commit)
    return {
        "status": "ok",
        "mode": (
            "archived-committed-exact"
            if transaction is not None
            else "archived-incomplete-move"
        ),
        "repo_root": str(root),
        "task_dir": str(task_dir),
        "task_dir_relative": task_locator,
        "plan": plan,
        "archive_commit": transaction,
    }


def execute_archive_metadata_transaction(
    root: Path,
    task_dir: Path,
    plan: dict[str, Any],
    *,
    bound_pr: dict[str, Any] | None = None,
) -> tuple[Path, dict[str, Any]]:
    archive_script = root / ".trellis/scripts/task.py"
    if not archive_script.is_file():
        raise WorkflowError(f"Trellis task.py not found: {archive_script}")
    evidence_commit = current_head(root)
    validate_closeout_evidence_commit(root, plan, evidence_commit)
    validate_closeout_active_projection(root, task_dir, plan)
    assert_closeout_archive_path_preflight(root, plan["task"]["archive_locator"])
    validate_closeout_pre_move_continuity(
        root,
        task_dir,
        plan,
        evidence_commit,
        expected_summary_pr=bound_pr,
    )
    proc = run(
        ["python3", "./.trellis/scripts/task.py", "archive", task_dir.name, "--no-commit"],
        cwd=root,
        check=False,
    )
    if proc.returncode != 0:
        raise WorkflowError("task.py archive move failed.", exit_code=2, payload={"stderr": proc.stderr.strip(), "stdout": proc.stdout.strip()})
    archived = root / plan["task"]["archive_locator"]
    validate_closeout_archive_move_layout(root, archived, plan)
    validate_closeout_archive_blob_continuity(
        root,
        archived,
        plan,
        evidence_commit,
        expected_summary_pr=bound_pr,
    )
    active_locator = plan["task"]["active_locator"]
    archive_locator = plan["task"]["archive_locator"]
    dirty = set(git_status_paths(root))
    validate_closeout_archive_git_paths(dirty, plan, stage="archive-move-dirty")
    run_stdout(["git", "add", "-A", "--", active_locator, archive_locator], cwd=root)
    staged = set(run_stdout(["git", "diff", "--cached", "--name-only", "--no-renames"], cwd=root).splitlines())
    validate_closeout_archive_git_paths(staged, plan, stage="archive-staged")
    run_stdout(["git", "commit", "-m", format_metadata_commit_subject(int(plan["task"]["source_issue"]))], cwd=root)
    archive_commit = current_head(root)
    committed = closeout_commit_paths(root, archive_commit)
    validate_closeout_archive_git_paths(committed, plan, stage="archive-commit")
    if committed != staged:
        raise WorkflowError("Archive metadata commit differs from its staged transaction.", exit_code=2, payload={"staged": sorted(staged), "committed": sorted(committed)})
    if closeout_commit_parent(root, archive_commit) != evidence_commit:
        raise WorkflowError("Archive metadata commit parent is not the validated evidence commit.", exit_code=2)
    validate_closeout_archive_blob_continuity(
        root,
        archived,
        plan,
        evidence_commit,
        archive_commit=archive_commit,
        expected_summary_pr=bound_pr,
    )
    if git_status_paths(root):
        raise WorkflowError("Archive metadata commit left repository paths dirty.", exit_code=2)
    run_stdout(["git", "push", plan["git"]["remote"], plan["git"]["head_branch"]], cwd=root)
    return archived, {"commit": archive_commit, "parent": evidence_commit, "paths": sorted(committed)}


def ensure_closeout_pr_ready(
    root: Path, plan: dict[str, Any], *, bound_pr: dict[str, Any] | None = None
) -> dict[str, Any]:
    git = plan["git"]
    pr = resolve_closeout_pull_request(
        root, git["repo"], git["head_branch"], git["base_branch"], git["remote"]
    )
    if pr is None:
        raise WorkflowError("Closeout draft PR is missing.", exit_code=2)
    local_head = current_head(root)
    validate_closeout_remote_pull_request_identity(
        plan,
        pr,
        expected_draft=bool(pr["isDraft"]),
        expected_head=local_head,
        bound_pr=bound_pr,
    )
    remote_proc = run(["git", "ls-remote", "--heads", git["remote"], git["head_branch"]], cwd=root, check=False)
    rows = [line.split() for line in remote_proc.stdout.splitlines() if line.strip()]
    remote_head = rows[0][0] if len(rows) == 1 else ""
    if remote_proc.returncode != 0 or not (local_head == remote_head == pr["headRefOid"]):
        raise WorkflowError(
            "Closeout local/remote/PR HEAD identity mismatch.",
            exit_code=2,
            payload={"local_head": local_head, "remote_head": remote_head, "pr_head": pr["headRefOid"]},
        )
    if pr["isDraft"]:
        proc = run(["gh", "pr", "ready", "--repo", git["repo"], str(pr["number"])], cwd=root, check=False)
        if proc.returncode != 0:
            raise WorkflowError("Draft-to-ready transition failed.", exit_code=2, payload={"stderr": proc.stderr.strip(), "stage": "draft-to-ready"})
        confirmed = resolve_closeout_pull_request(
            root, git["repo"], git["head_branch"], git["base_branch"], git["remote"]
        )
        if confirmed is None or confirmed.get("isDraft") is not False or confirmed.get("headRefOid") != local_head:
            raise WorkflowError("Draft-to-ready transition could not be confirmed.", exit_code=2, payload={"stage": "draft-to-ready-confirmation"})
        validate_closeout_remote_pull_request_identity(
            plan,
            confirmed,
            expected_draft=False,
            expected_head=local_head,
            bound_pr=bound_pr or pr,
        )
        pr = confirmed
    return {"pr": pr, "local_head": local_head, "remote_head": remote_head, "status": "ready"}


def resume_archive_metadata_transaction(
    root: Path,
    task_dir: Path,
    plan: dict[str, Any],
    *,
    bound_pr: dict[str, Any] | None = None,
) -> dict[str, Any]:
    validate_closeout_archive_move_layout(root, task_dir, plan)
    dirty = set(git_status_paths(root))
    if dirty:
        validate_closeout_archive_git_paths(dirty, plan, stage="archive-recovery-dirty")
        evidence_commit = current_head(root)
        validate_closeout_evidence_commit(root, plan, evidence_commit)
        validate_closeout_archive_blob_continuity(
            root,
            task_dir,
            plan,
            evidence_commit,
            expected_summary_pr=bound_pr,
        )
        active = plan["task"]["active_locator"]
        archived = plan["task"]["archive_locator"]
        staged = set(run_stdout(["git", "diff", "--cached", "--name-only", "--no-renames"], cwd=root).splitlines())
        if not staged:
            pathspecs = (
                [f"{active}/{relative}" for relative in plan["projection"]["tracked_move_paths"]]
                + [f"{archived}/{relative}" for relative in plan["projection"]["move_paths"]]
            )
            run_stdout(["git", "add", "-A", "--", *pathspecs], cwd=root)
            staged = set(run_stdout(["git", "diff", "--cached", "--name-only", "--no-renames"], cwd=root).splitlines())
        validate_closeout_archive_git_paths(staged, plan, stage="archive-recovery-staged")
        run_stdout(["git", "commit", "-m", format_metadata_commit_subject(int(plan["task"]["source_issue"]))], cwd=root)
        archive_commit = current_head(root)
        archive_paths = closeout_commit_paths(root, archive_commit)
        validate_closeout_archive_git_paths(archive_paths, plan, stage="archive-recovery-commit")
        if closeout_commit_parent(root, archive_commit) != evidence_commit:
            raise WorkflowError("Recovered archive commit does not match the exact parent/path transaction.", exit_code=2)
        validate_closeout_archive_blob_continuity(
            root,
            task_dir,
            plan,
            evidence_commit,
            archive_commit=archive_commit,
            expected_summary_pr=bound_pr,
        )
    else:
        archive_commit = current_head(root)
        last_paths = closeout_commit_paths(root, archive_commit)
        evidence_commit = closeout_commit_parent(root, archive_commit)
        validate_closeout_archive_git_paths(last_paths, plan, stage="archive-recovery-head")
        validate_closeout_evidence_commit(root, plan, evidence_commit)
        validate_closeout_archive_blob_continuity(
            root,
            task_dir,
            plan,
            evidence_commit,
            archive_commit=archive_commit,
            expected_summary_pr=bound_pr,
        )
    local_head = current_head(root)
    remote_proc = run(
        ["git", "ls-remote", "--heads", plan["git"]["remote"], plan["git"]["head_branch"]],
        cwd=root,
        check=False,
    )
    rows = [line.split() for line in remote_proc.stdout.splitlines() if line.strip()]
    remote_head = rows[0][0] if len(rows) == 1 else ""
    if remote_proc.returncode != 0 or remote_head != local_head:
        run_stdout(["git", "push", plan["git"]["remote"], plan["git"]["head_branch"]], cwd=root)
    return {
        "commit": archive_commit,
        "parent": evidence_commit,
        "paths": sorted(closeout_commit_paths(root, archive_commit)),
    }


def resume_archived_closeout(
    root: Path,
    args: argparse.Namespace,
    task_dir: Path,
    *,
    committed_plan: dict[str, Any] | None = None,
    committed_archive: dict[str, Any] | None = None,
) -> dict[str, Any]:
    plan = committed_plan or validate_closeout_plan(read_json(closeout_plan_path(task_dir)))
    expected = str(getattr(args, "expected_plan_digest", "") or "")
    if expected != plan["plan_digest"]:
        raise WorkflowError("Formal closeout expected digest does not match the archived plan.", exit_code=2, payload={"expected": expected, "actual": plan["plan_digest"]})
    git = plan["git"]
    require_gh_auth(root)
    archive_commit = committed_archive or resolve_committed_closeout_archive_transaction(root, plan)
    bound_pr: dict[str, Any] | None = None
    if archive_commit is not None:
        summary_pr = archive_commit.get("summary_pr")
        if not isinstance(summary_pr, dict):
            commit = str(archive_commit.get("commit") or "")
            summary_bytes = closeout_commit_blob_bytes(
                root,
                commit,
                f"{plan['task']['archive_locator']}/{FINISH_SUMMARY_ARTIFACT}",
            )
            summary_pr = closeout_summary_runtime_pr_facts_from_bytes(plan, summary_bytes)
        bound_pr = summary_pr
    pr = resolve_closeout_pull_request(
        root, git["repo"], git["head_branch"], git["base_branch"], git["remote"]
    )
    if pr is None:
        raise WorkflowError("Archived closeout recovery requires the bound pull request.", exit_code=2)
    validate_closeout_remote_pull_request_identity(
        plan,
        pr,
        expected_draft=bool(pr["isDraft"]),
        bound_pr=bound_pr,
    )
    if archive_commit is None:
        archive_commit = resume_archive_metadata_transaction(
            root,
            task_dir,
            plan,
            bound_pr=pr,
        )
    else:
        push_closeout_branch_if_needed(root, plan)
    result = ensure_closeout_pr_ready(root, plan, bound_pr=bound_pr or pr)
    return {
        "status": "ok",
        "stage": "ready",
        "task_dir": str(task_dir),
        "plan_digest": plan["plan_digest"],
        "archive_commit": archive_commit,
        "publish": result,
    }


def apply_active_closeout_month_supersession(
    root: Path,
    task_dir: Path,
    prepared: dict[str, Any],
) -> str:
    supersession = prepared.get("month_supersession")
    if not isinstance(supersession, dict):
        raise WorkflowError("Closeout month supersession state is missing.", exit_code=2)
    previous = supersession["previous_plan"]
    plan = prepared["plan"]
    committed = supersession.get("committed") is True
    errors = closeout_month_supersession_errors(
        previous,
        plan,
        previous_evidence_head=current_head(root),
        committed=committed,
    )
    if errors:
        raise WorkflowError(
            "Closeout archive month supersession is no longer valid.",
            exit_code=2,
            payload={"errors": errors, "stage": "archive-month-reprepare"},
        )
    assert_closeout_archive_month_current(plan)
    if (root / previous["task"]["archive_locator"]).exists():
        raise WorkflowError(
            "Closeout archive month supersession refuses an already moved task.",
            exit_code=2,
            payload={"stage": "archive-month-reprepare"},
        )
    summary_path = task_dir / FINISH_SUMMARY_ARTIFACT
    if summary_path.exists():
        read_and_validate_closeout_final_summary(summary_path, previous)
        summary_path.unlink()
    write_json(closeout_plan_path(task_dir), plan)
    readiness_path, readiness = build_pr_readiness_snapshot(
        root,
        task_dir,
        repo=plan["git"]["repo"],
        base_branch=plan["git"]["base_branch"],
        head_branch=plan["git"]["head_branch"],
        reviewed_head_sha=plan["git"]["reviewed_work_head"],
        title=plan["publish"]["title"],
        draft=True,
        closeout_plan_digest=plan["plan_digest"],
    )
    write_json(readiness_path, readiness)
    return "evidence_ready" if committed else str(supersession["prior_state"])


def resume_active_archive_move(
    root: Path,
    args: argparse.Namespace,
    config: dict[str, Any],
    task_dir: Path,
    task_context: dict[str, Any],
) -> dict[str, Any]:
    plan = validate_closeout_plan(read_json(closeout_plan_path(task_dir)))
    expected = str(getattr(args, "expected_plan_digest", "") or "")
    if expected != plan["plan_digest"]:
        raise WorkflowError("Archive-move recovery digest does not match committed plan.", exit_code=2)
    task = task_json(task_dir)
    if task.get("status") != "completed":
        raise WorkflowError("Archive-move recovery requires active task status=completed.", exit_code=2)
    gate_path, gate, gate_errors = validate_review_gate(root, task_dir, config, True)
    if gate_errors:
        raise WorkflowError("Archive-move recovery review gate is invalid.", exit_code=2, payload={"artifact_path": str(gate_path), "errors": gate_errors})
    ledger = load_issue_scope_ledger(task_dir, task_context)
    if not closeout_evidence_is_committed(root, task_dir, plan, ledger, gate):
        raise WorkflowError("Archive-move recovery requires committed plan/readiness/evidence.", exit_code=2)
    summary_path = task_dir / FINISH_SUMMARY_ARTIFACT
    if not summary_path.is_file():
        raise WorkflowError("Archive-move recovery requires the validated final summary.", exit_code=2)
    validate_closeout_active_projection(root, task_dir, plan)
    validate_closeout_evidence_commit(root, plan, current_head(root))
    assert_closeout_archive_month_current(plan)
    official_after_archive_hook_state(root)
    require_gh_auth(root)
    pr = resolve_closeout_pull_request(
        root,
        plan["git"]["repo"],
        plan["git"]["head_branch"],
        plan["git"]["base_branch"],
        plan["git"]["remote"],
    )
    if pr is None or pr.get("isDraft") is not True:
        raise WorkflowError("Archive-move recovery requires the bound draft PR.", exit_code=2)
    validate_closeout_pull_request_identity(
        root,
        task_dir,
        plan,
        pr,
        expected_draft=True,
        require_summary=True,
        expected_head=current_head(root),
    )
    archived_task_dir, archive_commit = execute_archive_metadata_transaction(
        root,
        task_dir,
        plan,
        bound_pr=pr,
    )
    publish_payload = ensure_closeout_pr_ready(root, plan, bound_pr=pr)
    return {
        "status": "ok",
        "stage": "ready",
        "entry_state": "archive_moved",
        "task_dir": str(task_dir),
        "archived_task_dir": str(archived_task_dir),
        "closeout_plan_digest": plan["plan_digest"],
        "finish_summary": str(archived_task_dir / FINISH_SUMMARY_ARTIFACT),
        "archive_commit": archive_commit,
        "publish": publish_payload,
    }


def cmd_finish_work(args: argparse.Namespace) -> dict[str, Any]:
    validate_finish_work_invocation(args)
    root = repo_root(Path(args.root or os.getcwd()))
    config = load_config(root)
    task_dir = resolve_finish_work_task_dir(root, args.task)
    if task_dir_is_archived(root, task_dir):
        if args.dry_run:
            raise WorkflowError("Archived closeout recovery does not have a new dry-run phase.", exit_code=2)
        committed_boundary = assert_archived_committed_workspace_boundary(
            root,
            config,
            task_dir,
            str(getattr(args, "expected_plan_digest", "") or ""),
        )
        return resume_archived_closeout(
            root,
            args,
            task_dir,
            committed_plan=committed_boundary["plan"],
            committed_archive=committed_boundary.get("archive_commit"),
        )
    task_context = load_task_start_context(task_dir, config)
    assert_workspace_boundary(root, config, task_context, task_dir)
    if closeout_plan_path(task_dir).is_file() and task_json(task_dir).get("status") == "completed":
        if args.dry_run:
            raise WorkflowError("Interrupted archive move must resume through formal finish-work.", exit_code=2)
        return resume_active_archive_move(root, args, config, task_dir, task_context)

    prepared = prepare_closeout(root, args, config, task_dir, task_context)
    plan = prepared["plan"]
    if args.dry_run:
        return {
            "status": "dry-run",
            "dry_run_side_effects": False,
            "task_dir": str(task_dir),
            "closeout_plan": plan,
            "closeout_plan_digest": plan["plan_digest"],
            "expected_actions": list(CLOSEOUT_TRANSITIONS[1:]),
        }

    expected_digest = str(getattr(args, "expected_plan_digest", "") or "")
    if expected_digest != plan["plan_digest"]:
        raise WorkflowError(
            "Formal closeout expected digest does not match the rebuilt plan.",
            exit_code=2,
            payload={"expected": expected_digest, "actual": plan["plan_digest"], "failed_stage": "plan-digest-handshake"},
        )
    assert_closeout_archive_month_current(plan)
    require_gh_auth(root)
    ledger = load_issue_scope_ledger(task_dir, task_context)
    evidence_commit: dict[str, Any] | None = None
    if prepared.get("month_supersession") is not None:
        supersession = prepared["month_supersession"]
        if supersession.get("committed") is True:
            push_closeout_branch_if_needed(root, supersession["previous_plan"])
        validate_publish_identity_and_remote_head(
            root, prepared["task"], task_context, plan["git"]["repo"],
            plan["git"]["base_branch"], plan["git"]["head_branch"], plan["git"]["remote"],
        )
        entry_state = apply_active_closeout_month_supersession(root, task_dir, prepared)
    else:
        entry_state = resolve_closeout_pre_draft_state(
            root, task_dir, plan, ledger, prepared["gate"]
        )
    if entry_state == "prepared":
        if current_head(root) != plan["git"]["reviewed_work_head"]:
            raise WorkflowError(
                "Closeout content HEAD drifted before evidence commit.",
                exit_code=2,
                payload={"expected": plan["git"]["reviewed_work_head"], "actual": current_head(root)},
            )
        run_stdout(
            ["git", "push", "-u", plan["git"]["remote"], plan["git"]["head_branch"]],
            cwd=root,
        )
        validate_publish_identity_and_remote_head(
            root, prepared["task"], task_context, plan["git"]["repo"],
            plan["git"]["base_branch"], plan["git"]["head_branch"], plan["git"]["remote"],
        )
        write_json(closeout_plan_path(task_dir), plan)
        readiness_path, readiness = build_pr_readiness_snapshot(
            root,
            task_dir,
            repo=plan["git"]["repo"],
            base_branch=plan["git"]["base_branch"],
            head_branch=plan["git"]["head_branch"],
            reviewed_head_sha=plan["git"]["reviewed_work_head"],
            title=plan["publish"]["title"],
            draft=True,
            closeout_plan_digest=plan["plan_digest"],
        )
        write_json(readiness_path, readiness)
        if plan["marketplace"]["required"]:
            pending_ledger = record_marketplace_machine_evidence(ledger, plan["marketplace"]["pending_machine"])
            write_json(issue_scope_ledger_path(task_dir), pending_ledger)
            ledger = pending_ledger

    if entry_state in {"content_pushed", "evidence_ready"}:
        validate_publish_identity_and_remote_head(
            root, prepared["task"], task_context, plan["git"]["repo"],
            plan["git"]["base_branch"], plan["git"]["head_branch"], plan["git"]["remote"],
        )

    if entry_state in {"prepared", "content_pushed"}:
        if plan["marketplace"]["required"]:
            verification = execute_marketplace_verification(
                root,
                task_dir,
                plan["git"]["repo"],
                plan["git"]["remote"],
                plan["git"]["head_branch"],
                plan["git"]["reviewed_work_head"],
                config,
            )
            verification_path = marketplace_verification_path(task_dir, config)
            passed = closeout_passed_marketplace_evidence(root, verification_path, verification)
            write_json(issue_scope_ledger_path(task_dir), record_marketplace_machine_evidence(ledger, passed))

    if entry_state in {"prepared", "content_pushed", "evidence_ready"}:
        evidence_commit = commit_closeout_evidence_metadata(root, task_dir, plan)
        push_closeout_branch_if_needed(root, plan)
        validate_publish_identity_and_remote_head(
            root, prepared["task"], task_context, plan["git"]["repo"],
            plan["git"]["base_branch"], plan["git"]["head_branch"], plan["git"]["remote"],
        )
    elif entry_state == "evidence_pushed":
        push_closeout_branch_if_needed(root, plan)
        validate_publish_identity_and_remote_head(
            root, prepared["task"], task_context, plan["git"]["repo"],
            plan["git"]["base_branch"], plan["git"]["head_branch"], plan["git"]["remote"],
        )

    pr = ensure_closeout_draft_pr(root, plan, prepared["body"])
    finish_summary_path = task_dir / FINISH_SUMMARY_ARTIFACT
    if finish_summary_path.is_file():
        validate_closeout_active_projection(root, task_dir, plan)
        validate_closeout_pull_request_identity(
            root,
            task_dir,
            plan,
            pr,
            expected_draft=True,
            require_summary=True,
            expected_head=current_head(root),
        )
    else:
        finish_summary_path, _summary = build_final_archive_projection(root, task_dir, prepared, pr)
    archived_task_dir, archive_commit = execute_archive_metadata_transaction(
        root,
        task_dir,
        plan,
        bound_pr=pr,
    )
    publish_payload = ensure_closeout_pr_ready(root, plan, bound_pr=pr)
    return {
        "status": "ok",
        "stage": "ready",
        "task_dir": str(task_dir),
        "archived_task_dir": str(archived_task_dir),
        "closeout_plan_digest": plan["plan_digest"],
        "entry_state": entry_state,
        "finish_summary": str(archived_task_dir / finish_summary_path.name),
        "evidence_commit": evidence_commit,
        "archive_commit": archive_commit,
        "publish": publish_payload,
    }


def context_canonical_bytes(value: Any) -> bytes:
    return (json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":")) + "\n").encode("utf-8")


def context_digest(value: Any) -> str:
    return hashlib.sha256(context_canonical_bytes(value)).hexdigest()


def context_sort(values: set[str] | list[str]) -> list[str]:
    return sorted(set(values), key=lambda item: item.encode("utf-8"))


def context_normalize_text(value: Any, label: str) -> str:
    if not isinstance(value, str):
        raise WorkflowError(f"{label} must be a string.", exit_code=2)
    if not value or any(ord(character) < 32 or ord(character) == 127 for character in value):
        raise WorkflowError(f"{label} contains an empty or control-character value.", exit_code=2)
    normalized = " ".join(unicodedata.normalize("NFKC", value).casefold().strip().split())
    if not normalized:
        raise WorkflowError(f"{label} normalizes to an empty value.", exit_code=2)
    return normalized


def context_normalize_retrieval_text(value: Any) -> str:
    if not isinstance(value, str) or not value or "\x00" in value:
        raise WorkflowError("index retrieval_text is invalid.", exit_code=2)
    if any(ord(character) < 32 and character not in "\t\n\r" for character in value):
        raise WorkflowError("index retrieval_text contains invalid control characters.", exit_code=2)
    normalized = " ".join(unicodedata.normalize("NFKC", value).casefold().split())
    if not normalized:
        raise WorkflowError("index retrieval_text normalizes to an empty value.", exit_code=2)
    return normalized


def context_canonical_ref(value: Any, *, pull_request: bool) -> str:
    normalized = context_normalize_text(value, "query reference")
    marker = "pull" if pull_request else "issues"
    url_match = re.fullmatch(rf"https://github\.com/[^/]+/[^/]+/{marker}/([1-9][0-9]*)", normalized)
    direct_pattern = r"(?:pr\s*)?#([1-9][0-9]*)" if pull_request else r"#?([1-9][0-9]*)"
    direct_match = re.fullmatch(direct_pattern, normalized)
    match = url_match or direct_match
    if match is None:
        kind = "PR" if pull_request else "issue"
        raise WorkflowError(f"query {kind} reference is invalid.", exit_code=2)
    return f"PR #{int(match.group(1))}" if pull_request else f"#{int(match.group(1))}"


def context_query_path_shape(value: Any) -> str:
    if not isinstance(value, str) or not value or "\\" in value:
        raise WorkflowError("query path is invalid.", exit_code=2)
    if any(ord(character) < 32 or ord(character) == 127 for character in value):
        raise WorkflowError("query path contains control characters.", exit_code=2)
    raw = Path(value)
    if raw.is_absolute() or any(part in {"", ".", ".."} for part in raw.parts):
        raise WorkflowError("query path must be a clean repository-relative path.", exit_code=2)
    normalized = raw.as_posix()
    if normalized == ".trellis/workspace" or normalized == ".trellis/.runtime" or any(
        normalized.startswith(prefix) for prefix in CONTEXT_PROTECTED_PREFIXES
    ):
        raise WorkflowError("query path targets protected workspace/runtime state.", exit_code=2)
    return normalized


def context_query_path(root: Path, value: Any) -> str:
    del root
    return context_query_path_shape(value)


def context_tokens(values: list[str]) -> list[str]:
    tokens: set[str] = set()
    for value in values:
        camel_split = re.sub(r"(?<=[a-z0-9])(?=[A-Z])", " ", unicodedata.normalize("NFKC", value))
        normalized = camel_split.casefold()
        for token in re.findall(r"[^\W_]+", normalized, flags=re.UNICODE):
            if len(token) >= 2 or token.isdigit():
                tokens.add(token)
    return context_sort(tokens)


def canonicalize_context_query(
    root: Path,
    raw: Any,
    *,
    validate_repo_paths: bool = True,
) -> dict[str, Any]:
    if not isinstance(raw, dict):
        raise WorkflowError("change-context query must be an object.", exit_code=2)
    unknown = set(raw) - set(CONTEXT_QUERY_KINDS) - {"tokens", "query_sha256"}
    if unknown:
        raise WorkflowError("change-context query contains unknown fields.", exit_code=2)
    query: dict[str, list[str]] = {}
    token_inputs: list[str] = []
    for kind in CONTEXT_QUERY_KINDS:
        values = raw.get(kind, [])
        if not isinstance(values, list):
            raise WorkflowError(f"change-context query {kind} must be an array.", exit_code=2)
        canonical: list[str] = []
        for value in values:
            if kind == "issue_refs":
                normalized = context_canonical_ref(value, pull_request=False)
            elif kind == "pr_refs":
                normalized = context_canonical_ref(value, pull_request=True)
            elif kind == "paths":
                normalized = (
                    context_query_path(root, value)
                    if validate_repo_paths
                    else context_query_path_shape(value)
                )
            else:
                normalized = context_normalize_text(value, f"query {kind}")
            canonical.append(normalized)
            if kind not in {"issue_refs", "pr_refs"}:
                token_inputs.append(str(value))
        query[kind] = context_sort(canonical)
    if not any(query[kind] for kind in CONTEXT_QUERY_KINDS):
        raise WorkflowError("change-context query has no clues.", exit_code=2)
    result: dict[str, Any] = {**query, "tokens": context_tokens(token_inputs)}
    result["query_sha256"] = context_digest(result)
    return result


def context_index_projection(index: dict[str, Any]) -> dict[str, Any]:
    return {
        "problem": index["problem"],
        "outcome": index["outcome"],
        "changed_behavior": copy.deepcopy(index["changed_behavior"]),
        "affected_surfaces": copy.deepcopy(index["affected_surfaces"]),
        "contract_changes": copy.deepcopy(index["contract_changes"]),
        "search_terms": copy.deepcopy(index["search_terms"]),
    }


def context_archive_file_error(root: Path, path: Path) -> str | None:
    try:
        relative = path.relative_to(root)
    except ValueError:
        return "unsafe_path"
    if relative.as_posix().startswith("../"):
        return "unsafe_path"
    archive_parts = Path(".trellis/tasks/archive").parts
    if (
        relative.name != "finish-summary.json"
        or relative.parts[: len(archive_parts)] != archive_parts
        or len(relative.parts) <= len(archive_parts) + 2
    ):
        return "unsafe_path"
    return None if path.is_file() else "not_regular_file"


def context_finish_summary_paths(root: Path) -> list[Path]:
    archive = root / ".trellis/tasks/archive"
    if not archive.exists():
        return []
    if not archive.is_dir():
        raise WorkflowError("Archived task root must be a directory.", exit_code=2)
    return sorted(
        archive.glob("**/finish-summary.json"),
        key=lambda path: path.relative_to(root).as_posix().encode("utf-8"),
    )


def context_candidate_score(query: dict[str, Any], index: dict[str, Any]) -> tuple[dict[str, Any], dict[str, list[str]]]:
    search_terms = index["search_terms"]
    retrieval = context_normalize_retrieval_text(index["retrieval_text"])
    retrieval_tokens = set(context_tokens([index["retrieval_text"]]))
    matched: dict[str, list[str]] = {}
    exact_points = 0
    exact_count = 0
    normalized_scalars: set[str] = set(retrieval_tokens)
    for values in search_terms.values():
        if isinstance(values, list):
            for value in values:
                if isinstance(value, str):
                    normalized_scalars.add(context_normalize_text(value, "index search term"))
    for kind in CONTEXT_QUERY_KINDS:
        query_values = query[kind]
        matches: list[str] = []
        if kind == "paths":
            candidate_values = set(search_terms.get("paths", []))
            matches = [value for value in query_values if value in candidate_values]
        elif kind == "terms":
            matches = [value for value in query_values if value in normalized_scalars]
        elif kind == "queries":
            matches = [value for value in query_values if value in retrieval]
        else:
            candidate_values = {
                context_normalize_text(value, f"index {kind}")
                if kind not in {"issue_refs", "pr_refs"} else value
                for value in search_terms.get(kind, [])
                if isinstance(value, str)
            }
            matches = [value for value in query_values if value in candidate_values]
        matches = context_sort(matches)
        if matches:
            matched[kind] = matches
            exact_count += len(matches)
            exact_points += CONTEXT_EXACT_WEIGHTS[kind] * len(matches)
    token_matches = context_sort(set(query["tokens"]) & retrieval_tokens)
    if token_matches:
        matched["tokens"] = token_matches
    token_points = min(99, len(token_matches))
    return {
        "total": exact_points + token_points,
        "exact": exact_points,
        "token": token_points,
        "exact_match_count": exact_count,
        "token_match_count": len(token_matches),
    }, matched


def build_context_history_preview(root: Path, raw_query: Any, *, limit: int = CONTEXT_HISTORY_LIMIT) -> dict[str, Any]:
    if limit != CONTEXT_HISTORY_LIMIT:
        raise WorkflowError(f"history preview limit must equal {CONTEXT_HISTORY_LIMIT}.", exit_code=2)
    query = canonicalize_context_query(root, raw_query)
    manifest: list[dict[str, Any]] = []
    candidates: list[dict[str, Any]] = []
    for path in context_finish_summary_paths(root):
        relative = path.relative_to(root).as_posix()
        error_code = context_archive_file_error(root, path)
        index: Any = None
        if error_code is None:
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
            except (OSError, UnicodeError, json.JSONDecodeError):
                error_code = "invalid_json"
            else:
                if not isinstance(payload, dict) or "index" not in payload:
                    error_code = "missing_index"
                else:
                    index = payload.get("index")
                    if finish_summary_index_errors(index, final=True):
                        error_code = "invalid_index_shape"
        if error_code is not None:
            manifest.append({"path": relative, "status": "invalid", "error_code": error_code})
            continue
        index_sha256 = context_digest(index)
        manifest.append({"path": relative, "status": "valid", "index_sha256": index_sha256})
        score, matched = context_candidate_score(query, index)
        if score["total"] <= 0:
            continue
        candidate_identity = {"finish_summary_path": relative, "index_sha256": index_sha256}
        candidates.append({
            "candidate_id": context_digest(candidate_identity),
            **candidate_identity,
            "score": score,
            "matched_clues": matched,
            "index_projection": context_index_projection(index),
        })
    manifest.sort(key=lambda row: row["path"].encode("utf-8"))
    candidates.sort(key=lambda row: (
        -row["score"]["total"],
        -row["score"]["exact_match_count"],
        -row["score"]["token_match_count"],
        row["finish_summary_path"].encode("utf-8"),
    ))
    candidates = candidates[:limit]
    invalid = [copy.deepcopy(row) for row in manifest if row["status"] == "invalid"]
    result: dict[str, Any] = {
        "algorithm_id": CONTEXT_HISTORY_ALGORITHM_ID,
        "canonical_query": query,
        "query_sha256": query["query_sha256"],
        "archive_manifest_sha256": context_digest(manifest),
        "limit": limit,
        "manifest": manifest,
        "candidates": candidates,
        "invalid": invalid,
    }
    digest_input = {
        key: result[key]
        for key in ("algorithm_id", "query_sha256", "archive_manifest_sha256", "limit", "candidates", "invalid")
    }
    result["preview_sha256"] = context_digest(digest_input)
    return result


def context_active_task_dir(root: Path, value: str) -> Path:
    raw = Path(value)
    task_root_lexical = tasks_root(root)
    if raw.is_absolute():
        candidates = [raw]
    elif len(raw.parts) == 1:
        candidates = [task_root_lexical / raw]
    else:
        candidates = [root / raw]
    task_dir: Path | None = None
    for candidate in candidates:
        candidate = Path(os.path.abspath(candidate))
        if candidate.is_dir() and (candidate / "task.json").is_file():
            task_dir = candidate
            break
    if task_dir is None:
        raise WorkflowError(
            "Context discovery recorder requires a direct active task directory.",
            exit_code=2,
            payload={"error_codes": ["task_not_active"]},
        )
    task_root = Path(os.path.abspath(task_root_lexical))
    try:
        relative = task_dir.relative_to(task_root)
    except ValueError as exc:
        raise WorkflowError(
            "Context discovery recorder requires a direct active task directory.",
            exit_code=2,
            payload={"error_codes": ["task_not_active"]},
        ) from exc
    if len(relative.parts) != 1 or relative.parts[0] == "archive" or task_dir_is_archived(root, task_dir):
        raise WorkflowError(
            "Context discovery recorder requires a direct active task directory.",
            exit_code=2,
            payload={"error_codes": ["task_not_active"]},
        )
    task_path = task_dir / "task.json"
    try:
        task_payload = json.loads(task_path.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError) as exc:
        raise WorkflowError(
            "Context discovery recorder requires a readable active task marker.",
            exit_code=2,
            payload={"error_codes": ["task_not_active"]},
        ) from exc
    if not isinstance(task_payload, dict) or task_payload.get("status") not in {
        "planning", "in_progress",
    }:
        raise WorkflowError(
            "Context discovery recorder requires task status planning or in_progress.",
            exit_code=2,
            payload={"error_codes": ["task_not_active"]},
        )
    return task_dir


def context_payload_from_args(
    root: Path,
    args: argparse.Namespace,
    *,
    require_active_task: bool = False,
) -> tuple[dict[str, Any], Path | None]:
    task_dir: Path | None = None
    if getattr(args, "task", None):
        task_dir = (
            context_active_task_dir(root, args.task)
            if require_active_task
            else resolve_task_dir(root, args.task)
        )
    input_value = getattr(args, "input", None)
    if input_value:
        if input_value == "-":
            raw = sys.stdin.read()
        else:
            input_path = Path(input_value)
            if not input_path.is_absolute():
                input_path = root / input_path
            try:
                raw = input_path.read_text(encoding="utf-8")
            except (OSError, UnicodeError) as exc:
                raise WorkflowError("context discovery input is unreadable.", exit_code=2) from exc
    elif task_dir is not None and (task_dir / "context-discovery.json").exists():
        artifact = task_dir / "context-discovery.json"
        try:
            raw = artifact.read_text(encoding="utf-8")
        except (OSError, UnicodeError) as exc:
            raise WorkflowError("context discovery task artifact is unreadable.", exit_code=2) from exc
    else:
        raise WorkflowError("context discovery requires --input or a task-local artifact.", exit_code=2)
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise WorkflowError("context discovery input is invalid JSON.", exit_code=2) from exc
    if not isinstance(payload, dict):
        raise WorkflowError("context discovery input root must be an object.", exit_code=2)
    return payload, task_dir


def context_snapshot_identity(payload: dict[str, Any]) -> dict[str, str]:
    unsigned = copy.deepcopy(payload)
    unsigned.pop("snapshot_identity", None)
    payload_sha256 = context_digest(unsigned)
    query = payload.get("canonical_query") if isinstance(payload.get("canonical_query"), dict) else {}
    preview = payload.get("history_preview") if isinstance(payload.get("history_preview"), dict) else {}
    live_change = payload.get("live_change") if isinstance(payload.get("live_change"), dict) else {}
    base = payload.get("base_evidence") if isinstance(payload.get("base_evidence"), dict) else {}
    sync_result = base.get("sync_result") if isinstance(base.get("sync_result"), dict) else {}
    identity = {
        "query_sha256": str(query.get("query_sha256") or ""),
        "archive_manifest_sha256": str(preview.get("archive_manifest_sha256") or ""),
        "live_change_sha256": str(live_change.get("facts_sha256") or ""),
        "base_head": str(base.get("base_head") or ""),
        "base_sync_facts_sha256": str(sync_result.get("facts_sha256") or ""),
        "post_sync_resolution_sha256": str(base.get("post_sync_resolution_sha256") or ""),
        "payload_sha256": payload_sha256,
    }
    identity["snapshot_sha256"] = context_digest(identity)
    return identity


def context_discovery_schema(root: Path) -> dict[str, Any]:
    candidates = [
        root / ".trellis/guru-team/skills/packages/guru-discover-change-context/schemas/context-discovery.schema.json",
        root / "trellis/skills/guru-team/packages/guru-discover-change-context/schemas/context-discovery.schema.json",
    ]
    runtime_path = Path(__file__).resolve()
    if len(runtime_path.parents) > 4:
        candidates.append(
            runtime_path.parents[4]
            / "skills/guru-team/packages/guru-discover-change-context/schemas/context-discovery.schema.json"
        )
    schema_path = next(
        (path for path in candidates if path.is_file() and not path.is_symlink()),
        None,
    )
    if schema_path is None:
        raise WorkflowError(
            "Context discovery schema is missing from the compatible Guru Team runtime.",
            exit_code=2,
            payload={"error_codes": ["context_schema_unavailable"]},
        )
    errors: list[str] = []
    schema = skill_read_json(schema_path, "context discovery schema", errors)
    if (
        errors
        or schema is None
        or schema.get("$schema") != SKILL_SCHEMA_DIALECT
        or schema.get("$id") != CONTEXT_DISCOVERY_SCHEMA_ID
    ):
        raise WorkflowError(
            "Context discovery schema identity is invalid.",
            exit_code=2,
            payload={"error_codes": ["context_schema_unavailable"]},
        )
    return schema


def context_portable_path_errors(root: Path, value: Any, label: str) -> list[str]:
    try:
        context_query_path(root, value)
    except WorkflowError:
        return [f"{label}_unsafe"]
    return []


def context_portable_path_shape_errors(value: Any, label: str) -> list[str]:
    try:
        context_query_path_shape(value)
    except WorkflowError:
        return [f"{label}_unsafe"]
    return []


CONTEXT_GITHUB_LOCATOR_RE = re.compile(
    r"^https://github\.com/[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+/(?:issues|pull)/[1-9][0-9]*$"
)
CONTEXT_GIT_OBJECT_LOCATOR_RE = re.compile(r"^git:object:([0-9a-f]{40})$")
CONTEXT_GIT_REF_LOCATOR_RE = re.compile(r"^git:ref:(refs/[A-Za-z0-9._/-]+)@([0-9a-f]{40})$")
def context_github_locator_valid(value: str) -> bool:
    if CONTEXT_GITHUB_LOCATOR_RE.fullmatch(value) is None:
        return False
    try:
        parsed = urlsplit(value)
    except ValueError:
        return False
    return (
        parsed.scheme == "https"
        and parsed.netloc == "github.com"
        and parsed.username is None
        and parsed.password is None
        and parsed.port is None
        and not parsed.query
        and not parsed.fragment
    )


def context_git_locator_errors(root: Path, value: str) -> list[str]:
    object_match = CONTEXT_GIT_OBJECT_LOCATOR_RE.fullmatch(value)
    if object_match is not None:
        oid = object_match.group(1)
        try:
            probe = run(["git", "cat-file", "-e", f"{oid}^{{object}}"], cwd=root, check=False)
        except OSError:
            return ["deep_read_git_object_unreadable"]
        return [] if probe.returncode == 0 else ["deep_read_git_object_unreadable"]
    ref_match = CONTEXT_GIT_REF_LOCATOR_RE.fullmatch(value)
    if ref_match is None:
        return ["deep_read_git_locator_invalid"]
    ref, expected_oid = ref_match.groups()
    try:
        ref_check = run(["git", "check-ref-format", ref], cwd=root, check=False)
    except OSError:
        return ["deep_read_git_ref_unreadable"]
    if ref_check.returncode != 0:
        return ["deep_read_git_locator_invalid"]
    try:
        resolved = run(
            ["git", "rev-parse", "--verify", "--quiet", ref],
            cwd=root,
            check=False,
        )
    except OSError:
        return ["deep_read_git_ref_unreadable"]
    if resolved.returncode != 0 or resolved.stdout.strip() != expected_oid:
        return ["deep_read_git_ref_stale"]
    return []


def context_git_ref_shape_valid(value: str) -> bool:
    if (
        not value.startswith("refs/")
        or value.endswith(("/", "."))
        or ".." in value
        or "@{" in value
        or "//" in value
        or any(character in value for character in " ~^:?*[\\")
        or any(ord(character) < 32 or ord(character) == 127 for character in value)
    ):
        return False
    return all(
        component
        and not component.startswith(".")
        and not component.endswith(".lock")
        for component in value.split("/")
    )


def context_git_locator_shape_errors(value: str) -> list[str]:
    if CONTEXT_GIT_OBJECT_LOCATOR_RE.fullmatch(value) is not None:
        return []
    ref_match = CONTEXT_GIT_REF_LOCATOR_RE.fullmatch(value)
    if ref_match is None or not context_git_ref_shape_valid(ref_match.group(1)):
        return ["deep_read_git_locator_invalid"]
    return []


def context_duplicate_values(values: Any) -> bool:
    if not isinstance(values, list):
        return False
    normalized: list[str] = []
    for value in values:
        if not isinstance(value, str):
            return False
        try:
            normalized.append(context_normalize_text(value, "context value"))
        except WorkflowError:
            return False
    return len(normalized) != len(set(normalized))


def context_base_evidence_contract_errors(root: Path, payload: dict[str, Any]) -> list[str]:
    base = payload.get("base_evidence")
    repository = payload.get("repository")
    if not isinstance(base, dict) or not isinstance(repository, dict):
        return ["invalid_base_evidence"]
    result = base.get("sync_result")
    if not isinstance(result, dict):
        return ["invalid_base_sync_result"]
    errors: list[str] = []
    unsigned_result = dict(result)
    facts_sha256 = unsigned_result.pop("facts_sha256", None)
    if facts_sha256 != canonical_json_sha256(unsigned_result):
        errors.append("invalid_base_sync_result")
    try:
        schema_errors = skill_json_schema_validation_errors(
            result,
            base_sync_schema(root),
            "context discovery base sync result",
        )
    except WorkflowError:
        schema_errors = ["base sync schema unavailable"]
    if schema_errors:
        errors.append("invalid_base_sync_result")
    resolution = result.get("resolution")
    decision = result.get("decision_checkout")
    git = result.get("git")
    if not all(isinstance(value, dict) for value in (resolution, decision, git)):
        return context_sort(errors + ["invalid_base_sync_result"])
    expected_projection = {
        "schema_id": BASE_SYNC_SCHEMA_ID.rsplit("/", 1)[-1].removesuffix(".json"),
        "remote": resolution.get("remote"),
        "base_head": decision.get("head_after"),
        "decision_head": decision.get("head_after"),
        "local_head": git.get("local_head_after"),
        "remote_head": git.get("remote_head_after"),
        "post_sync_resolution_sha256": result.get("post_sync_resolution_sha256"),
        "clean": decision.get("clean_after"),
    }
    if any(base.get(key) != value for key, value in expected_projection.items()):
        errors.append("base_sync_projection_mismatch")
    if (
        repository.get("selected_base") != resolution.get("selected_base")
        or repository.get("decision_branch") != decision.get("branch")
    ):
        errors.append("base_repository_projection_mismatch")
    repo = repository.get("repo")
    if normalize_github_repository(repo) != repo:
        errors.append("invalid_repository_identity")
    return context_sort(errors)


def context_change_binding_errors(payload: dict[str, Any]) -> list[str]:
    live = payload.get("live_change")
    change_input = payload.get("change_input")
    repository = payload.get("repository")
    if not all(isinstance(value, dict) for value in (live, change_input, repository)):
        return ["invalid_live_change"]
    binding = live.get("issue_binding")
    if live.get("kind") == "issue":
        return [] if binding is None else ["live_issue_forbids_issue_binding"]
    if live.get("kind") != "draft":
        return ["invalid_live_change_kind"]
    unsigned = {
        key: live.get(key)
        for key in ("kind", "identity", "state", "updated_at", "body_sha256")
    }
    errors: list[str] = []
    body_sha256 = str(live.get("body_sha256") or "")
    if live.get("identity") != f"draft:{body_sha256}" or live.get("facts_sha256") != context_digest(unsigned):
        errors.append("live_draft_digest_stale")
    issue_refs = change_input.get("issue_refs")
    if not isinstance(issue_refs, list):
        return context_sort(errors + ["invalid_change_issue_refs"])
    if not issue_refs:
        if binding is not None:
            errors.append("draft_issue_binding_without_issue_ref")
        return context_sort(errors)
    if not isinstance(binding, dict):
        return context_sort(errors + ["draft_issue_binding_required"])
    number = binding.get("number")
    if not isinstance(number, int) or f"#{number}" not in issue_refs:
        errors.append("draft_issue_binding_ref_mismatch")
    if binding.get("repo") != repository.get("repo"):
        errors.append("draft_issue_binding_repo_mismatch")
    if binding.get("body_sha256") != body_sha256:
        errors.append("draft_issue_body_mismatch")
    binding_unsigned = {
        key: binding.get(key)
        for key in ("repo", "number", "url", "state", "updated_at", "body_sha256")
    }
    if binding.get("facts_sha256") != context_digest(binding_unsigned):
        errors.append("draft_issue_binding_digest_mismatch")
    return context_sort(errors)


def context_duplicate_candidate_fact_projection(candidate: Any) -> dict[str, Any] | None:
    if not isinstance(candidate, dict):
        return None
    repo = candidate.get("repo")
    number = candidate.get("number")
    identity = candidate.get("identity")
    url = candidate.get("url")
    state = candidate.get("state")
    updated_at = candidate.get("updated_at")
    if (
        normalize_github_repository(repo) != repo
        or not isinstance(number, int)
        or isinstance(number, bool)
        or number < 1
        or not all(isinstance(value, str) and value for value in (identity, url, state, updated_at))
    ):
        return None
    return {
        "repo": repo,
        "number": number,
        "identity": identity,
        "url": url,
        "state": state,
        "updated_at": updated_at,
    }


def context_duplicate_candidate_structural_errors(candidate: Any) -> list[str]:
    expected_keys = {
        "repo", "number", "identity", "url", "state", "updated_at",
        "facts_sha256", "reason", "observation",
    }
    if not isinstance(candidate, dict) or set(candidate) != expected_keys:
        return ["invalid_duplicate_candidate"]
    projection = context_duplicate_candidate_fact_projection(candidate)
    if projection is None:
        return ["invalid_duplicate_candidate"]
    errors: list[str] = []
    repo = projection["repo"]
    number = projection["number"]
    if projection["identity"] != f"#{number}":
        errors.append("duplicate_candidate_identity_mismatch")
    if projection["url"] != f"https://github.com/{repo}/issues/{number}":
        errors.append("duplicate_candidate_url_mismatch")
    if projection["state"] != "open":
        errors.append("duplicate_candidate_not_open")
    if candidate.get("facts_sha256") != context_digest(projection):
        errors.append("duplicate_candidate_facts_digest_mismatch")
    return context_sort(errors)


def context_change_input_errors(payload: dict[str, Any]) -> list[str]:
    change_input = payload.get("change_input")
    if not isinstance(change_input, dict):
        return ["invalid_change_input"]
    clue_lists = [change_input.get(kind) for kind in CONTEXT_QUERY_KINDS]
    if any(not isinstance(values, list) for values in clue_lists):
        return ["invalid_change_input"]
    if not any(values for values in clue_lists):
        return ["change_input_has_no_clues"]
    errors: list[str] = []
    for value in change_input.get("paths", []):
        errors.extend(context_portable_path_shape_errors(value, "change_input_path"))
    return context_sort(errors)


def context_deep_read_shape_errors(
    candidate_by_id: dict[str, dict[str, Any]],
    row: Any,
) -> list[str]:
    if not isinstance(row, dict) or set(row) != {
        "candidate_id", "source", "locator", "purpose", "conclusion",
    }:
        return ["invalid_deep_read"]
    candidate_id = row.get("candidate_id")
    source = row.get("source")
    locator = row.get("locator")
    if candidate_id not in candidate_by_id or source not in {"task_artifact", "github", "git"}:
        return ["invalid_deep_read"]
    if not all(isinstance(row.get(key), str) and row[key].strip() for key in ("locator", "purpose", "conclusion")):
        return ["invalid_deep_read"]
    if source == "github":
        return [] if context_github_locator_valid(locator) else ["deep_read_github_locator_invalid"]
    if source == "git":
        return context_git_locator_shape_errors(locator)
    portable_errors = context_portable_path_shape_errors(locator, "deep_read_locator")
    if portable_errors:
        return portable_errors
    summary = candidate_by_id[candidate_id].get("finish_summary_path")
    if not isinstance(summary, str):
        return ["deep_read_candidate_invalid"]
    summary_path = Path(summary)
    archive_parts = Path(".trellis/tasks/archive").parts
    if (
        summary_path.name != "finish-summary.json"
        or summary_path.parts[:len(archive_parts)] != archive_parts
        or len(summary_path.parts) <= len(archive_parts) + 2
    ):
        return ["deep_read_candidate_invalid"]
    task_dir = summary_path.parent
    locator_path = Path(str(locator))
    try:
        locator_path.relative_to(task_dir)
    except ValueError:
        return ["deep_read_locator_outside_selected_task"]
    return []


def context_deep_read_locator_errors(
    root: Path,
    candidate_by_id: dict[str, dict[str, Any]],
    row: Any,
) -> list[str]:
    shape_errors = context_deep_read_shape_errors(candidate_by_id, row)
    if shape_errors:
        return shape_errors
    source = row["source"]
    locator = row["locator"]
    if source == "github":
        return []
    if source == "git":
        return context_git_locator_errors(root, locator)
    target = root / locator
    return [] if target.is_file() else ["deep_read_locator_not_regular_file"]


def context_structural_errors(root: Path, payload: dict[str, Any]) -> list[str]:
    errors: list[str] = []
    schema_errors = skill_json_schema_validation_errors(
        payload,
        context_discovery_schema(root),
        "context discovery result",
    )
    if schema_errors:
        errors.append("context_schema_validation_failed")
    if set(payload) != CONTEXT_TOP_LEVEL_KEYS:
        errors.append("invalid_top_level_fields")
    if payload.get("schema_version") != CONTEXT_DISCOVERY_SCHEMA_VERSION or payload.get("skill_id") != CONTEXT_DISCOVERY_SKILL_ID:
        errors.append("invalid_schema_identity")
    if payload.get("mode") not in {"workflow", "standalone"}:
        errors.append("invalid_mode")
    typed_exit = payload.get("typed_exit")
    if typed_exit not in {"context_ready", "refresh_base", "blocked"}:
        errors.append("invalid_typed_exit")
    errors.extend(context_base_evidence_contract_errors(root, payload))
    errors.extend(context_change_input_errors(payload))
    errors.extend(context_change_binding_errors(payload))
    query = payload.get("canonical_query")
    try:
        expected_query = canonicalize_context_query(
            root,
            query,
            validate_repo_paths=False,
        )
    except WorkflowError:
        errors.append("invalid_canonical_query")
        expected_query = None
    if expected_query is not None and query != expected_query:
        errors.append("canonical_query_digest_mismatch")
    current = payload.get("current_state")
    if not isinstance(current, dict) or current.get("sequence_trace") != CONTEXT_SEQUENCE_TRACE:
        errors.append("invalid_current_state_order")
    elif not all(isinstance(current.get(key), list) for key in ("docs", "code_contracts", "tests", "observations")):
        errors.append("invalid_current_state_evidence")
    else:
        if typed_exit == "context_ready" and any(not current[group] for group in ("docs", "code_contracts", "tests")):
            errors.append("context_ready_requires_current_evidence")
        for group in ("docs", "code_contracts", "tests"):
            for row in current[group]:
                if not isinstance(row, dict) or set(row) != {"path", "blob_or_content_sha256", "purpose", "observation", "query_clues"}:
                    errors.append("invalid_current_state_evidence")
                    continue
                errors.extend(
                    context_portable_path_shape_errors(
                        row.get("path"),
                        "current_evidence_path",
                    )
                )
                if not re.fullmatch(r"(?:[0-9a-f]{40}|[0-9a-f]{64})", str(row.get("blob_or_content_sha256") or "")):
                    errors.append("invalid_current_evidence_digest")
                if context_duplicate_values(row.get("query_clues")):
                    errors.append("duplicate_current_query_clues")
    preview = payload.get("history_preview")
    preview_keys = {
        "algorithm_id", "canonical_query", "query_sha256", "archive_manifest_sha256",
        "preview_sha256", "limit", "manifest", "candidates", "invalid",
    }
    if (
        not isinstance(preview, dict)
        or set(preview) != preview_keys
        or preview.get("algorithm_id") != CONTEXT_HISTORY_ALGORITHM_ID
        or preview.get("limit") != CONTEXT_HISTORY_LIMIT
    ):
        errors.append("invalid_history_preview")
        candidate_rows: list[Any] = []
    else:
        candidate_rows = preview.get("candidates") if isinstance(preview.get("candidates"), list) else []
        if preview.get("query_sha256") != (query or {}).get("query_sha256"):
            errors.append("history_query_digest_mismatch")
        if preview.get("canonical_query") != query:
            errors.append("history_canonical_query_mismatch")
        manifest = preview.get("manifest")
        invalid = preview.get("invalid")
        if not isinstance(manifest, list) or not isinstance(invalid, list):
            errors.append("invalid_history_manifest")
        else:
            manifest_paths = [row.get("path") for row in manifest if isinstance(row, dict)]
            if len(manifest_paths) != len(manifest) or len(manifest_paths) != len(set(manifest_paths)):
                errors.append("duplicate_history_manifest_path")
            expected_invalid = [row for row in manifest if isinstance(row, dict) and row.get("status") == "invalid"]
            if invalid != expected_invalid:
                errors.append("history_invalid_projection_mismatch")
            if preview.get("archive_manifest_sha256") != context_digest(manifest):
                errors.append("history_manifest_digest_mismatch")
        digest_input = {
            key: preview.get(key)
            for key in ("algorithm_id", "query_sha256", "archive_manifest_sha256", "limit", "candidates", "invalid")
        }
        if preview.get("preview_sha256") != context_digest(digest_input):
            errors.append("history_preview_digest_mismatch")
    candidate_ids = [row.get("candidate_id") for row in candidate_rows if isinstance(row, dict)]
    if len(candidate_ids) != len(candidate_rows) or len(candidate_ids) != len(set(candidate_ids)):
        errors.append("invalid_history_candidates")
    candidate_by_id = {
        str(row["candidate_id"]): row
        for row in candidate_rows
        if isinstance(row, dict) and isinstance(row.get("candidate_id"), str)
    }
    review = payload.get("history_review")
    if not isinstance(review, dict) or set(review) != {"selected_candidates", "excluded_candidates", "deep_reads"}:
        errors.append("invalid_history_review")
    else:
        selected = review.get("selected_candidates") if isinstance(review.get("selected_candidates"), list) else []
        excluded = review.get("excluded_candidates") if isinstance(review.get("excluded_candidates"), list) else []
        selected_ids = [row.get("candidate_id") for row in selected if isinstance(row, dict)]
        excluded_ids = [row.get("candidate_id") for row in excluded if isinstance(row, dict)]
        if (
            len(selected_ids) != len(selected)
            or len(excluded_ids) != len(excluded)
            or len(selected_ids) != len(set(selected_ids))
            or len(excluded_ids) != len(set(excluded_ids))
            or any(
                set(row) != {"candidate_id", "reason"}
                or not isinstance(row.get("reason"), str)
                or not row["reason"].strip()
                for row in selected + excluded if isinstance(row, dict)
            )
        ):
            errors.append("invalid_candidate_selection_shape")
        if candidate_ids and not (1 <= len(selected_ids) <= min(3, len(candidate_ids))):
            errors.append("invalid_selected_candidate_count")
        if not candidate_ids and (selected or excluded or review.get("deep_reads")):
            errors.append("zero_candidate_review_must_be_empty")
        if set(selected_ids) | set(excluded_ids) != set(candidate_ids) or set(selected_ids) & set(excluded_ids):
            errors.append("candidate_selection_partition_mismatch")
        deep_reads = review.get("deep_reads") if isinstance(review.get("deep_reads"), list) else []
        deep_ids = [row.get("candidate_id") for row in deep_reads if isinstance(row, dict)]
        if set(selected_ids) != set(deep_ids) and selected_ids:
            errors.append("selected_candidate_deep_read_mismatch")
        for row in deep_reads:
            errors.extend(context_deep_read_shape_errors(candidate_by_id, row))
    duplicate_search = payload.get("duplicate_search")
    if not isinstance(duplicate_search, dict) or set(duplicate_search) != {"query", "checked_at", "scope", "candidates"}:
        errors.append("invalid_duplicate_search")
    else:
        duplicate_candidates = duplicate_search.get("candidates")
        if not isinstance(duplicate_candidates, list):
            errors.append("invalid_duplicate_search")
        else:
            for candidate in duplicate_candidates:
                errors.extend(context_duplicate_candidate_structural_errors(candidate))
            duplicate_ids = [row.get("identity") for row in duplicate_candidates if isinstance(row, dict)]
            if len(duplicate_ids) != len(duplicate_candidates) or len(duplicate_ids) != len(set(duplicate_ids)):
                errors.append("duplicate_issue_candidate_identity")
    mem = payload.get("mem_review")
    if not isinstance(mem, dict) or mem.get("status") not in {"not_needed", "used"}:
        errors.append("invalid_mem_review")
    elif not candidate_ids and mem.get("status") != "not_needed":
        errors.append("zero_candidate_mem_must_be_not_needed")
    elif mem.get("status") == "used":
        sources = mem.get("exhausted_sources")
        if (
            not isinstance(sources, dict)
            or set(sources) != {"task_artifacts", "current_docs_code_tests", "github", "git_history"}
            or not all(value is True for value in sources.values())
            or not str(mem.get("load_bearing_question") or "").strip()
            or not str(mem.get("summary") or "").strip()
        ):
            errors.append("mem_gate_not_satisfied")
    else:
        if (
            mem.get("load_bearing_question") is not None
            or mem.get("summary") is not None
            or mem.get("exhausted_sources") != {
                "task_artifacts": False,
                "current_docs_code_tests": False,
                "github": False,
                "git_history": False,
            }
        ):
            errors.append("mem_not_needed_shape_invalid")
    gate = payload.get("ai_review_gate")
    if not isinstance(gate, dict) or gate.get("status") not in {"passed", "blocked"}:
        errors.append("invalid_ai_review_gate")
    else:
        if typed_exit == "context_ready" and gate.get("status") != "passed":
            errors.append("context_ready_requires_passed_gate")
        if typed_exit == "blocked" and gate.get("status") != "blocked":
            errors.append("blocked_requires_blocked_gate")
        if gate.get("status") == "blocked" and typed_exit != "blocked":
            errors.append("blocked_gate_requires_blocked_exit")
        if gate.get("status") == "passed" and any(
            isinstance(row, dict) and row.get("status") == "open"
            for row in gate.get("findings", []) if isinstance(gate.get("findings"), list)
        ):
            errors.append("passed_gate_has_open_findings")
    if isinstance(gate, dict) and gate.get("status") == "passed" and (
        not isinstance(gate.get("reviewed_scope"), list)
        or not gate["reviewed_scope"]
        or not isinstance(gate.get("load_bearing_conclusions"), list)
        or not gate["load_bearing_conclusions"]
    ):
        errors.append("passed_gate_requires_semantic_evidence")
    if payload.get("human_confirmation") != {"status": "not_required", "reason": "decision_owned_by_guru-clarify-requirements"}:
        errors.append("invalid_human_confirmation")
    if typed_exit == "refresh_base":
        refresh_history = payload.get("refresh_history")
        if not isinstance(refresh_history, list) or not refresh_history:
            errors.append("refresh_base_requires_history")
        else:
            latest = refresh_history[-1]
            codes = latest.get("error_codes") if isinstance(latest, dict) else None
            if (
                not isinstance(codes, list)
                or not codes
                or any(not isinstance(code, str) for code in codes)
                or codes != context_sort(codes)
            ):
                errors.append("invalid_refresh_error_codes")
            if isinstance(latest, dict) and latest.get("superseded_query_sha256") != (
                query.get("query_sha256") if isinstance(query, dict) else None
            ):
                errors.append("refresh_query_digest_mismatch")
    if typed_exit == "blocked" and not isinstance(payload.get("error"), dict):
        errors.append("blocked_requires_error")
    if typed_exit == "context_ready" and payload.get("error") is not None:
        errors.append("context_ready_forbids_error")
    expected_identity = context_snapshot_identity(payload)
    if payload.get("snapshot_identity") != expected_identity:
        errors.append("snapshot_identity_mismatch")
    return context_sort(errors)


def context_repo_bound_locator_errors(root: Path, payload: dict[str, Any]) -> list[str]:
    errors: list[str] = []
    change_input = payload.get("change_input")
    if isinstance(change_input, dict) and isinstance(change_input.get("paths"), list):
        for value in change_input["paths"]:
            errors.extend(context_portable_path_errors(root, value, "change_input_path"))
    query = payload.get("canonical_query")
    if isinstance(query, dict) and isinstance(query.get("paths"), list):
        for value in query["paths"]:
            errors.extend(context_portable_path_errors(root, value, "canonical_query_path"))
    current = payload.get("current_state")
    if isinstance(current, dict):
        for group in ("docs", "code_contracts", "tests"):
            rows = current.get(group)
            if not isinstance(rows, list):
                continue
            for row in rows:
                if isinstance(row, dict):
                    errors.extend(
                        context_portable_path_errors(
                            root,
                            row.get("path"),
                            "current_evidence_path",
                        )
                    )
    preview = payload.get("history_preview")
    review = payload.get("history_review")
    if isinstance(preview, dict) and isinstance(review, dict):
        candidates = preview.get("candidates")
        candidate_rows = candidates if isinstance(candidates, list) else []
        candidate_by_id = {
            str(row["candidate_id"]): row
            for row in candidate_rows if isinstance(row, dict)
            if isinstance(row.get("candidate_id"), str)
        }
        deep_reads = review.get("deep_reads")
        if isinstance(deep_reads, list):
            for row in deep_reads:
                errors.extend(
                    context_deep_read_locator_errors(root, candidate_by_id, row)
                )
    return context_sort(errors)


def context_read_live_issue(
    root: Path,
    repository: str,
    number: int,
) -> tuple[dict[str, Any] | None, str | None]:
    proc = run([
        "gh", "issue", "view", str(number), "--repo", repository,
        "--json", "number,url,state,updatedAt,body",
    ], cwd=root, check=False)
    if proc.returncode != 0:
        return None, "unreadable"
    try:
        issue = json.loads(proc.stdout)
    except json.JSONDecodeError:
        return None, "invalid"
    state = str(issue.get("state") or "").casefold()
    if state not in {"open", "closed"}:
        return None, "invalid"
    expected_url = f"https://github.com/{repository}/issues/{number}"
    if issue.get("number") != number or issue.get("url") != expected_url:
        return None, "invalid"
    facts = {
        "repo": repository,
        "number": issue.get("number"),
        "url": issue.get("url"),
        "state": state,
        "updated_at": issue.get("updatedAt"),
        "body_sha256": hashlib.sha256(str(issue.get("body") or "").encode("utf-8")).hexdigest(),
    }
    facts["facts_sha256"] = context_digest(facts)
    return facts, None


def context_live_change_errors(root: Path, payload: dict[str, Any]) -> list[str]:
    live = payload.get("live_change")
    repository = payload.get("repository")
    change_input = payload.get("change_input")
    if not all(isinstance(value, dict) for value in (live, repository, change_input)):
        return ["invalid_live_change"]
    repo = str(repository.get("repo") or "")
    if live.get("kind") == "draft":
        binding_errors = context_change_binding_errors(payload)
        if binding_errors:
            return binding_errors
        issue_refs = change_input.get("issue_refs")
        if not issue_refs:
            return []
        binding = live.get("issue_binding")
        if not isinstance(binding, dict) or not isinstance(binding.get("number"), int):
            return ["draft_issue_binding_required"]
        facts, issue_error = context_read_live_issue(root, repo, binding["number"])
        if issue_error is not None:
            return ["live_draft_issue_unreadable"]
        return [] if binding == facts else ["live_draft_issue_stale"]
    if live.get("kind") != "issue":
        return ["invalid_live_change_kind"]
    match = re.search(r"(?:issues/|#)([1-9][0-9]*)$", str(live.get("identity") or ""))
    if match is None:
        return ["invalid_live_issue_identity"]
    facts, issue_error = context_read_live_issue(root, repo, int(match.group(1)))
    if issue_error == "unreadable":
        return ["live_issue_unreadable"]
    if issue_error is not None or facts is None:
        return ["live_issue_invalid"]
    expected = {
        "kind": "issue", "identity": facts["url"], "state": facts["state"],
        "updated_at": facts["updated_at"], "body_sha256": facts["body_sha256"],
        "facts_sha256": facts["facts_sha256"], "issue_binding": None,
    }
    return [] if live == expected else ["live_issue_stale"]


def context_live_base_errors(root: Path, payload: dict[str, Any], task_dir: Path | None) -> list[str]:
    base = payload.get("base_evidence")
    repository = payload.get("repository")
    if not isinstance(base, dict) or not isinstance(repository, dict):
        return ["invalid_base_evidence"]
    contract_errors = context_base_evidence_contract_errors(root, payload)
    if contract_errors:
        return contract_errors
    result = base["sync_result"]
    resolution = result["resolution"]
    decision = result["decision_checkout"]
    git = result["git"]
    errors: list[str] = []
    head = current_head(root)
    if head != decision.get("head_after"):
        errors.append("base_head_stale")
    live_branch = current_branch(root)
    if task_dir is None:
        if live_branch != decision.get("branch"):
            errors.append("base_decision_branch_stale")
    else:
        try:
            active_task_dir = context_active_task_dir(root, str(task_dir))
        except WorkflowError:
            errors.append("task_not_active")
        else:
            if active_task_dir != task_dir.resolve():
                errors.append("task_not_active")
            try:
                task_payload = json.loads((active_task_dir / "task.json").read_text(encoding="utf-8"))
            except (OSError, UnicodeError, json.JSONDecodeError):
                errors.append("task_not_active")
            else:
                task_branch = task_payload.get("branch") if isinstance(task_payload, dict) else None
                try:
                    task_branch = validate_base_branch_name(
                        root,
                        task_branch,
                        "Context discovery active task branch",
                    )
                except WorkflowError:
                    errors.append("invalid_task_branch")
                else:
                    if live_branch != task_branch:
                        errors.append("task_branch_stale")
    selected_base = str(resolution.get("selected_base") or "")
    try:
        selected_base = validate_base_branch_name(root, selected_base, "Context discovery selected base")
    except WorkflowError:
        errors.append("invalid_selected_base")
        selected_base = ""
    try:
        remote_name = validate_base_remote_name(root, resolution.get("remote"))
    except WorkflowError:
        errors.append("invalid_base_remote")
        remote_name = ""
    local_head = ref_head(root, f"refs/heads/{selected_base}") if selected_base else None
    remote_head = (
        ref_head(root, f"refs/remotes/{remote_name}/{selected_base}")
        if remote_name and selected_base
        else None
    )
    if local_head != git.get("local_head_after"):
        errors.append("local_base_stale")
    if remote_head != git.get("remote_head_after"):
        errors.append("remote_base_stale")
    try:
        validate_github_remote_repository(root, remote_name, str(repository.get("repo") or ""))
    except WorkflowError:
        errors.append("base_repository_stale")
    try:
        dirty = git_status_paths(root, fail_closed=True)
    except (WorkflowError, UnicodeError):
        errors.append("git_status_unreadable")
        dirty = []
    if task_dir is None and dirty:
        errors.append("checkout_not_clean")
    elif task_dir is not None:
        task_prefix = task_dir.relative_to(root).as_posix() + "/"
        if any(path != task_prefix[:-1] and not path.startswith(task_prefix) for path in dirty):
            errors.append("dirty_path_outside_task")
    return errors


def context_reviewed_blob_errors(root: Path, payload: dict[str, Any]) -> list[str]:
    current = payload.get("current_state")
    if not isinstance(current, dict):
        return ["invalid_current_state_evidence"]
    errors: list[str] = []
    for group in ("docs", "code_contracts", "tests"):
        rows = current.get(group)
        if not isinstance(rows, list):
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            path = row.get("path")
            expected = str(row.get("blob_or_content_sha256") or "")
            if not isinstance(path, str):
                continue
            if len(expected) == 40:
                proc = run(["git", "rev-parse", f"HEAD:{path}"], cwd=root, check=False)
                resolved = proc.stdout.strip()
                if proc.returncode != 0 or resolved != expected:
                    errors.append("reviewed_blob_stale")
                    continue
                object_type = run(
                    ["git", "cat-file", "-t", resolved],
                    cwd=root,
                    check=False,
                )
                if object_type.returncode != 0 or object_type.stdout.strip() != "blob":
                    errors.append("reviewed_blob_stale")
            elif len(expected) == 64:
                target = root / path
                try:
                    actual = hashlib.sha256(target.read_bytes()).hexdigest()
                except OSError:
                    actual = ""
                if actual != expected:
                    errors.append("reviewed_content_stale")
    return errors


def context_live_errors(root: Path, payload: dict[str, Any], task_dir: Path | None) -> list[str]:
    errors = context_live_base_errors(root, payload, task_dir)
    if errors:
        return context_sort(errors)
    errors.extend(context_repo_bound_locator_errors(root, payload))
    errors.extend(context_live_change_errors(root, payload))
    errors.extend(context_reviewed_blob_errors(root, payload))
    query = payload.get("canonical_query")
    preview = payload.get("history_preview")
    try:
        rebuilt = build_context_history_preview(root, query)
    except WorkflowError:
        errors.append("history_preview_unreadable")
    else:
        if not isinstance(preview, dict) or any(
            preview.get(key) != rebuilt.get(key)
            for key in ("algorithm_id", "query_sha256", "archive_manifest_sha256", "preview_sha256", "limit", "manifest", "candidates", "invalid")
        ):
            errors.append("archive_manifest_or_preview_stale")
    return context_sort(errors)


def context_typed_exit_live_errors(
    payload: dict[str, Any],
    live_errors: list[str],
) -> list[str]:
    observed = context_sort(live_errors)
    if payload.get("typed_exit") != "refresh_base":
        return observed
    if not observed:
        return ["refresh_base_requires_live_stale"]
    if any(code not in CONTEXT_REFRESHABLE_LIVE_ERRORS for code in observed):
        return context_sort([*observed, "refresh_base_has_non_refreshable_error"])
    refresh_history = payload.get("refresh_history")
    latest = refresh_history[-1] if isinstance(refresh_history, list) and refresh_history else None
    expected_codes = latest.get("error_codes") if isinstance(latest, dict) else None
    if expected_codes != observed:
        return ["refresh_error_codes_mismatch"]
    return []


def context_persisted_snapshot_errors(
    root: Path,
    target: Path,
    expected_payload: dict[str, Any],
    task_dir: Path,
) -> list[str]:
    expected_bytes = json_document_bytes(expected_payload)
    try:
        actual_bytes = target.read_bytes()
    except OSError:
        return ["persisted_snapshot_unreadable"]
    if actual_bytes != expected_bytes:
        return ["persisted_snapshot_mismatch"]
    try:
        persisted = json.loads(actual_bytes)
    except (UnicodeError, json.JSONDecodeError):
        return ["persisted_snapshot_mismatch"]
    if not isinstance(persisted, dict) or persisted != expected_payload:
        return ["persisted_snapshot_mismatch"]
    if persisted.get("snapshot_identity") != context_snapshot_identity(persisted):
        return ["persisted_snapshot_identity_mismatch"]
    structural = context_structural_errors(root, persisted)
    if structural:
        return context_sort(structural)
    live = context_live_errors(root, persisted, task_dir)
    return context_sort(context_typed_exit_live_errors(persisted, live))


def context_discovery_target_trackability_errors(root: Path, target: Path) -> list[str]:
    try:
        relative_target = target.relative_to(root).as_posix()
    except ValueError:
        return ["context_discovery_target_trackability_unreadable"]
    try:
        result = run(
            [
                "git",
                "check-ignore",
                "--quiet",
                "--no-index",
                "--",
                relative_target,
            ],
            cwd=root,
            check=False,
        )
    except OSError:
        return ["context_discovery_target_trackability_unreadable"]
    if result.returncode == 0:
        return ["context_discovery_target_ignored"]
    if result.returncode == 1:
        return []
    return ["context_discovery_target_trackability_unreadable"]


def cmd_preview_change_context_history(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    if args.query_json:
        try:
            raw_query = json.loads(args.query_json)
        except json.JSONDecodeError as exc:
            raise WorkflowError("--query-json is invalid JSON.", exit_code=2) from exc
    else:
        raw_query = {
            "issue_refs": args.issue_ref,
            "pr_refs": args.pr_ref,
            "branches": args.branch,
            "paths": args.path,
            "commands": args.query_command,
            "config_keys": args.config_key,
            "schema_fields": args.schema_field,
            "symbols": args.symbol,
            "terms": args.term,
            "queries": args.query,
        }
    return build_context_history_preview(root, raw_query, limit=args.limit)


def cmd_record_context_discovery(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    payload, task_dir = context_payload_from_args(root, args, require_active_task=True)
    if payload.get("mode") != args.mode:
        raise WorkflowError("context discovery mode does not match recorder mode.", exit_code=2)
    payload["snapshot_identity"] = context_snapshot_identity(payload)
    structural = context_structural_errors(root, payload)
    if structural:
        raise WorkflowError(
            "Context discovery snapshot validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(structural)},
        )
    live = context_live_errors(root, payload, task_dir)
    route_live = context_typed_exit_live_errors(payload, live)
    if structural or route_live:
        raise WorkflowError(
            "Context discovery snapshot validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(structural + route_live)},
        )
    snapshot_sha256 = payload["snapshot_identity"]["snapshot_sha256"]
    if args.expected_snapshot_sha256 and args.expected_snapshot_sha256 != snapshot_sha256:
        raise WorkflowError("Expected context discovery snapshot digest does not match.", exit_code=2, payload={"error_codes": ["expected_snapshot_mismatch"]})
    if task_dir is None:
        if args.expected_snapshot_sha256:
            raise WorkflowError("Pre-task context recording does not accept an expected task snapshot.", exit_code=2)
        return payload
    if not args.expected_snapshot_sha256:
        raise WorkflowError("Task-local context recording requires --expected-snapshot-sha256.", exit_code=2)
    target = task_dir / "context-discovery.json"
    trackability_errors = context_discovery_target_trackability_errors(root, target)
    if trackability_errors:
        raise WorkflowError(
            "Context discovery target must be trackable by Git.",
            exit_code=2,
            payload={"error_codes": trackability_errors},
        )
    expected_bytes = json_document_bytes(payload)
    if target.exists():
        try:
            actual_bytes = target.read_bytes()
        except OSError as exc:
            raise WorkflowError(
                "Existing context-discovery.json is unreadable.",
                exit_code=2,
                payload={"error_codes": ["existing_snapshot_unreadable"]},
            ) from exc
        if actual_bytes != expected_bytes:
            raise WorkflowError("Existing context-discovery.json does not match the expected snapshot.", exit_code=2, payload={"error_codes": ["existing_snapshot_mismatch"]})
    else:
        write_json(target, payload)
    trackability_errors = context_discovery_target_trackability_errors(root, target)
    if trackability_errors:
        raise WorkflowError(
            "Context discovery target must remain trackable by Git.",
            exit_code=2,
            payload={"error_codes": trackability_errors},
        )
    persisted_errors = context_persisted_snapshot_errors(
        root,
        target,
        payload,
        task_dir,
    )
    if persisted_errors:
        raise WorkflowError(
            "Persisted context discovery snapshot validation failed.",
            exit_code=2,
            payload={"error_codes": persisted_errors},
        )
    return payload


def cmd_check_context_discovery(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    payload, task_dir = context_payload_from_args(root, args)
    structural = context_structural_errors(root, payload)
    if structural:
        raise WorkflowError(
            "Context discovery snapshot validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(structural)},
        )
    if task_dir is not None:
        trackability_errors = context_discovery_target_trackability_errors(
            root,
            task_dir / "context-discovery.json",
        )
        if trackability_errors:
            raise WorkflowError(
                "Context discovery target must be trackable by Git.",
                exit_code=2,
                payload={"error_codes": trackability_errors},
            )
    live = context_live_errors(root, payload, task_dir)
    expected = args.expected_snapshot_sha256
    actual = (payload.get("snapshot_identity") or {}).get("snapshot_sha256") if isinstance(payload.get("snapshot_identity"), dict) else None
    if expected and expected != actual:
        structural.append("expected_snapshot_mismatch")
    errors = context_sort(structural + context_typed_exit_live_errors(payload, live))
    if errors:
        raise WorkflowError("Context discovery snapshot validation failed.", exit_code=2, payload={"error_codes": errors})
    return {
        "status": "passed",
        "typed_exit": payload["typed_exit"],
        "snapshot_sha256": actual,
        "query_sha256": payload["snapshot_identity"]["query_sha256"],
        "archive_manifest_sha256": payload["snapshot_identity"]["archive_manifest_sha256"],
        "base_head": payload["snapshot_identity"]["base_head"],
        "base_sync_facts_sha256": payload["snapshot_identity"]["base_sync_facts_sha256"],
        "post_sync_resolution_sha256": payload["snapshot_identity"]["post_sync_resolution_sha256"],
    }


def requirements_clarification_schema(root: Path) -> dict[str, Any]:
    candidates = [
        root / ".trellis/guru-team/skills/packages/guru-clarify-requirements/schemas/requirements-clarification.schema.json",
        root / "trellis/skills/guru-team/packages/guru-clarify-requirements/schemas/requirements-clarification.schema.json",
    ]
    runtime_path = Path(__file__).resolve()
    if len(runtime_path.parents) > 4:
        candidates.append(
            runtime_path.parents[4]
            / "skills/guru-team/packages/guru-clarify-requirements/schemas/requirements-clarification.schema.json"
        )
    schema_path = next(
        (path for path in candidates if path.is_file() and not path.is_symlink()),
        None,
    )
    if schema_path is None:
        raise WorkflowError(
            "Requirements clarification schema is missing from the compatible Guru Team runtime.",
            exit_code=2,
            payload={"error_codes": ["requirements_clarification_schema_unavailable"]},
        )
    errors: list[str] = []
    schema = skill_read_json(schema_path, "requirements clarification schema", errors)
    if (
        errors
        or schema is None
        or schema.get("$schema") != SKILL_SCHEMA_DIALECT
        or schema.get("$id") != REQUIREMENTS_CLARIFICATION_SCHEMA_ID
    ):
        raise WorkflowError(
            "Requirements clarification schema is incompatible.",
            exit_code=2,
            payload={"error_codes": ["requirements_clarification_schema_invalid"]},
        )
    return schema


def requirements_clarification_payload_from_args(
    root: Path,
    args: argparse.Namespace,
) -> tuple[dict[str, Any], Path | None]:
    input_value = getattr(args, "input", None)
    if not input_value:
        raise WorkflowError("requirements clarification requires --input.", exit_code=2)
    if input_value == "-":
        raw = sys.stdin.read()
    else:
        input_path = Path(input_value)
        if not input_path.is_absolute():
            input_path = root / input_path
        try:
            raw = input_path.read_text(encoding="utf-8")
        except (OSError, UnicodeError) as exc:
            raise WorkflowError("requirements clarification input is unreadable.", exit_code=2) from exc
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise WorkflowError("requirements clarification input is invalid JSON.", exit_code=2) from exc
    if not isinstance(payload, dict):
        raise WorkflowError("requirements clarification input root must be an object.", exit_code=2)

    task_dir: Path | None = None
    task_value = getattr(args, "task", None)
    invocation = payload.get("invocation_context")
    if not task_value and isinstance(invocation, dict):
        task_value = invocation.get("task_locator")
    if task_value:
        task_dir = context_active_task_dir(root, str(task_value))
    return payload, task_dir


def requirements_clarification_review_target_projection(target: Any) -> dict[str, Any] | None:
    if not isinstance(target, dict):
        return None
    fields = (
        "kind", "repo", "issue_number", "url", "state", "updated_at",
        "body_sha256",
    )
    if any(field not in target for field in fields):
        return None
    return {field: copy.deepcopy(target[field]) for field in fields}


def requirements_clarification_proposal_projection(proposal: Any) -> dict[str, Any] | None:
    if not isinstance(proposal, dict):
        return None
    projection = copy.deepcopy(proposal)
    projection.pop("proposal_digest", None)
    projection.pop("confirmation_ref", None)
    return projection


def requirements_clarification_action_projection(action: Any) -> dict[str, Any] | None:
    if not isinstance(action, dict):
        return None
    fields = (
        "action_id", "kind", "target", "payload", "preimage_sha256",
        "payload_sha256",
    )
    if any(field not in action for field in fields):
        return None
    return {field: copy.deepcopy(action[field]) for field in fields}


def requirements_clarification_active_task_payload_projection(
    evidence: Any,
) -> dict[str, Any] | None:
    if not isinstance(evidence, dict) or any(
        field not in evidence for field in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_PAYLOAD_FIELDS
    ):
        return None
    return {
        field: copy.deepcopy(evidence[field])
        for field in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_PAYLOAD_FIELDS
    }


def requirements_clarification_mutation_projection(result: Any) -> dict[str, Any] | None:
    if not isinstance(result, dict):
        return None
    projection = copy.deepcopy(result)
    projection.pop("facts_sha256", None)
    return projection


def requirements_clarification_content_identity(payload: dict[str, Any]) -> dict[str, str]:
    actions = payload.get("source_actions") if isinstance(payload.get("source_actions"), list) else []
    content_projection = {
        "confirmed_facts": payload.get("confirmed_facts"),
        "repository_answerable_questions": payload.get("repository_answerable_questions"),
        "clarification_rounds": payload.get("clarification_rounds"),
        "open_questions": payload.get("open_questions"),
        "affected_contracts": payload.get("affected_contracts"),
        "reason": payload.get("reason"),
    }
    unsigned_result = copy.deepcopy(payload)
    unsigned_result.pop("content_identity", None)
    return {
        "target_sha256": context_digest(payload.get("review_target")),
        "content_sha256": context_digest(content_projection),
        "context_sha256": context_digest(payload.get("context_evidence")),
        "scope_sha256": context_digest(payload.get("scope_proposals")),
        "action_sha256": context_digest(actions),
        "payload_sha256": context_digest([
            action.get("payload") if isinstance(action, dict) else None
            for action in actions
        ]),
        "result_sha256": context_digest(unsigned_result),
    }


def derive_requirements_clarification_result(payload: dict[str, Any]) -> dict[str, Any]:
    result = copy.deepcopy(payload)
    result["schema_version"] = REQUIREMENTS_CLARIFICATION_SCHEMA_VERSION
    result["skill_id"] = REQUIREMENTS_CLARIFICATION_SKILL_ID
    target = result.get("review_target")
    projection = requirements_clarification_review_target_projection(target)
    if isinstance(target, dict) and projection is not None:
        target["facts_sha256"] = context_digest(projection)
    proposals = result.get("scope_proposals")
    if isinstance(proposals, list):
        for proposal in proposals:
            projection = requirements_clarification_proposal_projection(proposal)
            if isinstance(proposal, dict) and projection is not None:
                proposal["proposal_digest"] = context_digest(projection)
    actions = result.get("source_actions")
    if isinstance(actions, list):
        for action in actions:
            if not isinstance(action, dict):
                continue
            payload_value = action.get("payload")
            action["payload_sha256"] = (
                context_digest(payload_value) if isinstance(payload_value, dict) else None
            )
            projection = requirements_clarification_action_projection(action)
            if projection is not None:
                action["action_digest"] = context_digest(projection)
    mutations = result.get("mutation_results")
    if isinstance(mutations, list):
        for mutation in mutations:
            projection = requirements_clarification_mutation_projection(mutation)
            if isinstance(mutation, dict) and projection is not None:
                mutation["facts_sha256"] = context_digest(projection)
    result["content_identity"] = requirements_clarification_content_identity(result)
    return result


def requirements_clarification_is_sha256(value: Any) -> bool:
    return isinstance(value, str) and re.fullmatch(r"[0-9a-f]{64}", value) is not None


def requirements_clarification_nonempty(value: Any) -> bool:
    return (
        isinstance(value, str)
        and bool(value.strip())
        and "\x00" not in value
        and not any(
            (ord(character) < 32 and character not in "\t\n\r")
            or ord(character) == 127
            for character in value
        )
    )


def requirements_clarification_confirmation_covers_actions(
    confirmation: Any,
    action_by_id: dict[str, dict[str, Any]],
    required_action_ids: set[str],
) -> bool:
    if not isinstance(confirmation, dict):
        return False
    confirmed_actions = confirmation.get("confirmed_actions")
    if (
        confirmation.get("status") != "confirmed"
        or confirmation.get("confirmation_kind")
        not in {"exact_source_action", "exact_source_action_and_scope"}
        or not isinstance(confirmed_actions, list)
        or any(
            not isinstance(action_id, str) or action_id not in action_by_id
            for action_id in confirmed_actions
        )
        or not required_action_ids.issubset(set(confirmed_actions))
    ):
        return False
    expected_digest = context_digest([
        action_by_id[action_id].get("action_digest")
        for action_id in confirmed_actions
    ])
    return confirmation.get("action_digest") == expected_digest


def requirements_clarification_active_task_action_confirmation_errors(
    payload: dict[str, Any],
) -> list[str]:
    invocation = payload.get("invocation_context")
    if not isinstance(invocation, dict) or invocation.get("kind") != "active_task_scope_change":
        return []
    proposals = payload.get("scope_proposals")
    classification_proposals = [
        proposal for proposal in proposals
        if isinstance(proposals, list)
        and isinstance(proposal, dict)
        and proposal.get("decision")
        in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_CLASSIFICATION_DECISIONS
    ] if isinstance(proposals, list) else []
    if not classification_proposals:
        return []
    actions = payload.get("source_actions")
    action_by_id = {
        action["action_id"]: action
        for action in actions
        if isinstance(actions, list)
        and isinstance(action, dict)
        and isinstance(action.get("action_id"), str)
    } if isinstance(actions, list) else {}
    task_update_action_ids = {
        action_id for action_id, action in action_by_id.items()
        if action.get("kind") == "active_task_scope_update"
    }
    if not task_update_action_ids:
        return []
    confirmation = payload.get("human_confirmation")
    expected_proposal_digests = [
        proposal.get("proposal_digest") for proposal in classification_proposals
    ]
    if (
        not isinstance(confirmation, dict)
        or confirmation.get("confirmation_kind") != "exact_source_action_and_scope"
        or confirmation.get("proposal_digests") != expected_proposal_digests
        or not requirements_clarification_confirmation_covers_actions(
            confirmation,
            action_by_id,
            task_update_action_ids,
        )
    ):
        return ["active_task_scope_update_requires_exact_action_confirmation"]
    return []


def requirements_clarification_structural_errors(
    root: Path,
    payload: dict[str, Any],
    task_dir: Path | None,
) -> list[str]:
    errors: list[str] = []
    schema_errors = skill_json_schema_validation_errors(
        payload,
        requirements_clarification_schema(root),
        "requirements clarification result",
    )
    if schema_errors:
        errors.append("requirements_clarification_schema_validation_failed")
    if set(payload) != REQUIREMENTS_CLARIFICATION_TOP_LEVEL_KEYS:
        errors.append("invalid_requirements_clarification_top_level")
    if payload.get("schema_version") != REQUIREMENTS_CLARIFICATION_SCHEMA_VERSION:
        errors.append("invalid_requirements_clarification_schema_version")
    if payload.get("skill_id") != REQUIREMENTS_CLARIFICATION_SKILL_ID:
        errors.append("invalid_requirements_clarification_skill_id")
    if payload.get("mode") not in {"workflow", "standalone"}:
        errors.append("invalid_requirements_clarification_mode")
    typed_exit = payload.get("typed_exit")
    if typed_exit not in REQUIREMENTS_CLARIFICATION_CONSUMERS:
        errors.append("invalid_requirements_clarification_typed_exit")
    elif payload.get("consumer") != REQUIREMENTS_CLARIFICATION_CONSUMERS[typed_exit]:
        errors.append("requirements_clarification_consumer_mismatch")
    try:
        parse_iso_datetime(payload.get("generated_at"), "requirements clarification generated_at")
    except WorkflowError:
        errors.append("invalid_requirements_clarification_generated_at")

    invocation = payload.get("invocation_context")
    invocation_kind = invocation.get("kind") if isinstance(invocation, dict) else None
    if (
        not isinstance(invocation, dict)
        or set(invocation) != {"kind", "caller", "task_locator", "resume_target"}
        or invocation_kind not in {"initial_issue", "proposed_draft", "active_task_scope_change", "standalone_review"}
        or not requirements_clarification_nonempty(invocation.get("caller"))
    ):
        errors.append("invalid_requirements_clarification_invocation")
    elif invocation.get("resume_target") not in REQUIREMENTS_CLARIFICATION_RESUME_TARGETS[invocation_kind]:
        errors.append("requirements_clarification_resume_target_mismatch")
    if invocation_kind == "active_task_scope_change":
        if task_dir is None or not isinstance(invocation.get("task_locator"), str):
            errors.append("active_task_scope_change_requires_task")
    elif task_dir is not None or (isinstance(invocation, dict) and invocation.get("task_locator") is not None):
        errors.append("non_task_clarification_forbids_task")

    target = payload.get("review_target")
    target_projection = requirements_clarification_review_target_projection(target)
    if (
        not isinstance(target, dict)
        or set(target) != {"kind", "repo", "issue_number", "url", "state", "updated_at", "body_sha256", "facts_sha256"}
        or target.get("kind") not in {"issue", "draft"}
        or not re.fullmatch(r"[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+", str(target.get("repo") or ""))
        or not requirements_clarification_is_sha256(target.get("body_sha256"))
        or target_projection is None
        or target.get("facts_sha256") != context_digest(target_projection)
    ):
        errors.append("invalid_requirements_clarification_target")
    elif target.get("kind") == "draft":
        if any(target.get(field) is not None for field in ("issue_number", "url", "updated_at")) or target.get("state") != "draft":
            errors.append("invalid_requirements_clarification_draft_target")
    elif (
        not isinstance(target.get("issue_number"), int)
        or target["issue_number"] <= 0
        or target.get("url") != f"https://github.com/{target['repo']}/issues/{target['issue_number']}"
        or target.get("state") not in {"open", "closed"}
        or not requirements_clarification_nonempty(target.get("updated_at"))
    ):
        errors.append("invalid_requirements_clarification_issue_target")

    context = payload.get("context_evidence")
    if (
        not isinstance(context, dict)
        or set(context) != {"status", "schema_id", "snapshot_sha256", "evidence_refs", "missing_reason"}
        or context.get("status") not in {"current", "missing", "stale"}
        or not isinstance(context.get("evidence_refs"), list)
    ):
        errors.append("invalid_requirements_clarification_context")
    elif context.get("status") == "current":
        if (
            context.get("schema_id") != "guru-context-discovery-1.0"
            or not requirements_clarification_is_sha256(context.get("snapshot_sha256"))
            or not context.get("evidence_refs")
            or context.get("missing_reason") is not None
        ):
            errors.append("invalid_current_requirements_context")
    elif context.get("status") == "missing":
        if (
            context.get("schema_id") is not None
            or context.get("snapshot_sha256") is not None
            or not context.get("evidence_refs")
            or not requirements_clarification_nonempty(context.get("missing_reason"))
        ):
            errors.append("invalid_missing_requirements_context")
    elif (
        context.get("schema_id") != "guru-context-discovery-1.0"
        or not requirements_clarification_is_sha256(context.get("snapshot_sha256"))
        or not context.get("evidence_refs")
        or not requirements_clarification_nonempty(context.get("missing_reason"))
    ):
        errors.append("invalid_stale_requirements_context")
    repository_questions = payload.get("repository_answerable_questions")
    if not isinstance(repository_questions, list):
        errors.append("invalid_repository_answerable_questions")
        repository_questions = []
    repository_question_ids: list[Any] = []
    for question in repository_questions:
        if not isinstance(question, dict):
            errors.append("invalid_repository_answerable_question")
            continue
        repository_question_ids.append(question.get("question_id"))
        status = question.get("status")
        evidence_refs = question.get("evidence_refs")
        if status not in {"pending", "answered", "not_answerable"} or not isinstance(evidence_refs, list):
            errors.append("invalid_repository_answerable_question")
        elif status == "answered" and (
            not requirements_clarification_nonempty(question.get("answer_summary"))
            or not evidence_refs
        ):
            errors.append("answered_repository_question_requires_evidence")
        elif status == "not_answerable" and (not evidence_refs or not requirements_clarification_nonempty(question.get("missing_reason"))):
            errors.append("not_answerable_question_requires_evidence")
    if len(repository_question_ids) != len(set(repository_question_ids)):
        errors.append("duplicate_repository_question_id")

    rounds = payload.get("clarification_rounds")
    if not isinstance(rounds, list):
        errors.append("invalid_clarification_rounds")
        rounds = []
    if rounds and any(question.get("status") == "pending" for question in repository_questions if isinstance(question, dict)):
        errors.append("repository_questions_must_precede_user_questions")
    round_ids: list[Any] = []
    user_question_ids: list[Any] = []
    opened: set[str] = set()
    closed: set[str] = set()
    current_open: set[str] = set()
    for round_item in rounds:
        if not isinstance(round_item, dict):
            errors.append("invalid_clarification_round")
            continue
        round_ids.append(round_item.get("round_id"))
        user_question_ids.append(round_item.get("question_id"))
        opened_ids = round_item.get("opened_question_ids")
        closed_ids = round_item.get("closed_question_ids")
        if not isinstance(opened_ids, list) or not isinstance(closed_ids, list):
            errors.append("invalid_clarification_question_transitions")
            continue
        opened_this_round = {value for value in opened_ids if isinstance(value, str)}
        closed_this_round = {value for value in closed_ids if isinstance(value, str)}
        question_id = round_item.get("question_id")
        if question_id not in current_open | opened_this_round:
            errors.append("clarification_question_not_opened")
        if round_item.get("answer_status") == "partial" and closed_ids:
            errors.append("partial_answer_cannot_close_questions")
        if opened_this_round & closed:
            errors.append("clarification_question_reopened_after_closure")
        if closed_this_round - (current_open | opened_this_round):
            errors.append("clarification_question_closes_unopened")
        opened.update(opened_this_round)
        closed.update(closed_this_round)
        current_open.update(opened_this_round)
        current_open.difference_update(closed_this_round)
        atomic_id = round_item.get("atomic_group_id")
        atomic_reason = round_item.get("atomic_group_reason")
        if (atomic_id is None) != (atomic_reason is None):
            errors.append("invalid_atomic_group")
    if len(round_ids) != len(set(round_ids)) or len(user_question_ids) != len(set(user_question_ids)):
        errors.append("duplicate_clarification_round_or_question")
    open_questions = payload.get("open_questions")
    if not isinstance(open_questions, list) or len(open_questions) != len(set(open_questions)):
        errors.append("invalid_open_questions")
        open_questions = []
    if set(open_questions) & closed:
        errors.append("closed_question_remains_open")
    if set(open_questions) != current_open or current_open != opened - closed:
        errors.append("open_questions_state_mismatch")

    proposals = payload.get("scope_proposals")
    if not isinstance(proposals, list):
        errors.append("invalid_scope_proposals")
        proposals = []
    proposal_ids: list[Any] = []
    proposal_by_id: dict[str, dict[str, Any]] = {}
    for proposal in proposals:
        projection = requirements_clarification_proposal_projection(proposal)
        if not isinstance(proposal, dict) or projection is None:
            errors.append("invalid_scope_proposal")
            continue
        proposal_id = proposal.get("proposal_id")
        proposal_ids.append(proposal_id)
        if isinstance(proposal_id, str):
            proposal_by_id[proposal_id] = proposal
        if proposal.get("proposal_digest") != context_digest(projection):
            errors.append("scope_proposal_digest_mismatch")
        decision = proposal.get("decision")
        optional_mechanism = proposal.get("optional_mechanism_origin") is True
        if decision in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_MECHANISM_DECISIONS:
            if not optional_mechanism:
                errors.append("mechanism_disposition_requires_optional_mechanism_origin")
            if proposal.get("confirmation_ref") is not None:
                errors.append("mechanism_disposition_forbids_confirmation")
        elif (
            optional_mechanism
            and decision
            in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_CLASSIFICATION_DECISIONS
        ):
            errors.append("optional_mechanism_requires_mechanism_disposition")
            if decision == "accepted_current":
                errors.append("optional_mechanism_cannot_expand_scope")
    if len(proposal_ids) != len(set(proposal_ids)):
        errors.append("duplicate_scope_proposal_id")

    actions = payload.get("source_actions")
    if not isinstance(actions, list) or not actions:
        errors.append("invalid_source_actions")
        actions = []
    action_ids: list[Any] = []
    action_by_id: dict[str, dict[str, Any]] = {}
    for action in actions:
        projection = requirements_clarification_action_projection(action)
        if not isinstance(action, dict) or projection is None or action.get("kind") not in REQUIREMENTS_CLARIFICATION_ACTION_KINDS:
            errors.append("invalid_source_action")
            continue
        action_id = action.get("action_id")
        action_ids.append(action_id)
        if isinstance(action_id, str):
            action_by_id[action_id] = action
        expected_payload_sha = context_digest(action.get("payload")) if isinstance(action.get("payload"), dict) else None
        if action.get("payload_sha256") != expected_payload_sha or action.get("action_digest") != context_digest(projection):
            errors.append("source_action_digest_mismatch")
        action_kind = action.get("kind")
        action_target = action.get("target")
        action_payload = action.get("payload")
        action_status = action.get("status")
        if action_kind == "none":
            if (
                any(action.get(field) is not None for field in ("target", "payload", "preimage_sha256", "mutation_evidence"))
                or action_status != "not_required"
            ):
                errors.append("none_action_shape_invalid")
        elif action_kind in {"issue_comment", "issue_body_edit"}:
            expected_target = {
                "repo": target.get("repo") if isinstance(target, dict) else None,
                "issue_number": target.get("issue_number") if isinstance(target, dict) else None,
            }
            if (
                not isinstance(target, dict)
                or target.get("kind") != "issue"
                or action_target != expected_target
                or not isinstance(action_payload, dict)
                or set(action_payload) != {"body"}
                or not requirements_clarification_nonempty(action_payload.get("body"))
                or action.get("preimage_sha256") != target.get("body_sha256")
                or action_status not in {"pending", "executed", "validated"}
            ):
                errors.append("github_source_action_shape_invalid")
            if action_status == "pending" and action.get("mutation_evidence") is not None:
                errors.append("pending_source_action_has_mutation_evidence")
            if (
                action_status in {"executed", "validated"}
                and action.get("mutation_evidence") != {"source": "ai-reviewed-gh"}
            ):
                errors.append("executed_source_action_requires_mutation_evidence")
        elif action_kind in {"proposed_draft_update", "new_issue_draft"}:
            if (
                not isinstance(action_target, dict)
                or action_target != {"repo": target.get("repo") if isinstance(target, dict) else None}
                or not isinstance(action_payload, dict)
                or set(action_payload) != {"title", "body"}
                or not all(requirements_clarification_nonempty(action_payload.get(field)) for field in ("title", "body"))
                or action.get("mutation_evidence") is not None
            ):
                errors.append("draft_source_action_shape_invalid")
            if action_kind == "proposed_draft_update" and (
                not isinstance(target, dict)
                or target.get("kind") != "draft"
                or not isinstance(action_payload, dict)
                or action_status != "validated"
                or hashlib.sha256(action_payload.get("body", "").encode("utf-8")).hexdigest()
                != target.get("body_sha256")
            ):
                errors.append("proposed_draft_update_binding_invalid")
            if action_kind == "new_issue_draft" and (
                action.get("preimage_sha256") is not None or action_status != "draft_ready"
            ):
                errors.append("new_issue_draft_binding_invalid")
        elif action_kind == "active_task_scope_update":
            expected_locator = (
                task_dir.relative_to(root).as_posix() if task_dir is not None else None
            )
            expected_payload = requirements_clarification_active_task_payload_projection(
                payload.get("active_task_evidence")
            )
            if (
                invocation_kind != "active_task_scope_change"
                or action_target != {"task_locator": expected_locator}
                or action_payload != expected_payload
                or not requirements_clarification_is_sha256(action.get("preimage_sha256"))
                or action_status not in {"executed", "validated"}
                or action.get("mutation_evidence")
                != {"source": "confirmed-task-local-update"}
            ):
                errors.append("active_task_scope_action_binding_invalid")
    if len(action_ids) != len(set(action_ids)):
        errors.append("duplicate_source_action_id")

    confirmation = payload.get("human_confirmation")
    if not isinstance(confirmation, dict):
        errors.append("invalid_requirements_confirmation")
        confirmation = {}
    confirmation_status = confirmation.get("status")
    proposal_digests = confirmation.get("proposal_digests")
    confirmed_actions = confirmation.get("confirmed_actions")
    if not isinstance(proposal_digests, list) or not isinstance(confirmed_actions, list):
        errors.append("invalid_requirements_confirmation")
        proposal_digests = []
        confirmed_actions = []
    if confirmation_status == "not_required":
        if (
            confirmation.get("confirmation_kind") != "none"
            or confirmation.get("action_digest") is not None
            or proposal_digests
            or confirmed_actions
            or confirmation.get("confirmer") is not None
            or confirmation.get("confirmed_at") is not None
        ):
            errors.append("not_required_confirmation_shape_invalid")
    elif confirmation_status in {"confirmed", "refused"}:
        if confirmation.get("confirmation_kind") not in {"exact_source_action", "exact_scope_proposal", "exact_source_action_and_scope"}:
            errors.append("generic_confirmation_forbidden")
        if not requirements_clarification_nonempty(confirmation.get("confirmer")) or not requirements_clarification_nonempty(confirmation.get("confirmed_at")):
            errors.append("exact_confirmation_identity_required")
        if confirmed_actions and confirmation.get("action_digest") != context_digest([
            action_by_id[action_id].get("action_digest")
            for action_id in confirmed_actions if action_id in action_by_id
        ]):
            errors.append("confirmation_action_digest_mismatch")
        if any(action_id not in action_by_id for action_id in confirmed_actions):
            errors.append("confirmation_action_unknown")
        known_proposal_digests = {
            proposal.get("proposal_digest")
            for proposal in proposals if isinstance(proposal, dict)
        }
        if any(digest not in known_proposal_digests for digest in proposal_digests):
            errors.append("confirmation_proposal_unknown")
        if confirmed_actions and confirmation.get("confirmation_kind") not in {
            "exact_source_action", "exact_source_action_and_scope",
        }:
            errors.append("confirmation_kind_action_mismatch")
        if proposal_digests and confirmation.get("confirmation_kind") not in {
            "exact_scope_proposal", "exact_source_action_and_scope",
        }:
            errors.append("confirmation_kind_proposal_mismatch")
    else:
        errors.append("invalid_requirements_confirmation_status")
    for proposal in proposals:
        if not isinstance(proposal, dict):
            continue
        if proposal.get("origin_requirement_status") == "unconfirmed_expansion" and proposal.get("decision") == "accepted_current":
            if (
                confirmation_status != "confirmed"
                or proposal.get("proposal_digest") not in proposal_digests
                or proposal.get("confirmation_ref") is None
            ):
                errors.append("unconfirmed_expansion_requires_exact_confirmation")
        if (
            invocation_kind == "active_task_scope_change"
            and proposal.get("origin_requirement_status") == "unconfirmed_expansion"
            and proposal.get("decision")
            in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_NON_CURRENT_DECISIONS
            and (
                confirmation_status != "confirmed"
                or proposal.get("proposal_digest") not in proposal_digests
                or proposal.get("confirmation_ref") is None
            )
        ):
            errors.append("unconfirmed_non_current_decision_requires_user_evidence")

    mutations = payload.get("mutation_results")
    if not isinstance(mutations, list):
        errors.append("invalid_mutation_results")
        mutations = []
    mutation_ids: list[Any] = []
    for mutation in mutations:
        projection = requirements_clarification_mutation_projection(mutation)
        if (
            not isinstance(mutation, dict)
            or projection is None
            or set(mutation) != {
                "action_id", "kind", "status", "url", "state", "updated_at",
                "content_sha256", "action_digest", "facts_sha256",
            }
            or mutation.get("status") != "succeeded"
            or not requirements_clarification_is_sha256(mutation.get("content_sha256"))
            or not requirements_clarification_is_sha256(mutation.get("action_digest"))
        ):
            errors.append("invalid_mutation_result")
            continue
        mutation_ids.append(mutation.get("action_id"))
        action = action_by_id.get(str(mutation.get("action_id")))
        if action is None:
            errors.append("mutation_action_binding_mismatch")
            continue
        if mutation.get("action_digest") != action.get("action_digest"):
            errors.append("mutation_action_binding_mismatch")
        elif mutation.get("kind") != action.get("kind") or action.get("status") not in {"executed", "validated"}:
            errors.append("mutation_action_state_mismatch")
        elif (
            confirmation_status != "confirmed"
            or not requirements_clarification_confirmation_covers_actions(
                confirmation,
                action_by_id,
                {str(mutation.get("action_id"))},
            )
        ):
            errors.append("mutation_requires_exact_action_confirmation")
        if mutation.get("facts_sha256") != context_digest(projection):
            errors.append("mutation_facts_digest_mismatch")
        mutation_kind = mutation.get("kind")
        action_payload = action.get("payload") if isinstance(action, dict) else None
        expected_content_sha = (
            hashlib.sha256(action_payload["body"].encode("utf-8")).hexdigest()
            if isinstance(action_payload, dict)
            and requirements_clarification_nonempty(action_payload.get("body"))
            else None
        )
        if mutation_kind in {"issue_comment", "issue_body_edit"} and (
            action.get("payload_sha256") != context_digest(action_payload)
            or mutation.get("content_sha256") != expected_content_sha
        ):
            errors.append("mutation_confirmed_payload_mismatch")
        if mutation_kind == "proposed_draft_update":
            if (
                mutation.get("url") is not None
                or mutation.get("state") != "draft"
                or mutation.get("updated_at") is not None
                or mutation.get("content_sha256") != expected_content_sha
            ):
                errors.append("proposed_draft_mutation_result_invalid")
        elif mutation_kind == "active_task_scope_update":
            if (
                mutation.get("url") is not None
                or mutation.get("state") != "task_local"
                or mutation.get("updated_at") is not None
                or mutation.get("content_sha256")
                != context_digest(payload.get("active_task_evidence"))
            ):
                errors.append("active_task_scope_mutation_result_invalid")
    if len(mutation_ids) != len(set(mutation_ids)):
        errors.append("duplicate_mutation_action_id")
    mutation_action_ids = {
        str(action_id) for action_id in mutation_ids if isinstance(action_id, str)
    }
    for action in actions:
        if not isinstance(action, dict):
            continue
        if (
            action.get("kind") in REQUIREMENTS_CLARIFICATION_REFRESH_ACTION_KINDS
            and action.get("status") in {"executed", "validated"}
            and action.get("action_id") not in mutation_action_ids
        ):
            errors.append("executed_source_action_requires_mutation_result")

    accepted_current = [
        proposal for proposal in proposals
        if isinstance(proposal, dict) and proposal.get("decision") == "accepted_current"
    ]
    active_task_terminal_proposals = [
        proposal for proposal in proposals
        if isinstance(proposal, dict)
        and proposal.get("decision")
        in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_TERMINAL_DECISIONS
    ]
    active_task_classification_proposals = [
        proposal for proposal in proposals
        if isinstance(proposal, dict)
        and proposal.get("decision")
        in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_CLASSIFICATION_DECISIONS
    ]
    active_task_mechanism_proposals = [
        proposal for proposal in proposals
        if isinstance(proposal, dict)
        and proposal.get("decision")
        in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_MECHANISM_DECISIONS
    ]
    if invocation_kind == "active_task_scope_change" and typed_exit in {"clear", "new_task"}:
        if not proposals or len(active_task_terminal_proposals) != len(proposals):
            errors.append("active_task_clear_or_new_task_requires_final_scope_proposal_set")
        if typed_exit == "new_task" and not any(
            proposal.get("decision") == "new_task"
            for proposal in active_task_classification_proposals
        ):
            errors.append("active_task_new_task_requires_new_task_classification")
    if invocation_kind == "active_task_scope_change" and accepted_current:
        if invocation.get("resume_target") != "guru-active-task-planning-review":
            errors.append("active_task_current_scope_requires_planning_resume")
        accepted_digests = {proposal.get("proposal_digest") for proposal in accepted_current}
        if confirmation_status != "confirmed" or not accepted_digests.issubset(set(proposal_digests)):
            errors.append("active_task_current_scope_requires_exact_confirmation")
    if invocation_kind == "active_task_scope_change" and active_task_classification_proposals:
        classification_proposal_digests = [
            proposal.get("proposal_digest")
            for proposal in active_task_classification_proposals
        ]
        if (
            confirmation_status != "confirmed"
            or confirmation.get("confirmation_kind")
            != "exact_source_action_and_scope"
            or proposal_digests != classification_proposal_digests
            or any(
                proposal.get("confirmation_ref") is None
                for proposal in active_task_classification_proposals
            )
        ):
            errors.append("active_task_final_classification_requires_exact_user_decision")
        evidence = payload.get("active_task_evidence")
        trail = evidence.get("decision_trail") if isinstance(evidence, dict) else None
        requires_reentry_trail = typed_exit in {"clear", "new_task"}
        if requires_reentry_trail and not isinstance(trail, dict):
            errors.append("active_task_final_classification_requires_decision_trail")
        elif requires_reentry_trail:
            expected_decisions = [
                {
                    "proposal_id": proposal.get("proposal_id"),
                    "proposal_digest": proposal.get("proposal_digest"),
                    "decision": proposal.get("decision"),
                    "confirmation_ref": proposal.get("confirmation_ref"),
                }
                for proposal in active_task_classification_proposals
            ]
            if trail.get("proposal_decisions") != expected_decisions:
                errors.append("active_task_decision_trail_proposals_mismatch")
            trail_decision = trail.get("user_decision")
            if not isinstance(trail_decision, dict):
                errors.append("active_task_decision_trail_user_evidence_invalid")
            elif trail_decision != {
                "status": confirmation_status,
                "proposal_digests": proposal_digests,
                "confirmer": confirmation.get("confirmer"),
                "confirmed_at": confirmation.get("confirmed_at"),
                "evidence_summary": confirmation.get("evidence_summary"),
            }:
                errors.append("active_task_decision_trail_user_evidence_mismatch")
            if trail.get("planning_documents") != evidence.get("planning_documents"):
                errors.append("active_task_decision_trail_planning_mismatch")
            if trail.get("stale_downstream_evidence") != evidence.get("stale_downstream_evidence"):
                errors.append("active_task_decision_trail_stale_evidence_mismatch")
            if trail.get("review_evidence") != evidence.get("review_evidence"):
                errors.append("active_task_decision_trail_review_mismatch")
            if trail.get("reentry_owners") != evidence.get("reentry_owners"):
                errors.append("active_task_decision_trail_reentry_mismatch")
            if trail.get("interrupted_resume_target") != invocation.get("resume_target"):
                errors.append("active_task_decision_trail_resume_mismatch")
            context_before = trail.get("context_before_task_update_sha256")
            current_context = context.get("snapshot_sha256") if isinstance(context, dict) else None
            if context_before != current_context:
                errors.append("active_task_decision_trail_task_update_context_mismatch")
        elif trail is not None:
            errors.append("active_task_decision_trail_forbidden_before_reentry")

        github_action_kinds = {
            action.get("kind") for action in actions
            if isinstance(action, dict)
            and action.get("kind") in {"issue_comment", "issue_body_edit"}
        }
        task_update_actions = [
            action for action in actions
            if isinstance(action, dict)
            and action.get("kind") == "active_task_scope_update"
        ]
        if typed_exit == "refresh_context":
            if not github_action_kinds:
                errors.append("active_task_classification_refresh_requires_github_authority")
            if task_update_actions:
                errors.append("active_task_task_update_forbidden_before_context_refresh")
        elif typed_exit in {"clear", "new_task"}:
            if github_action_kinds or any(
                isinstance(mutation, dict)
                and mutation.get("kind") in {"issue_comment", "issue_body_edit"}
                for mutation in mutations
            ):
                errors.append("active_task_reentry_forbids_github_mutation")
            if len(task_update_actions) != 1:
                errors.append("active_task_final_classification_requires_task_update")
            elif task_update_actions[0].get("status") != "validated":
                errors.append("active_task_final_classification_requires_validated_task_update")
            elif (
                isinstance(trail, dict)
                and task_update_actions[0].get("preimage_sha256")
                != trail.get("context_before_task_update_sha256")
            ):
                errors.append("active_task_task_update_preimage_mismatch")

        errors.extend(
            requirements_clarification_active_task_action_confirmation_errors(
                payload
            )
        )

    if invocation_kind == "active_task_scope_change" and active_task_mechanism_proposals:
        if any(
            proposal.get("confirmation_ref") is not None
            or proposal.get("optional_mechanism_origin") is not True
            for proposal in active_task_mechanism_proposals
        ):
            errors.append("active_task_mechanism_disposition_shape_invalid")
        if not active_task_classification_proposals:
            evidence = payload.get("active_task_evidence")
            if confirmation_status != "not_required" or proposal_digests:
                errors.append("active_task_mechanism_only_forbids_confirmation")
            if not isinstance(evidence, dict):
                errors.append("active_task_mechanism_only_requires_task_evidence")
            elif evidence.get("decision_trail") is not None:
                errors.append("active_task_mechanism_only_forbids_decision_trail")
            if any(
                isinstance(action, dict) and action.get("kind") != "none"
                for action in actions
            ) or mutations:
                errors.append("active_task_mechanism_only_forbids_authority_mutation")

    gate = payload.get("ai_review_gate")
    gate_status = gate.get("status") if isinstance(gate, dict) else None
    if (
        not isinstance(gate, dict)
        or gate_status not in {"passed", "blocked"}
        or not isinstance(gate.get("reviewed_scope"), list)
        or not gate.get("reviewed_scope")
        or not isinstance(gate.get("load_bearing_conclusions"), list)
        or not gate.get("load_bearing_conclusions")
    ):
        errors.append("invalid_requirements_ai_review_gate")
    if (typed_exit == "blocked") != (gate_status == "blocked"):
        errors.append("requirements_blocked_gate_exit_mismatch")
    if gate_status == "passed" and any(
        isinstance(finding, dict) and finding.get("status") == "open"
        for finding in gate.get("findings", []) if isinstance(gate.get("findings"), list)
    ):
        errors.append("passed_requirements_gate_has_open_findings")

    if invocation_kind == "active_task_scope_change":
        if (
            typed_exit in {"clear", "new_task"}
            and active_task_terminal_proposals
        ):
            errors.extend(
                requirements_clarification_active_task_shape_errors(
                    root, payload, task_dir
                )
            )
        elif payload.get("active_task_evidence") is not None:
            errors.append("active_task_evidence_forbidden_before_classification_reentry")
    elif payload.get("active_task_evidence") is not None:
        errors.append("non_task_clarification_has_active_task_evidence")

    has_new_issue_draft = any(
        action.get("kind") == "new_issue_draft" and action.get("status") == "draft_ready"
        for action in actions if isinstance(action, dict)
    )
    has_refresh_action = any(
        action.get("kind") in REQUIREMENTS_CLARIFICATION_REFRESH_ACTION_KINDS
        and action.get("status") in {"executed", "validated"}
        for action in actions if isinstance(action, dict)
    )
    if has_new_issue_draft and typed_exit != "new_task":
        errors.append("new_issue_draft_requires_new_task_exit")
    if has_refresh_action and typed_exit != "refresh_context":
        errors.append("source_action_requires_refresh_context")
    if mutations and typed_exit != "refresh_context":
        errors.append("mutation_results_require_refresh_context")
    if typed_exit in {"clear", "needs_context"} and any(
        action.get("kind") in {"proposed_draft_update", "new_issue_draft"}
        for action in actions if isinstance(action, dict)
    ):
        errors.append("draft_source_action_forbidden_for_exit")

    if typed_exit == "clear":
        if open_questions:
            errors.append("clear_requires_zero_open_questions")
        if any(question.get("status") == "pending" for question in repository_questions if isinstance(question, dict)):
            errors.append("clear_requires_repository_questions_resolved")
        if not isinstance(context, dict) or context.get("status") != "current":
            errors.append("clear_requires_current_context")
        if any(proposal.get("decision") == "pending" for proposal in proposals if isinstance(proposal, dict)):
            errors.append("clear_forbids_pending_scope_proposals")
        if any(action.get("status") == "pending" for action in actions if isinstance(action, dict)):
            errors.append("clear_forbids_pending_source_actions")
        if any(
            action.get("kind") in {"issue_comment", "issue_body_edit"}
            for action in actions if isinstance(action, dict)
        ):
            errors.append("clear_forbids_source_mutation_actions")
        if mutations:
            errors.append("clear_forbids_unrefreshed_mutations")
        if payload.get("error") is not None:
            errors.append("clear_forbids_error")
    elif typed_exit == "needs_context":
        if not isinstance(context, dict) or context.get("status") != "missing":
            errors.append("needs_context_requires_missing_context")
    elif typed_exit == "refresh_context":
        if not mutations and (not isinstance(context, dict) or context.get("status") != "stale"):
            errors.append("refresh_context_requires_stale_or_mutated_authority")
    elif typed_exit == "new_task":
        if not any(action.get("kind") == "new_issue_draft" and action.get("status") == "draft_ready" for action in actions if isinstance(action, dict)):
            errors.append("new_task_requires_reviewed_issue_draft")
        if payload.get("error") is not None:
            errors.append("new_task_forbids_error")
    elif typed_exit == "blocked" and not isinstance(payload.get("error"), dict):
        errors.append("blocked_requirements_requires_error")

    expected_identity = requirements_clarification_content_identity(payload)
    if payload.get("content_identity") != expected_identity:
        errors.append("requirements_clarification_content_identity_mismatch")
    return context_sort(errors)


def requirements_clarification_active_task_shape_errors(
    root: Path,
    payload: dict[str, Any],
    task_dir: Path | None,
) -> list[str]:
    evidence = payload.get("active_task_evidence")
    if task_dir is None or not isinstance(evidence, dict):
        return ["active_task_evidence_required"]
    errors: list[str] = []
    expected_locator = task_dir.relative_to(root).as_posix()
    if evidence.get("task_locator") != expected_locator:
        errors.append("active_task_locator_mismatch")
    target = payload.get("review_target")
    if not isinstance(target, dict) or evidence.get("github_authority_facts_sha256") != target.get("facts_sha256"):
        errors.append("active_task_github_authority_mismatch")
    ledger = evidence.get("ledger")
    expected_ledger = f"{expected_locator}/issue-scope-ledger.json"
    if not isinstance(ledger, dict) or ledger.get("path") != expected_ledger or not requirements_clarification_is_sha256(ledger.get("content_sha256")):
        errors.append("active_task_ledger_binding_invalid")
    planning = evidence.get("planning_documents")
    expected_planning = {
        f"{expected_locator}/prd.md",
        f"{expected_locator}/design.md",
        f"{expected_locator}/implement.md",
    }
    planning_paths = {
        item.get("path") for item in planning if isinstance(item, dict)
    } if isinstance(planning, list) else set()
    if planning_paths != expected_planning or len(planning or []) != 3:
        errors.append("active_task_planning_binding_invalid")
    stale = evidence.get("stale_downstream_evidence")
    if (
        not isinstance(stale, dict)
        or set(stale)
        != {"planning_approval_sha256", "phase2_check_sha256", "branch_review_sha256"}
    ):
        errors.append("active_task_stale_evidence_invalid")
    elif not requirements_clarification_is_sha256(stale.get("planning_approval_sha256")):
        errors.append("active_task_planning_approval_evidence_required")
    review = evidence.get("review_evidence")
    branch_review_sha = stale.get("branch_review_sha256") if isinstance(stale, dict) else None
    review_path = task_dir / "review-gate.json"
    review_started = review_path.exists()
    if not isinstance(review, dict) or set(review) != {"status", "artifact"}:
        errors.append("active_task_review_evidence_invalid")
    elif review.get("status") == "not_started":
        if review.get("artifact") is not None or branch_review_sha is not None:
            errors.append("active_task_review_evidence_mismatch")
        if review_started:
            errors.append("active_task_review_started_requires_stale")
    elif review.get("status") == "current":
        errors.append("active_task_review_current_forbidden_during_reentry")
    elif review.get("status") == "stale":
        artifact = review.get("artifact")
        expected_review_path = f"{expected_locator}/review-gate.json"
        if (
            not isinstance(artifact, dict)
            or artifact.get("path") != expected_review_path
            or artifact.get("content_sha256") != branch_review_sha
            or not requirements_clarification_is_sha256(branch_review_sha)
        ):
            errors.append("active_task_review_evidence_mismatch")
        if not review_started:
            errors.append("active_task_review_stale_requires_existing_artifact")
    else:
        errors.append("active_task_review_evidence_invalid")
    trail = evidence.get("decision_trail")
    if trail is not None:
        required_trail_keys = {
            "trail_id", "proposal_decisions", "user_decision",
            "github_authority", "context_before_task_update_sha256",
            "planning_documents", "stale_downstream_evidence",
            "review_evidence", "reentry_owners", "interrupted_resume_target",
        }
        if set(trail) != required_trail_keys:
            errors.append("active_task_decision_trail_shape_invalid")
        if not requirements_clarification_nonempty(trail.get("trail_id")):
            errors.append("active_task_decision_trail_shape_invalid")
        if not requirements_clarification_is_sha256(
            trail.get("context_before_task_update_sha256")
        ):
            errors.append("active_task_decision_trail_shape_invalid")
        authority = trail.get("github_authority")
        if (
            not isinstance(authority, dict)
            or set(authority) != {"kind", "url", "content_sha256", "updated_at"}
            or authority.get("kind") not in {"issue_comment", "issue_body"}
            or not requirements_clarification_nonempty(authority.get("url"))
            or not requirements_clarification_is_sha256(authority.get("content_sha256"))
        ):
            errors.append("active_task_decision_trail_github_authority_invalid")
        else:
            try:
                parse_iso_datetime(
                    authority.get("updated_at"),
                    "active-task GitHub authority updated_at",
                )
            except WorkflowError:
                errors.append("active_task_decision_trail_github_authority_invalid")
    reentry = evidence.get("reentry_owners")
    if not isinstance(reentry, list) or set(reentry) != REQUIREMENTS_CLARIFICATION_REENTRY_OWNERS or len(reentry) != 3:
        errors.append("active_task_reentry_owners_invalid")
    return errors


def requirements_clarification_file_digest(path: Path) -> str | None:
    try:
        return hashlib.sha256(path.read_bytes()).hexdigest()
    except OSError:
        return None


def requirements_clarification_live_issue_errors(
    root: Path,
    target: dict[str, Any],
) -> list[str]:
    if target.get("kind") != "issue":
        return []
    number = target.get("issue_number")
    if not isinstance(number, int):
        return ["requirements_target_issue_invalid"]
    facts, issue_error = context_read_live_issue(root, str(target.get("repo") or ""), number)
    if issue_error is not None or facts is None:
        return ["requirements_target_issue_unreadable"]
    expected = {
        "kind": "issue",
        "repo": target.get("repo"),
        "issue_number": facts["number"],
        "url": facts["url"],
        "state": facts["state"],
        "updated_at": facts["updated_at"],
        "body_sha256": facts["body_sha256"],
    }
    expected["facts_sha256"] = context_digest(expected)
    return [] if target == expected else ["requirements_target_issue_stale"]


def requirements_clarification_decision_authority_live_errors(
    root: Path,
    target: Any,
    authority: Any,
) -> list[str]:
    if not isinstance(target, dict) or target.get("kind") != "issue":
        return ["active_task_decision_authority_requires_issue"]
    if not isinstance(authority, dict):
        return ["active_task_decision_authority_invalid"]
    repo = str(target.get("repo") or "")
    number = target.get("issue_number")
    if not isinstance(number, int) or number <= 0:
        return ["active_task_decision_authority_requires_issue"]
    if authority.get("kind") == "issue_body":
        facts, issue_error = context_read_live_issue(root, repo, number)
        if (
            issue_error is not None
            or facts is None
            or authority.get("url") != facts.get("url")
            or authority.get("content_sha256") != facts.get("body_sha256")
            or authority.get("updated_at") != facts.get("updated_at")
        ):
            return ["active_task_decision_authority_body_stale"]
        return []
    if authority.get("kind") != "issue_comment":
        return ["active_task_decision_authority_invalid"]
    url = str(authority.get("url") or "")
    match = re.fullmatch(
        rf"https://github\.com/{re.escape(repo)}/issues/{number}#issuecomment-([1-9][0-9]*)",
        url,
    )
    if match is None:
        return ["active_task_decision_authority_comment_invalid"]
    comment_id = int(match.group(1))
    proc = run(
        ["gh", "api", f"repos/{repo}/issues/comments/{comment_id}"],
        cwd=root,
        check=False,
    )
    if proc.returncode != 0:
        return ["active_task_decision_authority_comment_unreadable"]
    try:
        comment = json.loads(proc.stdout)
    except json.JSONDecodeError:
        return ["active_task_decision_authority_comment_unreadable"]
    if (
        not isinstance(comment, dict)
        or comment.get("id") != comment_id
        or comment.get("html_url") != url
        or authority.get("updated_at") != comment.get("updated_at")
        or authority.get("content_sha256")
        != hashlib.sha256(str(comment.get("body") or "").encode("utf-8")).hexdigest()
    ):
        return ["active_task_decision_authority_comment_stale"]
    return []


def requirements_clarification_active_task_live_errors(
    root: Path,
    payload: dict[str, Any],
    task_dir: Path | None,
) -> list[str]:
    if task_dir is None:
        return []
    evidence = payload.get("active_task_evidence")
    if not isinstance(evidence, dict):
        return ["active_task_evidence_required"]
    errors: list[str] = []
    planning_approval_payload: dict[str, Any] = {}
    try:
        _, planning_approval_payload, planning_approval_errors = validate_planning_approval(
            root,
            task_dir,
        )
    except WorkflowError:
        planning_approval_errors = ["planning approval unavailable"]
    if planning_approval_errors:
        errors.append("active_task_planning_approval_invalid")
    ledger_payload: Any = None
    file_rows: list[dict[str, Any]] = []
    ledger = evidence.get("ledger")
    if isinstance(ledger, dict):
        file_rows.append(ledger)
    planning = evidence.get("planning_documents")
    if isinstance(planning, list):
        file_rows.extend(row for row in planning if isinstance(row, dict))
    reviewed_artifacts = planning_approval_payload.get("reviewed_artifacts")
    normalized_reviewed = [
        normalized_digest_entry(root, task_dir, item)
        for item in reviewed_artifacts
    ] if isinstance(reviewed_artifacts, list) else []
    reviewed_by_path = {
        str(item.get("path")): item
        for item in normalized_reviewed
        if isinstance(item, dict)
    }
    expected_planning_from_approval = [
        {
            "path": repo_relative(root, task_dir / name),
            "content_sha256": reviewed_by_path.get(
                repo_relative(root, task_dir / name),
                {},
            ).get("sha256"),
        }
        for name in DEFAULT_PLANNING_ARTIFACTS
    ]
    if planning != expected_planning_from_approval:
        errors.append("active_task_planning_approval_binding_mismatch")
    for row in file_rows:
        path_value = row.get("path")
        if not isinstance(path_value, str):
            errors.append("active_task_file_binding_invalid")
            continue
        try:
            path = root / context_query_path_shape(path_value)
        except WorkflowError:
            errors.append("active_task_file_binding_invalid")
            continue
        if requirements_clarification_file_digest(path) != row.get("content_sha256"):
            errors.append("active_task_file_stale")
        if row is ledger:
            try:
                ledger_payload = json.loads(path.read_text(encoding="utf-8"))
            except (OSError, UnicodeError, json.JSONDecodeError):
                errors.append("active_task_ledger_unreadable")
    required_ledger_keys = {
        "primary_issue", "close_issues", "related_issues", "followup_issues",
    }
    if not isinstance(ledger_payload, dict) or not required_ledger_keys.issubset(ledger_payload):
        errors.append("active_task_ledger_structure_invalid")
    trail = evidence.get("decision_trail")
    if isinstance(trail, dict):
        scope_decisions = ledger_payload.get("scope_decisions") if isinstance(ledger_payload, dict) else None
        matching = [
            item for item in scope_decisions
            if isinstance(item, dict) and item.get("trail_id") == trail.get("trail_id")
        ] if isinstance(scope_decisions, list) else []
        if len(matching) != 1 or matching[0] != trail:
            errors.append("active_task_decision_trail_ledger_mismatch")
        errors.extend(
            requirements_clarification_decision_authority_live_errors(
                root,
                payload.get("review_target"),
                trail.get("github_authority"),
            )
        )
    stale = evidence.get("stale_downstream_evidence")
    if isinstance(stale, dict):
        stale_files = {
            "planning_approval_sha256": task_dir / PLANNING_APPROVAL_ARTIFACT,
            "phase2_check_sha256": task_dir / PHASE2_CHECK_ARTIFACT,
            "branch_review_sha256": task_dir / "review-gate.json",
        }
        for field, path in stale_files.items():
            expected = stale.get(field)
            actual = requirements_clarification_file_digest(path)
            if expected is None and actual is not None:
                errors.append("active_task_stale_evidence_unbound")
            elif expected is not None and actual != expected:
                errors.append("active_task_stale_evidence_drift")
    review = evidence.get("review_evidence")
    review_path = task_dir / "review-gate.json"
    review_started = review_path.exists()
    review_status = review.get("status") if isinstance(review, dict) else None
    if review_started:
        if review_status != "stale":
            errors.append("active_task_review_started_requires_stale")
        artifact = review.get("artifact") if isinstance(review, dict) else None
        if isinstance(artifact, dict):
            try:
                bound_review_path = root / context_query_path_shape(
                    str(artifact.get("path") or "")
                )
            except WorkflowError:
                errors.append("active_task_review_evidence_invalid")
            else:
                if (
                    bound_review_path != review_path
                    or requirements_clarification_file_digest(bound_review_path)
                    != artifact.get("content_sha256")
                ):
                    errors.append("active_task_review_evidence_stale")
        else:
            errors.append("active_task_review_evidence_invalid")
    elif review_status != "not_started" or (
        isinstance(review, dict) and review.get("artifact") is not None
    ):
        errors.append("active_task_review_not_started_required")
    context = payload.get("context_evidence")
    context_path = task_dir / "context-discovery.json"
    if isinstance(context, dict) and context.get("status") == "current":
        if not context_path.is_file() or context_path.is_symlink():
            errors.append("requirements_context_snapshot_unavailable")
        else:
            try:
                snapshot = json.loads(context_path.read_text(encoding="utf-8"))
            except (OSError, UnicodeError, json.JSONDecodeError):
                errors.append("requirements_context_snapshot_unreadable")
            else:
                identity = snapshot.get("snapshot_identity") if isinstance(snapshot, dict) else None
                if not isinstance(identity, dict) or identity.get("snapshot_sha256") != context.get("snapshot_sha256"):
                    errors.append("requirements_context_snapshot_stale")
                trail = evidence.get("decision_trail")
                authority = trail.get("github_authority") if isinstance(trail, dict) else None
                if isinstance(authority, dict):
                    try:
                        context_generated_at = parse_iso_datetime(
                            snapshot.get("generated_at") if isinstance(snapshot, dict) else None,
                            "active-task context generated_at",
                        )
                    except WorkflowError:
                        errors.append("active_task_context_generated_at_invalid")
                    else:
                        try:
                            authority_updated_at = parse_iso_datetime(
                                authority.get("updated_at"),
                                "active-task GitHub authority updated_at",
                            )
                        except WorkflowError:
                            errors.append("active_task_decision_authority_updated_at_invalid")
                        else:
                            if context_generated_at < authority_updated_at:
                                errors.append("active_task_context_predates_decision_authority")
    return context_sort(errors)


def requirements_clarification_live_mutation_errors(
    root: Path,
    payload: dict[str, Any],
    task_dir: Path | None,
) -> list[str]:
    actions = payload.get("source_actions")
    mutations = payload.get("mutation_results")
    if not isinstance(actions, list) or not isinstance(mutations, list):
        return ["invalid_mutation_results"]
    action_by_id = {
        str(action.get("action_id")): action
        for action in actions if isinstance(action, dict)
    }
    errors: list[str] = []
    for mutation in mutations:
        if not isinstance(mutation, dict):
            continue
        action = action_by_id.get(str(mutation.get("action_id")))
        if not isinstance(action, dict):
            continue
        kind = mutation.get("kind")
        if kind == "proposed_draft_update":
            continue
        if kind == "active_task_scope_update":
            evidence = payload.get("active_task_evidence")
            expected_locator = (
                task_dir.relative_to(root).as_posix() if task_dir is not None else None
            )
            if (
                task_dir is None
                or action.get("target") != {"task_locator": expected_locator}
                or action.get("payload")
                != requirements_clarification_active_task_payload_projection(evidence)
                or mutation.get("url") is not None
                or mutation.get("state") != "task_local"
                or mutation.get("updated_at") is not None
                or mutation.get("content_sha256") != context_digest(evidence)
            ):
                errors.append("active_task_scope_mutation_live_binding_invalid")
            continue
        target = action.get("target")
        if not isinstance(target, dict):
            errors.append("mutation_target_invalid")
            continue
        repo = target.get("repo")
        number = target.get("issue_number")
        if not isinstance(repo, str) or not isinstance(number, int) or number <= 0:
            errors.append("mutation_target_invalid")
            continue
        issue_facts, issue_error = context_read_live_issue(root, repo, number)
        if issue_error is not None or issue_facts is None:
            errors.append("mutation_live_issue_unreadable")
            continue
        if kind == "issue_body_edit":
            action_payload = action.get("payload")
            expected_content_sha = (
                hashlib.sha256(action_payload["body"].encode("utf-8")).hexdigest()
                if isinstance(action_payload, dict)
                and requirements_clarification_nonempty(action_payload.get("body"))
                else None
            )
            if (
                mutation.get("url") != issue_facts["url"]
                or mutation.get("state") != issue_facts["state"]
                or mutation.get("updated_at") != issue_facts["updated_at"]
                or mutation.get("content_sha256") != issue_facts["body_sha256"]
                or mutation.get("content_sha256") != expected_content_sha
            ):
                errors.append("mutation_live_body_payload_mismatch")
            continue
        if kind != "issue_comment":
            errors.append("mutation_kind_invalid")
            continue
        url = str(mutation.get("url") or "")
        match = re.fullmatch(
            rf"https://github\.com/{re.escape(repo)}/issues/{number}#issuecomment-([1-9][0-9]*)",
            url,
        )
        if match is None:
            errors.append("mutation_comment_url_invalid")
            continue
        comment_id = int(match.group(1))
        proc = run(
            ["gh", "api", f"repos/{repo}/issues/comments/{comment_id}"],
            cwd=root,
            check=False,
        )
        if proc.returncode != 0:
            errors.append("mutation_live_comment_unreadable")
            continue
        try:
            comment = json.loads(proc.stdout)
        except json.JSONDecodeError:
            errors.append("mutation_live_comment_unreadable")
            continue
        if (
            not isinstance(comment, dict)
            or comment.get("id") != comment_id
            or comment.get("html_url") != url
            or mutation.get("updated_at") != comment.get("updated_at")
            or mutation.get("state") != issue_facts["state"]
            or mutation.get("content_sha256")
            != hashlib.sha256(str(comment.get("body") or "").encode("utf-8")).hexdigest()
            or mutation.get("content_sha256")
            != hashlib.sha256(str((action.get("payload") or {}).get("body") or "").encode("utf-8")).hexdigest()
        ):
            errors.append("mutation_live_comment_payload_mismatch")
    return context_sort(errors)


def requirements_clarification_live_errors(
    root: Path,
    payload: dict[str, Any],
    task_dir: Path | None,
) -> list[str]:
    target = payload.get("review_target")
    errors = requirements_clarification_live_issue_errors(root, target) if isinstance(target, dict) else ["requirements_target_invalid"]
    errors.extend(
        requirements_clarification_active_task_action_confirmation_errors(payload)
    )
    proposals = payload.get("scope_proposals")
    has_active_task_terminal_reentry = (
        task_dir is not None
        and payload.get("typed_exit") in {"clear", "new_task"}
        and isinstance(proposals, list)
        and bool(proposals)
        and all(
            isinstance(proposal, dict)
            and proposal.get("decision")
            in REQUIREMENTS_CLARIFICATION_ACTIVE_TASK_TERMINAL_DECISIONS
            for proposal in proposals
        )
    )
    if has_active_task_terminal_reentry:
        errors.extend(
            requirements_clarification_active_task_live_errors(
                root, payload, task_dir
            )
        )
    errors.extend(requirements_clarification_live_mutation_errors(root, payload, task_dir))
    return context_sort(errors)


def requirements_clarification_typed_exit_live_errors(
    payload: dict[str, Any],
    live_errors: list[str],
) -> list[str]:
    if payload.get("typed_exit") != "refresh_context":
        return context_sort(live_errors)
    allowed_refresh_drift = {
        "requirements_target_issue_stale",
        "requirements_context_snapshot_stale",
    }
    fatal = [code for code in live_errors if code not in allowed_refresh_drift]
    if fatal:
        return context_sort(fatal)
    has_mutation = bool(payload.get("mutation_results"))
    context = payload.get("context_evidence")
    has_stale_context = isinstance(context, dict) and context.get("status") == "stale"
    if not live_errors and not has_mutation and not has_stale_context:
        return ["refresh_context_requires_observed_drift"]
    return []


def contract_wording_scope_from_args(
    root: Path,
    args: argparse.Namespace,
    profile: str,
    mode: str,
) -> tuple[dict[str, Any], dict[str, str], Path | None]:
    task_dir: Path | None = None
    if profile == "planning_artifacts":
        task_dir = resolve_task_dir(root, getattr(args, "task", None))
        config = load_config(root)
        task_context = load_task_start_context(task_dir, config)
        assert_workspace_boundary(root, config, task_context, task_dir)
    elif getattr(args, "task", None):
        raise WorkflowError("Only planning_artifacts accepts --task.", exit_code=2)
    scope, contents = contract_wording_build_scope(
        root,
        profile,
        mode,
        task_dir=task_dir,
        explicit_paths=list(getattr(args, "path", None) or []),
        change_request_input=getattr(args, "change_request_input", None),
    )
    return scope, contents, task_dir


def cmd_record_contract_wording_review(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    profile = str(args.profile or "").strip()
    mode = str(args.mode or "").strip()
    scope, contents, task_dir = contract_wording_scope_from_args(root, args, profile, mode)
    replace_stale = bool(getattr(args, "replace_stale", False))
    supersede_facts = str(
        getattr(args, "supersede_reentry_facts_sha256", None) or ""
    ).strip()
    if replace_stale and supersede_facts:
        raise WorkflowError(
            "Stale replacement and current re-entry supersession are mutually exclusive.",
            exit_code=2,
            payload={"error_codes": ["contract_wording_replacement_modes_conflict"]},
        )
    if (replace_stale or supersede_facts) and (
        profile != "planning_artifacts" or bool(getattr(args, "scan_only", False))
    ):
        raise WorkflowError(
            "Contract wording replacement is available only while recording task-local planning_artifacts evidence.",
            exit_code=2,
            payload={"error_codes": ["contract_wording_replacement_profile_invalid"]},
        )
    scan = scan_contract_wording(scope, contents)
    if args.scan_only:
        if getattr(args, "input", None):
            raise WorkflowError("--scan-only does not accept semantic --input.", exit_code=2)
        return {
            "status": "scanned",
            "skill_id": CONTRACT_WORDING_SKILL_ID,
            "profile": profile,
            "mode": mode,
            "vocabulary_version": CONTRACT_WORDING_VOCABULARY_VERSION,
            "scope": scope,
            "scan": scan,
        }
    if getattr(args, "input", None) == "-" and getattr(args, "change_request_input", None) == "-":
        raise WorkflowError("Semantic input and change_request scope cannot both read stdin.", exit_code=2)
    authored = contract_wording_read_input(root, getattr(args, "input", None), "contract wording recorder")
    result = contract_wording_derive_result(profile, mode, scope, scan, authored)
    errors = contract_wording_structural_errors(root, result, scope, scan)
    if errors:
        raise WorkflowError(
            "Contract wording review result validation failed.",
            exit_code=2,
            payload={"error_codes": errors},
        )
    if profile != "planning_artifacts":
        return result

    assert task_dir is not None
    target = task_dir / CONTRACT_WORDING_EVIDENCE_ARTIFACT
    trackability = contract_wording_trackability_errors(root, target)
    if trackability:
        raise WorkflowError(
            "Contract wording evidence target must be trackable by Git.",
            exit_code=2,
            payload={"error_codes": trackability},
        )
    if not target.exists() and (replace_stale or supersede_facts):
        raise WorkflowError(
            "Contract wording replacement requires an existing task-local artifact.",
            exit_code=2,
            payload={"error_codes": ["contract_wording_replacement_target_missing"]},
        )
    if target.exists():
        existing = read_json(target)
        if existing != result and not replace_stale and not supersede_facts:
            raise WorkflowError(
                "Existing contract-wording-review.json differs; use --replace-stale for stale evidence or --supersede-reentry-facts-sha256 after a current non-pass re-entry.",
                exit_code=2,
            )
        if replace_stale or supersede_facts:
            existing_errors = contract_wording_structural_errors(root, existing, scope, scan)
            if replace_stale:
                if not existing_errors:
                    raise WorkflowError(
                        "Current contract-wording-review.json cannot be replaced as stale.",
                        exit_code=2,
                    )
            else:
                supersession_errors: list[str] = []
                if re.fullmatch(r"[0-9a-f]{64}", supersede_facts) is None:
                    supersession_errors.append(
                        "contract_wording_reentry_superseded_facts_invalid"
                    )
                if existing == result:
                    supersession_errors.append(
                        "contract_wording_reentry_requires_new_result"
                    )
                if existing_errors:
                    supersession_errors.append(
                        "contract_wording_reentry_requires_current_evidence"
                    )
                if (
                    existing.get("profile") != result.get("profile")
                    or existing.get("mode") != result.get("mode")
                ):
                    supersession_errors.append(
                        "contract_wording_reentry_profile_mismatch"
                    )
                if existing.get("facts_sha256") != supersede_facts:
                    supersession_errors.append(
                        "contract_wording_reentry_superseded_facts_mismatch"
                    )
                if existing.get("typed_exit") == "pass":
                    supersession_errors.append(
                        "contract_wording_current_pass_protected"
                    )
                elif existing.get("typed_exit") not in {"content_changed", "blocked"}:
                    supersession_errors.append(
                        "contract_wording_reentry_requires_nonpass_exit"
                    )
                if supersession_errors:
                    raise WorkflowError(
                        "Contract wording same-profile re-entry supersession is invalid.",
                        exit_code=2,
                        payload={"error_codes": context_sort(supersession_errors)},
                    )
    write_json(target, result)
    persisted = read_json(target)
    if persisted != result:
        raise WorkflowError("Persisted contract wording evidence identity mismatch.", exit_code=2)
    trackability = contract_wording_trackability_errors(root, target)
    if trackability:
        raise WorkflowError(
            "Contract wording evidence target must remain trackable by Git.",
            exit_code=2,
            payload={"error_codes": trackability},
        )
    return result


def cmd_check_contract_wording_review(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    input_value = getattr(args, "input", None)
    if input_value:
        payload = contract_wording_read_input(root, input_value, "contract wording checker")
    elif getattr(args, "task", None):
        task_dir = resolve_task_dir(root, args.task)
        payload = read_json(task_dir / CONTRACT_WORDING_EVIDENCE_ARTIFACT)
    else:
        raise WorkflowError("check-contract-wording-review requires --input or --task.", exit_code=2)
    profile = str(payload.get("profile") or "")
    mode = str(payload.get("mode") or "")
    scope, contents, task_dir = contract_wording_scope_from_args(root, args, profile, mode)
    scan = scan_contract_wording(scope, contents)
    errors = contract_wording_structural_errors(root, payload, scope, scan)
    if task_dir is not None:
        expected_target = task_dir / CONTRACT_WORDING_EVIDENCE_ARTIFACT
        if not input_value or Path(input_value).name == CONTRACT_WORDING_EVIDENCE_ARTIFACT:
            errors.extend(contract_wording_trackability_errors(root, expected_target))
    if args.expected_facts_sha256 and args.expected_facts_sha256 != payload.get("facts_sha256"):
        errors.append("expected_contract_wording_facts_mismatch")
    if errors:
        raise WorkflowError(
            "Contract wording review freshness validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(errors)},
        )
    return {
        "status": "passed",
        "skill_id": CONTRACT_WORDING_SKILL_ID,
        "profile": profile,
        "typed_exit": payload["typed_exit"],
        "scope_sha256": payload["scope"]["scope_sha256"],
        "scan_sha256": payload["scan"]["scan_sha256"],
        "facts_sha256": payload["facts_sha256"],
    }


def cmd_record_requirements_clarification(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    payload, task_dir = requirements_clarification_payload_from_args(root, args)
    if payload.get("mode") != args.mode:
        raise WorkflowError("requirements clarification mode does not match recorder mode.", exit_code=2)
    result = derive_requirements_clarification_result(payload)
    structural = requirements_clarification_structural_errors(root, result, task_dir)
    if structural:
        raise WorkflowError(
            "Requirements clarification result validation failed.",
            exit_code=2,
            payload={"error_codes": structural},
        )
    live = requirements_clarification_live_errors(root, result, task_dir)
    errors = requirements_clarification_typed_exit_live_errors(result, live)
    if errors:
        raise WorkflowError(
            "Requirements clarification result freshness validation failed.",
            exit_code=2,
            payload={"error_codes": errors},
        )
    return result


def cmd_check_requirements_clarification(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    payload, task_dir = requirements_clarification_payload_from_args(root, args)
    structural = requirements_clarification_structural_errors(root, payload, task_dir)
    if structural:
        raise WorkflowError(
            "Requirements clarification result validation failed.",
            exit_code=2,
            payload={"error_codes": structural},
        )
    live = requirements_clarification_live_errors(root, payload, task_dir)
    errors = requirements_clarification_typed_exit_live_errors(payload, live)
    identity = payload.get("content_identity")
    actual = identity.get("result_sha256") if isinstance(identity, dict) else None
    if args.expected_result_sha256 and args.expected_result_sha256 != actual:
        errors.append("expected_requirements_clarification_result_mismatch")
    if errors:
        raise WorkflowError(
            "Requirements clarification result freshness validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(errors)},
        )
    return {
        "status": "passed",
        "typed_exit": payload["typed_exit"],
        "target_sha256": payload["content_identity"]["target_sha256"],
        "context_sha256": payload["content_identity"]["context_sha256"],
        "scope_sha256": payload["content_identity"]["scope_sha256"],
        "action_sha256": payload["content_identity"]["action_sha256"],
        "result_sha256": payload["content_identity"]["result_sha256"],
    }


def change_request_review_schema(root: Path) -> dict[str, Any]:
    candidates = [
        root / ".trellis/guru-team/skills/packages/guru-review-change-request/schemas/change-request-review.schema.json",
        root / "trellis/skills/guru-team/packages/guru-review-change-request/schemas/change-request-review.schema.json",
    ]
    runtime_path = Path(__file__).resolve()
    if len(runtime_path.parents) > 2:
        candidates.append(
            runtime_path.parents[2]
            / "skills/packages/guru-review-change-request/schemas/change-request-review.schema.json"
        )
    if len(runtime_path.parents) > 4:
        candidates.append(
            runtime_path.parents[4]
            / "skills/guru-team/packages/guru-review-change-request/schemas/change-request-review.schema.json"
        )
    schema_path = next(
        (path for path in candidates if path.is_file() and not path.is_symlink()),
        None,
    )
    if schema_path is None:
        raise WorkflowError(
            "Change request review schema is missing from the compatible Guru Team runtime.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_schema_unavailable"]},
        )
    errors: list[str] = []
    schema = skill_read_json(schema_path, "change request review schema", errors)
    if (
        errors
        or schema is None
        or schema.get("$schema") != SKILL_SCHEMA_DIALECT
        or schema.get("$id") != CHANGE_REQUEST_REVIEW_SCHEMA_ID
    ):
        raise WorkflowError(
            "Change request review schema identity is invalid.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_schema_unavailable"]},
        )
    return schema


def change_request_review_read_input(
    root: Path,
    value: str | None,
    label: str,
) -> dict[str, Any]:
    if not value:
        raise WorkflowError(f"{label} requires an input JSON object.", exit_code=2)
    return contract_wording_read_input(root, value, label)


def change_request_review_sha256(value: Any) -> str | None:
    return value if isinstance(value, str) and re.fullmatch(r"[0-9a-f]{64}", value) else None


def change_request_review_scope_hashes(
    scope: dict[str, Any],
) -> tuple[str | None, str | None, str | None]:
    items = scope.get("items") if isinstance(scope, dict) else None
    if not isinstance(items, list):
        return None, None, None
    title_hash: str | None = None
    body_hash: str | None = None
    for item in items:
        if not isinstance(item, dict):
            continue
        field = item.get("field")
        if field == "title":
            title_hash = change_request_review_sha256(item.get("content_sha256"))
        elif field == "body":
            body_hash = change_request_review_sha256(item.get("content_sha256"))
    if title_hash is None or body_hash is None:
        return title_hash, body_hash, None
    return title_hash, body_hash, context_digest({
        "title_sha256": title_hash,
        "body_sha256": body_hash,
    })


def change_request_review_request_authority_projection(
    repo: Any,
    source: Any,
    body_sha256: Any,
) -> dict[str, Any] | None:
    if (
        normalize_github_repository(repo) != repo
        or not isinstance(source, dict)
        or source.get("kind") != "draft"
        or change_request_review_sha256(body_sha256) is None
    ):
        return None
    authority = {
        "kind": "draft",
        "repo": repo,
        "issue_number": None,
        "url": None,
        "state": "draft",
        "updated_at": None,
        "body_sha256": body_sha256,
    }
    return requirements_clarification_review_target_projection(authority)


def change_request_review_target_identity_projection(
    target: dict[str, Any],
) -> dict[str, Any]:
    common = {
        "kind": target.get("kind"),
        "repo": target.get("repo"),
        "title_sha256": target.get("title_sha256"),
        "body_sha256": target.get("body_sha256"),
    }
    if target.get("kind") == "existing_issue":
        return {
            **common,
            "issue_number": target.get("issue_number"),
            "url": target.get("url"),
            "updated_at": target.get("updated_at"),
        }
    if target.get("kind") == "proposed_draft":
        return {
            **common,
            "draft_id": target.get("draft_id"),
            "source_request_sha256": target.get("source_request_sha256"),
        }
    return {
        **common,
        "caller_locator": target.get("caller_locator"),
        "request_id": target.get("request_id"),
        "source_request_sha256": target.get("source_request_sha256"),
    }


def change_request_review_normalize_target(
    root: Path,
    raw_target: Any,
    change_request_input: str,
    mode: str,
) -> tuple[dict[str, Any], dict[str, Any], dict[str, str]]:
    if not isinstance(raw_target, dict):
        raise WorkflowError(
            "Change request review target must be an object.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_target_invalid"]},
        )
    source = change_request_review_read_input(
        root,
        change_request_input,
        "change request review target source",
    )
    scope, contents = contract_wording_build_scope(
        root,
        "change_request",
        mode,
        change_request_input=change_request_input,
    )
    title_hash, body_hash, content_hash = change_request_review_scope_hashes(scope)
    if title_hash is None or body_hash is None or content_hash is None:
        raise WorkflowError(
            "Change request review target scope is incomplete.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_target_scope_incomplete"]},
        )
    kind = raw_target.get("kind")
    repo = raw_target.get("repo")
    if normalize_github_repository(repo) != repo:
        raise WorkflowError(
            "Change request review repository identity is invalid.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_target_repo_invalid"]},
        )
    base_keys = {"kind", "repo", "title_sha256", "body_sha256"}
    errors: list[str] = []
    target: dict[str, Any]
    if kind == "existing_issue":
        expected_keys = base_keys | {"issue_number", "url", "updated_at"}
        issue_number = raw_target.get("issue_number")
        expected_url = (
            f"https://github.com/{repo}/issues/{issue_number}"
            if is_strict_int(issue_number) and int(issue_number) > 0
            else None
        )
        source_identity = str(scope.get("identity") or "").removeprefix("change_request:")
        scope_items = scope.get("items") if isinstance(scope.get("items"), list) else []
        source_updated = next(
            (
                item.get("updated_at")
                for item in scope_items
                if isinstance(item, dict) and item.get("field") == "title"
            ),
            None,
        )
        if (
            source.get("kind") != "issue"
            or source.get("repo") != repo
            or source.get("number") != issue_number
            or expected_url is None
            or raw_target.get("url") != expected_url
            or source_identity != expected_url
            or raw_target.get("updated_at") != source_updated
        ):
            errors.append("change_request_review_issue_authority_mismatch")
        target = {
            "kind": kind,
            "repo": repo,
            "issue_number": issue_number,
            "url": raw_target.get("url"),
            "updated_at": raw_target.get("updated_at"),
            "draft_id": None,
            "source_request_sha256": None,
            "caller_locator": None,
            "request_id": None,
            "title_sha256": title_hash,
            "body_sha256": body_hash,
            "side_effect_free": False,
        }
    elif kind == "proposed_draft":
        expected_keys = base_keys | {"draft_id", "source_request_sha256", "side_effect_free"}
        draft_id = raw_target.get("draft_id")
        source_request_sha256 = change_request_review_sha256(raw_target.get("source_request_sha256"))
        authority_projection = change_request_review_request_authority_projection(
            repo,
            source,
            body_hash,
        )
        expected_source_request_sha256 = (
            context_digest(authority_projection)
            if authority_projection is not None
            else None
        )
        if (
            source.get("kind") != "draft"
            or source.get("draft_id") != draft_id
            or not isinstance(draft_id, str)
            or not draft_id.strip()
            or authority_projection is None
            or raw_target.get("side_effect_free") is not True
        ):
            errors.append("change_request_review_draft_authority_mismatch")
        if source_request_sha256 != expected_source_request_sha256:
            errors.append("change_request_review_source_request_mismatch")
        target = {
            "kind": kind,
            "repo": repo,
            "issue_number": None,
            "url": None,
            "updated_at": None,
            "draft_id": draft_id,
            "source_request_sha256": source_request_sha256,
            "caller_locator": None,
            "request_id": None,
            "title_sha256": title_hash,
            "body_sha256": body_hash,
            "side_effect_free": True,
        }
    elif kind == "standalone_request":
        expected_keys = base_keys | {
            "caller_locator", "request_id", "source_request_sha256",
            "side_effect_free",
        }
        caller_locator = raw_target.get("caller_locator")
        request_id = raw_target.get("request_id")
        source_request_sha256 = change_request_review_sha256(raw_target.get("source_request_sha256"))
        authority_projection = change_request_review_request_authority_projection(
            repo,
            source,
            body_hash,
        )
        expected_source_request_sha256 = (
            context_digest(authority_projection)
            if authority_projection is not None
            else None
        )
        if (
            source.get("kind") != "draft"
            or source.get("draft_id") != request_id
            or not isinstance(caller_locator, str)
            or not caller_locator.strip()
            or not isinstance(request_id, str)
            or not request_id.strip()
            or authority_projection is None
            or raw_target.get("side_effect_free") is not True
        ):
            errors.append("change_request_review_standalone_authority_mismatch")
        if source_request_sha256 != expected_source_request_sha256:
            errors.append("change_request_review_source_request_mismatch")
        target = {
            "kind": kind,
            "repo": repo,
            "issue_number": None,
            "url": None,
            "updated_at": None,
            "draft_id": None,
            "source_request_sha256": source_request_sha256,
            "caller_locator": caller_locator,
            "request_id": request_id,
            "title_sha256": title_hash,
            "body_sha256": body_hash,
            "side_effect_free": True,
        }
    else:
        raise WorkflowError(
            "Change request review target kind is invalid.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_target_kind_invalid"]},
        )
    target["identity_sha256"] = context_digest(
        change_request_review_target_identity_projection(target)
    )
    target["content_sha256"] = content_hash
    actual_keys = set(raw_target)
    if actual_keys == expected_keys:
        pass
    elif actual_keys == set(target):
        if raw_target != target:
            errors.append("change_request_review_normalized_target_mismatch")
    else:
        errors.append("change_request_review_target_fields_invalid")
    if raw_target.get("title_sha256") != title_hash or raw_target.get("body_sha256") != body_hash:
        errors.append("change_request_review_target_content_mismatch")
    if "identity_sha256" in raw_target and raw_target.get("identity_sha256") != target["identity_sha256"]:
        errors.append("change_request_review_target_identity_mismatch")
    if "content_sha256" in raw_target and raw_target.get("content_sha256") != target["content_sha256"]:
        errors.append("change_request_review_target_content_digest_mismatch")
    if errors:
        raise WorkflowError(
            "Change request review target validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(errors)},
        )
    return target, scope, contents


def change_request_review_missing_projection(kind: str) -> dict[str, Any]:
    common = {
        "status": "missing",
        "schema_id": None,
        "typed_exit": None,
        "payload_sha256": None,
    }
    if kind == "context":
        return {
            **common,
            "snapshot_sha256": None,
            "base_sync_facts_sha256": None,
            "base_head": None,
            "live_target_sha256": None,
            "query_sha256": None,
            "current_state_sha256": None,
            "history_sha256": None,
            "duplicate_sha256": None,
            "error_codes": ["change_request_review_context_missing"],
        }
    if kind == "clarity":
        return {
            **common,
            "facts_sha256": None,
            "target_sha256": None,
            "content_sha256": None,
            "scope_sha256": None,
            "error_codes": ["change_request_review_clarity_missing"],
        }
    return {
        **common,
        "profile": None,
        "facts_sha256": None,
        "scope_sha256": None,
        "scan_sha256": None,
        "target_content_sha256": None,
        "error_codes": ["change_request_review_wording_missing"],
    }


def change_request_review_context_projection(
    root: Path,
    payload: Any,
) -> dict[str, Any]:
    if payload is None:
        return change_request_review_missing_projection("context")
    if not isinstance(payload, dict):
        result = change_request_review_missing_projection("context")
        result["status"] = "invalid"
        result["error_codes"] = ["change_request_review_context_invalid"]
        return result
    structural = context_structural_errors(root, payload)
    live: list[str] = []
    if not structural:
        live = context_typed_exit_live_errors(
            payload,
            context_live_errors(root, payload, None),
        )
    errors = list(structural) + list(live)
    if payload.get("typed_exit") != "context_ready":
        errors.append("change_request_review_context_exit_not_ready")
    snapshot = payload.get("snapshot_identity") if isinstance(payload.get("snapshot_identity"), dict) else {}
    base = payload.get("base_evidence") if isinstance(payload.get("base_evidence"), dict) else {}
    sync_result = base.get("sync_result") if isinstance(base.get("sync_result"), dict) else {}
    live_change = payload.get("live_change") if isinstance(payload.get("live_change"), dict) else {}
    preview = payload.get("history_preview") if isinstance(payload.get("history_preview"), dict) else {}
    history_projection = {
        "preview_sha256": preview.get("preview_sha256"),
        "history_review": payload.get("history_review"),
        "mem_review": payload.get("mem_review"),
    }
    return {
        "status": "current" if not errors else "invalid",
        "schema_id": "guru-context-discovery-1.0",
        "typed_exit": payload.get("typed_exit") if isinstance(payload.get("typed_exit"), str) else None,
        "payload_sha256": context_digest(payload),
        "snapshot_sha256": change_request_review_sha256(snapshot.get("snapshot_sha256")),
        "base_sync_facts_sha256": change_request_review_sha256(sync_result.get("facts_sha256")),
        "base_head": snapshot.get("base_head") if re.fullmatch(r"[0-9a-f]{40}", str(snapshot.get("base_head") or "")) else None,
        "live_target_sha256": change_request_review_sha256(live_change.get("facts_sha256")),
        "query_sha256": change_request_review_sha256(snapshot.get("query_sha256")),
        "current_state_sha256": context_digest(payload.get("current_state")),
        "history_sha256": context_digest(history_projection),
        "duplicate_sha256": context_digest(payload.get("duplicate_search")),
        "error_codes": context_sort(errors),
    }


def change_request_review_clarity_projection(
    root: Path,
    payload: Any,
) -> dict[str, Any]:
    if payload is None:
        return change_request_review_missing_projection("clarity")
    if not isinstance(payload, dict):
        result = change_request_review_missing_projection("clarity")
        result["status"] = "invalid"
        result["error_codes"] = ["change_request_review_clarity_invalid"]
        return result
    structural = requirements_clarification_structural_errors(root, payload, None)
    live: list[str] = []
    if not structural:
        live = requirements_clarification_typed_exit_live_errors(
            payload,
            requirements_clarification_live_errors(root, payload, None),
        )
    errors = list(structural) + list(live)
    if payload.get("typed_exit") != "clear":
        errors.append("change_request_review_clarity_exit_not_clear")
    identity = payload.get("content_identity") if isinstance(payload.get("content_identity"), dict) else {}
    return {
        "status": "current" if not errors else "invalid",
        "schema_id": "guru-requirements-clarification-1.0",
        "typed_exit": payload.get("typed_exit") if isinstance(payload.get("typed_exit"), str) else None,
        "payload_sha256": context_digest(payload),
        "facts_sha256": change_request_review_sha256(identity.get("result_sha256")),
        "target_sha256": change_request_review_sha256(identity.get("target_sha256")),
        "content_sha256": change_request_review_sha256(identity.get("content_sha256")),
        "scope_sha256": change_request_review_sha256(identity.get("scope_sha256")),
        "error_codes": context_sort(errors),
    }


def change_request_review_wording_projection(
    root: Path,
    payload: Any,
    scope: dict[str, Any],
    contents: dict[str, str],
) -> dict[str, Any]:
    if payload is None:
        return change_request_review_missing_projection("wording")
    if not isinstance(payload, dict):
        result = change_request_review_missing_projection("wording")
        result["status"] = "invalid"
        result["error_codes"] = ["change_request_review_wording_invalid"]
        return result
    scan = scan_contract_wording(scope, contents)
    errors = contract_wording_structural_errors(root, payload, scope, scan)
    if payload.get("profile") != "change_request":
        errors.append("change_request_review_wording_profile_invalid")
    if payload.get("typed_exit") != "pass":
        errors.append("change_request_review_wording_exit_not_pass")
    _, _, target_content_sha256 = change_request_review_scope_hashes(scope)
    scope_value = payload.get("scope") if isinstance(payload.get("scope"), dict) else {}
    scan_value = payload.get("scan") if isinstance(payload.get("scan"), dict) else {}
    return {
        "status": "current" if not errors else "invalid",
        "schema_id": "guru-contract-wording-review-1.0",
        "profile": payload.get("profile") if isinstance(payload.get("profile"), str) else None,
        "typed_exit": payload.get("typed_exit") if isinstance(payload.get("typed_exit"), str) else None,
        "payload_sha256": context_digest(payload),
        "facts_sha256": change_request_review_sha256(payload.get("facts_sha256")),
        "scope_sha256": change_request_review_sha256(scope_value.get("scope_sha256")),
        "scan_sha256": change_request_review_sha256(scan_value.get("scan_sha256")),
        "target_content_sha256": target_content_sha256,
        "error_codes": context_sort(errors),
    }


def change_request_review_prerequisite_target_identity_projection(
    payloads: dict[str, Any],
) -> dict[str, Any] | None:
    context_payload = payloads.get("context")
    clarity_payload = payloads.get("clarity")
    wording_payload = payloads.get("wording")
    if not all(
        isinstance(payload, dict)
        for payload in (context_payload, clarity_payload, wording_payload)
    ):
        return None

    repository = context_payload.get("repository")
    repository = repository if isinstance(repository, dict) else {}
    live_change = context_payload.get("live_change")
    live_change = live_change if isinstance(live_change, dict) else {}
    clarity_target = clarity_payload.get("review_target")
    clarity_target = clarity_target if isinstance(clarity_target, dict) else {}
    invocation = clarity_payload.get("invocation_context")
    invocation = invocation if isinstance(invocation, dict) else {}
    wording_scope = wording_payload.get("scope")
    wording_scope = wording_scope if isinstance(wording_scope, dict) else {}
    title_hash, body_hash, _ = change_request_review_scope_hashes(wording_scope)
    source_identity = str(wording_scope.get("identity") or "").removeprefix(
        "change_request:"
    )

    invocation_kind = invocation.get("kind")
    if (
        live_change.get("kind") == "issue"
        and clarity_target.get("kind") == "issue"
        and invocation_kind == "initial_issue"
    ):
        kind = "existing_issue"
    elif (
        live_change.get("kind") == "draft"
        and clarity_target.get("kind") == "draft"
        and invocation_kind == "proposed_draft"
    ):
        kind = "proposed_draft"
    elif (
        live_change.get("kind") == "draft"
        and clarity_target.get("kind") == "draft"
        and invocation_kind == "standalone_review"
    ):
        kind = "standalone_request"
    else:
        return None

    common = {
        "kind": kind,
        "repo": repository.get("repo"),
        "title_sha256": title_hash,
        "body_sha256": body_hash,
    }
    if kind == "existing_issue":
        return {
            **common,
            "issue_number": clarity_target.get("issue_number"),
            "url": clarity_target.get("url"),
            "updated_at": clarity_target.get("updated_at"),
        }
    request_identity = (
        source_identity.removeprefix("draft:")
        if source_identity.startswith("draft:")
        else None
    )
    if kind == "proposed_draft":
        return {
            **common,
            "draft_id": request_identity,
            "source_request_sha256": clarity_target.get("facts_sha256"),
        }
    return {
        **common,
        "caller_locator": invocation.get("caller"),
        "request_id": request_identity,
        "source_request_sha256": clarity_target.get("facts_sha256"),
    }


def change_request_review_target_linkage_errors(
    target: dict[str, Any],
    payloads: dict[str, Any],
    projections: dict[str, dict[str, Any]],
) -> None:
    context_payload = payloads.get("context")
    if isinstance(context_payload, dict):
        repository = context_payload.get("repository") if isinstance(context_payload.get("repository"), dict) else {}
        live_change = context_payload.get("live_change") if isinstance(context_payload.get("live_change"), dict) else {}
        context_errors: list[str] = []
        if repository.get("repo") != target.get("repo") or live_change.get("body_sha256") != target.get("body_sha256"):
            context_errors.append("change_request_review_context_target_mismatch")
        if target.get("kind") == "existing_issue" and (
            live_change.get("kind") != "issue"
            or live_change.get("identity") != target.get("url")
            or live_change.get("updated_at") != target.get("updated_at")
        ):
            context_errors.append("change_request_review_context_issue_mismatch")
        if target.get("kind") != "existing_issue" and live_change.get("kind") != "draft":
            context_errors.append("change_request_review_context_draft_mismatch")
        if context_errors:
            projections["context"]["status"] = "invalid"
            projections["context"]["error_codes"] = context_sort(
                projections["context"]["error_codes"] + context_errors
            )
    clarity_payload = payloads.get("clarity")
    if isinstance(clarity_payload, dict):
        clarity_target = clarity_payload.get("review_target") if isinstance(clarity_payload.get("review_target"), dict) else {}
        clarity_errors: list[str] = []
        if clarity_target.get("repo") != target.get("repo") or clarity_target.get("body_sha256") != target.get("body_sha256"):
            clarity_errors.append("change_request_review_clarity_target_mismatch")
        if target.get("kind") == "existing_issue" and (
            clarity_target.get("kind") != "issue"
            or clarity_target.get("issue_number") != target.get("issue_number")
            or clarity_target.get("url") != target.get("url")
            or clarity_target.get("updated_at") != target.get("updated_at")
        ):
            clarity_errors.append("change_request_review_clarity_issue_mismatch")
        if target.get("kind") != "existing_issue" and clarity_target.get("kind") != "draft":
            clarity_errors.append("change_request_review_clarity_draft_mismatch")
        if clarity_errors:
            projections["clarity"]["status"] = "invalid"
            projections["clarity"]["error_codes"] = context_sort(
                projections["clarity"]["error_codes"] + clarity_errors
            )
    wording = projections["wording"]
    if (
        wording.get("target_content_sha256") is not None
        and wording.get("target_content_sha256") != target.get("content_sha256")
    ):
        wording["status"] = "invalid"
        wording["error_codes"] = context_sort(
            wording["error_codes"] + ["change_request_review_wording_target_mismatch"]
        )
    prerequisite_identity = change_request_review_prerequisite_target_identity_projection(
        payloads
    )
    complete_prerequisite_payloads = all(
        isinstance(payloads.get(kind), dict)
        for kind in ("context", "clarity", "wording")
    )
    if (
        complete_prerequisite_payloads
        and (
            prerequisite_identity is None
            or context_digest(prerequisite_identity) != target.get("identity_sha256")
        )
    ):
        identity_error = "change_request_review_target_identity_linkage_mismatch"
        for projection in projections.values():
            projection["status"] = "invalid"
            projection["error_codes"] = context_sort(
                projection["error_codes"] + [identity_error]
            )


def change_request_review_prerequisite_projections(
    root: Path,
    payloads: Any,
    target: dict[str, Any],
    scope: dict[str, Any],
    contents: dict[str, str],
) -> dict[str, dict[str, Any]]:
    if not isinstance(payloads, dict) or set(payloads) != {"context", "clarity", "wording"}:
        raise WorkflowError(
            "Change request review prerequisite payloads must contain context, clarity, and wording.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_prerequisites_invalid"]},
        )
    projections = {
        "context": change_request_review_context_projection(root, payloads.get("context")),
        "clarity": change_request_review_clarity_projection(root, payloads.get("clarity")),
        "wording": change_request_review_wording_projection(
            root,
            payloads.get("wording"),
            scope,
            contents,
        ),
    }
    change_request_review_target_linkage_errors(target, payloads, projections)
    return projections


def change_request_review_linkage(
    target: dict[str, Any],
    prerequisites: dict[str, dict[str, Any]],
) -> dict[str, Any]:
    context_projection = prerequisites["context"]
    clarity_projection = prerequisites["clarity"]
    wording_projection = prerequisites["wording"]
    linkage = {
        "target_identity_sha256": target["identity_sha256"],
        "target_content_sha256": target["content_sha256"],
        "base_head": context_projection["base_head"],
        "current_state_sha256": context_projection["current_state_sha256"],
        "history_sha256": context_projection["history_sha256"],
        "duplicate_sha256": context_projection["duplicate_sha256"],
        "clarity_facts_sha256": clarity_projection["facts_sha256"],
        "wording_facts_sha256": wording_projection["facts_sha256"],
    }
    linkage["linkage_sha256"] = context_digest(linkage)
    return linkage


def change_request_review_derive_result(
    target: dict[str, Any],
    prerequisites: dict[str, dict[str, Any]],
    linkage: dict[str, Any],
    authored: dict[str, Any],
) -> dict[str, Any]:
    expected = {
        "generated_at", "mode", "target", "prerequisite_payloads",
        "semantic_review", "human_confirmation", "typed_exit", "reason",
        "affected_evidence", "consumer",
    }
    if set(authored) != expected:
        raise WorkflowError(
            "Change request review recorder input has undeclared or missing fields.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_input_fields_invalid"]},
        )
    result = {
        "schema_version": CHANGE_REQUEST_REVIEW_SCHEMA_VERSION,
        "skill_id": CHANGE_REQUEST_REVIEW_SKILL_ID,
        "generated_at": authored.get("generated_at"),
        "mode": authored.get("mode"),
        "target": copy.deepcopy(target),
        "prerequisites": copy.deepcopy(prerequisites),
        "evidence_linkage": copy.deepcopy(linkage),
        "semantic_review": copy.deepcopy(authored.get("semantic_review")),
        "human_confirmation": copy.deepcopy(authored.get("human_confirmation")),
        "typed_exit": authored.get("typed_exit"),
        "reason": authored.get("reason"),
        "affected_evidence": copy.deepcopy(authored.get("affected_evidence")),
        "consumer": copy.deepcopy(authored.get("consumer")),
    }
    result["facts_sha256"] = context_digest(result)
    return result


def change_request_review_structural_errors(
    root: Path,
    payload: dict[str, Any],
    expected_target: dict[str, Any],
    expected_prerequisites: dict[str, dict[str, Any]],
    expected_linkage: dict[str, Any],
) -> list[str]:
    errors: list[str] = []
    if skill_json_schema_validation_errors(
        payload,
        change_request_review_schema(root),
        "change request review result",
    ):
        errors.append("change_request_review_schema_validation_failed")
    expected_top = {
        "schema_version", "skill_id", "generated_at", "mode", "target",
        "prerequisites", "evidence_linkage", "semantic_review",
        "human_confirmation", "typed_exit", "reason", "affected_evidence",
        "consumer", "facts_sha256",
    }
    if set(payload) != expected_top:
        errors.append("change_request_review_top_level_fields_invalid")
    if (
        payload.get("schema_version") != CHANGE_REQUEST_REVIEW_SCHEMA_VERSION
        or payload.get("skill_id") != CHANGE_REQUEST_REVIEW_SKILL_ID
    ):
        errors.append("change_request_review_schema_identity_invalid")
    if payload.get("target") != expected_target:
        errors.append("change_request_review_target_stale")
    if payload.get("prerequisites") != expected_prerequisites:
        errors.append("change_request_review_prerequisites_stale")
    if payload.get("evidence_linkage") != expected_linkage:
        errors.append("change_request_review_linkage_stale")
    identity_error = "change_request_review_target_identity_linkage_mismatch"
    if any(
        identity_error in projection.get("error_codes", [])
        for projection in expected_prerequisites.values()
    ):
        errors.append(identity_error)
    unsigned = copy.deepcopy(payload)
    actual_facts = unsigned.pop("facts_sha256", None)
    if actual_facts != context_digest(unsigned):
        errors.append("change_request_review_facts_digest_mismatch")
    typed_exit = payload.get("typed_exit")
    if typed_exit not in CHANGE_REQUEST_REVIEW_CONSUMERS:
        errors.append("change_request_review_exit_invalid")
    elif payload.get("consumer") != CHANGE_REQUEST_REVIEW_CONSUMERS[typed_exit]:
        errors.append("change_request_review_consumer_mismatch")
    semantic = payload.get("semantic_review")
    semantic = semantic if isinstance(semantic, dict) else {}
    dimensions = semantic.get("dimensions")
    dimensions = dimensions if isinstance(dimensions, list) else []
    dimension_ids = [
        row.get("id") for row in dimensions if isinstance(row, dict)
    ]
    if dimension_ids != CHANGE_REQUEST_REVIEW_DIMENSIONS:
        errors.append("change_request_review_dimensions_invalid")
    findings = semantic.get("findings")
    findings = findings if isinstance(findings, list) else []
    finding_ids = [
        row.get("finding_id") for row in findings if isinstance(row, dict)
    ]
    if len(finding_ids) != len(findings) or len(finding_ids) != len(set(finding_ids)):
        errors.append("change_request_review_findings_invalid")
    for finding in findings:
        if not isinstance(finding, dict):
            continue
        if finding.get("category") not in CHANGE_REQUEST_REVIEW_FINDING_CATEGORIES:
            errors.append("change_request_review_finding_category_invalid")
    referenced_findings: set[Any] = set()
    for dimension in dimensions:
        if not isinstance(dimension, dict):
            continue
        ids = dimension.get("finding_ids")
        if not isinstance(ids, list) or any(value not in finding_ids for value in ids):
            errors.append("change_request_review_finding_reference_invalid")
        else:
            referenced_findings.update(ids)
    if set(finding_ids) != referenced_findings:
        errors.append("change_request_review_finding_reference_incomplete")
    affected = payload.get("affected_evidence")
    affected = affected if isinstance(affected, list) else []
    evidence_refs = [
        row.get("ref") for row in affected if isinstance(row, dict)
    ]
    if len(evidence_refs) != len(affected) or len(evidence_refs) != len(set(evidence_refs)):
        errors.append("change_request_review_affected_evidence_invalid")
    affected_hashes = {
        row.get("sha256")
        for row in affected
        if isinstance(row, dict) and change_request_review_sha256(row.get("sha256")) is not None
    }
    prerequisite_hashes = {
        value
        for projection in expected_prerequisites.values()
        for value in projection.values()
        if change_request_review_sha256(value) is not None
    }
    allowed_hashes = affected_hashes | prerequisite_hashes | {
        expected_target.get("identity_sha256"),
        expected_target.get("content_sha256"),
        expected_linkage.get("linkage_sha256"),
    }
    allowed_refs = set(evidence_refs) | {
        "target", "prerequisites.context", "prerequisites.clarity",
        "prerequisites.wording", "evidence_linkage",
    }
    for row in [*dimensions, *findings]:
        if not isinstance(row, dict):
            continue
        refs = row.get("evidence_refs")
        if not isinstance(refs, list) or any(ref not in allowed_refs for ref in refs):
            errors.append("change_request_review_evidence_reference_invalid")
        hashes = row.get("affected_hashes")
        if not isinstance(hashes, list) or any(value not in allowed_hashes for value in hashes):
            errors.append("change_request_review_affected_hash_invalid")
    scope_conclusion = semantic.get("scope_conclusion")
    scope_conclusion = scope_conclusion if isinstance(scope_conclusion, dict) else {}
    gate = semantic.get("ai_review_gate")
    gate = gate if isinstance(gate, dict) else {}
    if gate.get("reviewed_linkage_sha256") != expected_linkage.get("linkage_sha256"):
        errors.append("change_request_review_gate_linkage_mismatch")
    if gate.get("findings_count") != len(findings):
        errors.append("change_request_review_gate_findings_mismatch")
    if gate.get("scope_conclusion_sha256") != context_digest(scope_conclusion):
        errors.append("change_request_review_gate_scope_mismatch")
    expected_gate = CHANGE_REQUEST_REVIEW_GATE_BY_EXIT.get(typed_exit)
    if gate.get("status") != expected_gate:
        errors.append("change_request_review_gate_exit_mismatch")
    confirmation = payload.get("human_confirmation")
    confirmation = confirmation if isinstance(confirmation, dict) else {}
    if confirmation.get("status") == "not_required" and confirmation.get("proposal_sha256") is not None:
        errors.append("change_request_review_confirmation_shape_invalid")
    if confirmation.get("status") == "required" and (
        typed_exit != "clarify_requirements"
        or change_request_review_sha256(confirmation.get("proposal_sha256")) is None
    ):
        errors.append("change_request_review_confirmation_route_invalid")
    if typed_exit in CHANGE_REQUEST_REVIEW_CONSUMERS and typed_exit != "ready":
        if not findings:
            errors.append("change_request_review_non_ready_requires_finding")
        if not any(
            isinstance(dimension, dict) and dimension.get("status") == "failed"
            for dimension in dimensions
        ):
            errors.append("change_request_review_non_ready_requires_failed_dimension")
        if not any(
            isinstance(finding, dict) and finding.get("blocking") is True
            for finding in findings
        ):
            errors.append("change_request_review_non_ready_requires_blocking_finding")
        if not affected:
            errors.append("change_request_review_non_ready_requires_affected_evidence")
    if typed_exit == "ready":
        if any(
            projection.get("status") != "current" or projection.get("error_codes")
            for projection in expected_prerequisites.values()
        ):
            errors.append("change_request_review_ready_requires_current_prerequisites")
        if any(
            not isinstance(dimension, dict) or dimension.get("status") != "passed"
            for dimension in dimensions
        ):
            errors.append("change_request_review_ready_requires_passed_dimensions")
        if any(
            isinstance(finding, dict) and finding.get("blocking") is True
            for finding in findings
        ):
            errors.append("change_request_review_ready_has_blocking_finding")
        if confirmation.get("status") != "not_required":
            errors.append("change_request_review_ready_confirmation_invalid")
        if any(
            expected_linkage.get(field) is None
            for field in (
                "base_head", "current_state_sha256", "history_sha256",
                "duplicate_sha256", "clarity_facts_sha256",
                "wording_facts_sha256",
            )
        ):
            errors.append("change_request_review_ready_linkage_incomplete")
    return context_sort(errors)


def cmd_record_change_request_review(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    authored = change_request_review_read_input(root, args.input, "change request review recorder")
    if authored.get("mode") != args.mode:
        raise WorkflowError(
            "Change request review mode does not match recorder mode.",
            exit_code=2,
            payload={"error_codes": ["change_request_review_mode_mismatch"]},
        )
    target, scope, contents = change_request_review_normalize_target(
        root,
        authored.get("target"),
        args.change_request_input,
        args.mode,
    )
    prerequisites = change_request_review_prerequisite_projections(
        root,
        authored.get("prerequisite_payloads"),
        target,
        scope,
        contents,
    )
    linkage = change_request_review_linkage(target, prerequisites)
    result = change_request_review_derive_result(target, prerequisites, linkage, authored)
    errors = change_request_review_structural_errors(
        root,
        result,
        target,
        prerequisites,
        linkage,
    )
    if errors:
        raise WorkflowError(
            "Change request review result validation failed.",
            exit_code=2,
            payload={"error_codes": errors},
        )
    return result


def cmd_check_change_request_review(args: argparse.Namespace) -> dict[str, Any]:
    root = repo_root(Path(args.root or os.getcwd()))
    payload = change_request_review_read_input(root, args.input, "change request review checker")
    prerequisite_payloads = change_request_review_read_input(
        root,
        args.prerequisites_input,
        "change request review current prerequisites",
    )
    mode = str(payload.get("mode") or "")
    target, scope, contents = change_request_review_normalize_target(
        root,
        payload.get("target"),
        args.change_request_input,
        mode,
    )
    prerequisites = change_request_review_prerequisite_projections(
        root,
        prerequisite_payloads,
        target,
        scope,
        contents,
    )
    linkage = change_request_review_linkage(target, prerequisites)
    errors = change_request_review_structural_errors(
        root,
        payload,
        target,
        prerequisites,
        linkage,
    )
    if args.expected_facts_sha256 and args.expected_facts_sha256 != payload.get("facts_sha256"):
        errors.append("expected_change_request_review_facts_mismatch")
    if errors:
        raise WorkflowError(
            "Change request review freshness validation failed.",
            exit_code=2,
            payload={"error_codes": context_sort(errors)},
        )
    return {
        "status": "passed",
        "skill_id": CHANGE_REQUEST_REVIEW_SKILL_ID,
        "typed_exit": payload["typed_exit"],
        "target_identity_sha256": target["identity_sha256"],
        "target_content_sha256": target["content_sha256"],
        "linkage_sha256": linkage["linkage_sha256"],
        "facts_sha256": payload["facts_sha256"],
    }


